insert into public.content_disciplines (slug, sort_order, color, icon, min_plan) values ('running-cardio', 0, 'orange', 'running', 'pro') on conflict (slug) do update set sort_order=excluded.sort_order, color=excluded.color, icon=excluded.icon, min_plan=excluded.min_plan, updated_at=now();
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('running-cardio', 'fr', '{"title":"Running & Cardio","tag":"Cardio","description":"Programmes de course adaptés à tous les niveaux — du 5K au marathon. Plans personnalisés avec coaching GPS et suivi de fréquence cardiaque.","stats":["+4 200 coureurs","120+ plans","12 semaines moy."],"levels":["Débutant","Intermédiaire","Avancé","Élite"]}'::jsonb, '{"tagline":"Cours plus vite, plus longtemps, sans te blesser.","heroStat":"4 200+ coureurs actifs","guide":{"technique":{"emoji":"👟","title":"Technique de course","items":["Attaque médio-pied plutôt que talon — réduit le risque de blessure de 30 %","Cadence cible : 170–180 pas/min pour maximiser l''efficacité","Bras à 90° et mains détendues — économise de l''énergie sur longue distance","Regard fixé à 10–15 m devant soi pour maintenir une posture droite","Respiration en rythme 3:2 (3 pas inspiration / 2 pas expiration) aux allures lentes"]},"equipment":{"emoji":"🛒","title":"Équipement recommandé","items":["Chaussures de running adaptées à ta foulée (test foulée en boutique spécialisée)","Montre GPS pour suivre allure, distance et fréquence cardiaque","Vêtements techniques respirants (éviter le coton)","Ceinture cardiaque pour zones d''entraînement précises","Application de suivi : Xenotif® + intégration Garmin / Apple Watch"]},"nutrition":{"emoji":"🥑","title":"Nutrition & Hydratation","items":["Repas riche en glucides complexes 3h avant la sortie longue (riz, pâtes, quinoa)","Gel énergétique ou banane toutes les 40–45 min au-delà de 1h30 de course","Hydratation : 500 ml d''eau 2h avant, puis 150–200 ml toutes les 20 min","Récupération : 20–30 g de protéines dans les 30 min post-effort","Caféine (3–5 mg/kg) 60 min avant une compétition pour la performance"]},"recovery":{"emoji":"💆","title":"Récupération optimale","items":["Stretching statique 10–15 min post-sortie (ischio-jambiers, mollets, quadriceps)","Rouleau de massage (foam roller) sur les chaînes musculaires 3× /semaine","Bain froid (12–15 °C, 10 min) après les séances intenses pour réduire l''inflammation","Minimum 8h de sommeil — la reconstruction musculaire se fait la nuit","1 jour de repos complet par semaine obligatoire pour prévenir le surentraînement"]}},"tips":[{"icon":"⚡","title":"Règle des 10 %","body":"N''augmente jamais ton volume hebdomadaire de plus de 10 % — la règle d''or pour éviter les blessures de surmenage."},{"icon":"🎯","title":"Entraîne-toi en zones","body":"80 % de ton volume à basse intensité (Zone 2), 20 % en haute intensité — c''est la formule des champions d''endurance."},{"icon":"🧠","title":"Visualisation pré-course","body":"5 min de visualisation mentale avant chaque sortie difficile améliore la performance de 15 % selon les études sportives."},{"icon":"🌡️","title":"Bilan FTP mensuel","body":"Teste ta vitesse au seuil lactique chaque mois (test Cooper 12 min) pour ajuster tes zones d''entraînement précisément."}],"exercises":[{"name":"Fentes marchées","muscles":"Quadriceps, fessiers, ischio-jambiers","sets":"3×12/jambe","difficulty":"Débutant","description":"Fais un grand pas en avant, descends le genou arrière près du sol, puis pousse sur le pied avant pour ramener l''autre jambe. Maintiens le dos droit."},{"name":"Squat sauté","muscles":"Quadriceps, fessiers, cardio","sets":"3×15","difficulty":"Intermédiaire","description":"Descends en squat parallèle puis explose vers le haut. Atterris doucement en fléchissant les genoux pour amortir. Renforce la puissance propulsive."},{"name":"Step-up sur caisse","muscles":"Quadriceps, fessiers, stabilisateurs","sets":"3×10/jambe","difficulty":"Débutant","description":"Pose un pied sur une caisse ou step, pousse pour monter, redescends lentement. Simule la montée de côtes en course."},{"name":"Jumping lunges","muscles":"Quadriceps, fessiers, explosivité","sets":"3×10/jambe","difficulty":"Intermédiaire","description":"Depuis la position de fente, saute et échange les jambes en l''air. Excellent pour développer la puissance et l''endurance des membres inférieurs."},{"name":"Single-leg deadlift","muscles":"Ischio-jambiers, fessiers, équilibre","sets":"3×8/jambe","difficulty":"Avancé","description":"Penche-toi en avant sur une jambe en gardant le dos plat, l''autre jambe s''étend derrière. Reviens à la verticale sans poser le pied. Renforce proprioception."},{"name":"Box jumps","muscles":"Quadriceps, mollets, explosivité","sets":"4×8","difficulty":"Avancé","description":"Saute sur une boîte en deux pieds, absorbe l''atterrissage en demi-squat. Descends par l''extérieur. Améliore la puissance explosive des membres inférieurs."},{"name":"Running A-drills","muscles":"Fléchisseurs de hanche, cadence","sets":"3×20 m","difficulty":"Débutant","description":"Marche en montant les genoux haut à chaque pas, bras en rythme. Améliore la mécanique de course et la cadence en travaillant l''activation des hanches."},{"name":"Planche latérale","muscles":"Obliques, stabilité latérale","sets":"3×30 s/côté","difficulty":"Débutant","description":"Appui sur le coude et le côté du pied, corps en ligne droite. Renforce les muscles latéraux du tronc indispensables au maintien de la posture en course."}],"program":[{"week":"Semaine 1–2","theme":"Fondation aérobie","sessions":[{"name":"Footing Z2 30 min","detail":"Allure conversationnelle (fréquence cardiaque 65–75 % FCmax)"},{"name":"Côtes 8× 30 s","detail":"Sprint en montée, récup descente — améliore la puissance et la foulée"},{"name":"Longue sortie 50 min","detail":"Rythme très lent, objectif durée et endurance de base"}]},{"week":"Semaine 3–4","theme":"Développement seuil","sessions":[{"name":"Intervalles 5×5 min","detail":"Allure 10K, récup 90 s entre chaque — travail au seuil lactique"},{"name":"Fartlek 35 min","detail":"Alternance accélérations libres / footing lent selon ressenti"},{"name":"Sortie longue 65 min","detail":"Avec 15 min en allure marathon sur la 2ème partie"}]},{"week":"Semaine 5–6","theme":"Vitesse & spécifique","sessions":[{"name":"Tempo run 45 min","detail":"Allure semi-marathon maintenue en continu — effort contrôlé"},{"name":"Séance piste 12×400 m","detail":"Allure objectif 5K, récup 200 m jogging entre chaque rep"},{"name":"Test Cooper 12 min","detail":"Course max sur 12 min pour évaluer la progression VO2max"}]},{"week":"Semaine 7–8","theme":"Affinage & compétition","sessions":[{"name":"Réduction volume −30 %","detail":"Diminue le kilométrage mais maintiens les allures — récupération active"},{"name":"Strides 8×100 m","detail":"Accélérations progressives pour garder la vivacité avant course"},{"name":"Race day simulation","detail":"Échauffement + 20 min à allure objectif + retour au calme"}]}],"faq":[{"q":"À quelle fréquence dois-je courir par semaine ?","a":"Débutant : 3 séances. Intermédiaire : 4–5 séances. Avancé : 5–6 séances avec un jour de repos absolu. La qualité prime sur la quantité."},{"q":"Comment éviter les douleurs au genou ?","a":"Renforce tes fessiers et tes ischio-jambiers (squats, fentes), travaille ta cadence (vise 175 pas/min) et privilégie des surfaces souples au début."},{"q":"Faut-il courir à jeun pour brûler plus de graisses ?","a":"La course à jeun améliore l''utilisation des lipides mais réduit la performance. Conseillé uniquement pour les footings légers (< 45 min) en Zone 2."},{"q":"En combien de temps puis-je courir mon premier 5K ?","a":"Avec notre programme débutant, 8 semaines suffisent pour enchaîner 5K sans s''arrêter, quelle que soit ta condition de départ."},{"q":"Quelle chaussure choisir pour commencer ?","a":"Va dans un magasin spécialisé pour une analyse de ta foulée gratuite. Privilégie une chaussure avec bon amorti si tu cours sur bitume — budget 100–150 € minimum."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('running-cardio', 'en', '{"title":"Running & Cardio","tag":"Cardio","description":"Running programs for every level — from 5K to marathon. Personalized plans with GPS coaching and heart-rate tracking.","stats":["+4,200 runners","120+ plans","12 weeks avg."],"levels":["Beginner","Intermediate","Advanced","Elite"]}'::jsonb, '{"tagline":"Run faster, run longer, without getting injured.","heroStat":"4,200+ active runners","guide":{"technique":{"emoji":"👟","title":"Running technique","items":["Land midfoot rather than heel-first — cuts injury risk by 30%","Target cadence: 170–180 steps/min to maximize efficiency","Arms at 90° with relaxed hands — saves energy over long distances","Gaze fixed 10–15 m ahead to keep an upright posture","Breathe on a 3:2 rhythm (3 steps inhale / 2 steps exhale) at easy paces"]},"equipment":{"emoji":"🛒","title":"Recommended gear","items":["Running shoes matched to your gait (get a gait analysis at a specialty store)","GPS watch to track pace, distance and heart rate","Breathable technical clothing (avoid cotton)","Heart-rate chest strap for precise training zones","Tracking app: Xenotif® + Garmin / Apple Watch integration"]},"nutrition":{"emoji":"🥑","title":"Nutrition & Hydration","items":["Meal rich in complex carbs 3h before a long run (rice, pasta, quinoa)","Energy gel or banana every 40–45 min beyond 1h30 of running","Hydration: 500 ml of water 2h before, then 150–200 ml every 20 min","Recovery: 20–30 g of protein within 30 min after the effort","Caffeine (3–5 mg/kg) 60 min before a race for performance"]},"recovery":{"emoji":"💆","title":"Optimal recovery","items":["Static stretching 10–15 min post-run (hamstrings, calves, quads)","Foam roller on the muscle chains 3× /week","Cold bath (12–15 °C, 10 min) after intense sessions to reduce inflammation","At least 8h of sleep — muscle rebuilding happens at night","One full rest day per week is mandatory to prevent overtraining"]}},"tips":[{"icon":"⚡","title":"The 10% rule","body":"Never increase your weekly volume by more than 10% — the golden rule for avoiding overuse injuries."},{"icon":"🎯","title":"Train by zones","body":"80% of your volume at low intensity (Zone 2), 20% at high intensity — that''s the formula of endurance champions."},{"icon":"🧠","title":"Pre-run visualization","body":"5 min of mental visualization before each hard run improves performance by 15% according to sports studies."},{"icon":"🌡️","title":"Monthly FTP check","body":"Test your speed at lactate threshold every month (12-min Cooper test) to fine-tune your training zones."}],"exercises":[{"name":"Walking lunges","muscles":"Quads, glutes, hamstrings","sets":"3×12/leg","difficulty":"Beginner","description":"Take a big step forward, lower your back knee close to the floor, then push off the front foot to bring the other leg through. Keep your back straight."},{"name":"Jump squat","muscles":"Quads, glutes, cardio","sets":"3×15","difficulty":"Intermediate","description":"Lower into a parallel squat then explode upward. Land softly by bending the knees to absorb. Builds propulsive power."},{"name":"Box step-up","muscles":"Quads, glutes, stabilizers","sets":"3×10/leg","difficulty":"Beginner","description":"Place one foot on a box or step, push up, then lower slowly. Mimics running uphill."},{"name":"Jumping lunges","muscles":"Quads, glutes, explosiveness","sets":"3×10/leg","difficulty":"Intermediate","description":"From the lunge position, jump and swap legs in the air. Excellent for developing lower-body power and endurance."},{"name":"Single-leg deadlift","muscles":"Hamstrings, glutes, balance","sets":"3×8/leg","difficulty":"Advanced","description":"Hinge forward on one leg keeping a flat back, the other leg extending behind. Return to standing without putting the foot down. Builds proprioception."},{"name":"Box jumps","muscles":"Quads, calves, explosiveness","sets":"4×8","difficulty":"Advanced","description":"Jump onto a box with both feet, absorb the landing in a half-squat. Step down on the outside. Improves explosive lower-body power."},{"name":"Running A-drills","muscles":"Hip flexors, cadence","sets":"3×20 m","difficulty":"Beginner","description":"Walk while driving the knees high each step, arms in rhythm. Improves running mechanics and cadence by training hip activation."},{"name":"Side plank","muscles":"Obliques, lateral stability","sets":"3×30 s/side","difficulty":"Beginner","description":"Support on the elbow and the side of the foot, body in a straight line. Strengthens the lateral trunk muscles essential for posture while running."}],"program":[{"week":"Week 1–2","theme":"Aerobic foundation","sessions":[{"name":"Z2 easy run 30 min","detail":"Conversational pace (heart rate 65–75% HRmax)"},{"name":"Hills 8× 30 s","detail":"Uphill sprint, recover on the way down — improves power and stride"},{"name":"Long run 50 min","detail":"Very slow pace, goal is duration and base endurance"}]},{"week":"Week 3–4","theme":"Threshold development","sessions":[{"name":"Intervals 5×5 min","detail":"10K pace, 90 s recovery between each — work at lactate threshold"},{"name":"Fartlek 35 min","detail":"Alternate free accelerations / easy jog based on feel"},{"name":"Long run 65 min","detail":"With 15 min at marathon pace in the second half"}]},{"week":"Week 5–6","theme":"Speed & specific","sessions":[{"name":"Tempo run 45 min","detail":"Half-marathon pace held continuously — controlled effort"},{"name":"Track session 12×400 m","detail":"5K target pace, 200 m jog recovery between each rep"},{"name":"12-min Cooper test","detail":"Max run over 12 min to assess VO2max progress"}]},{"week":"Week 7–8","theme":"Sharpening & racing","sessions":[{"name":"Volume reduction −30%","detail":"Lower the mileage but keep the paces — active recovery"},{"name":"Strides 8×100 m","detail":"Progressive accelerations to stay sharp before the race"},{"name":"Race day simulation","detail":"Warm-up + 20 min at target pace + cool-down"}]}],"faq":[{"q":"How often should I run per week?","a":"Beginner: 3 sessions. Intermediate: 4–5 sessions. Advanced: 5–6 sessions with one full rest day. Quality beats quantity."},{"q":"How do I avoid knee pain?","a":"Strengthen your glutes and hamstrings (squats, lunges), work on your cadence (aim for 175 steps/min) and favor soft surfaces at first."},{"q":"Should I run fasted to burn more fat?","a":"Fasted running improves fat usage but reduces performance. Recommended only for easy runs (< 45 min) in Zone 2."},{"q":"How long until I can run my first 5K?","a":"With our beginner program, 8 weeks are enough to run 5K without stopping, whatever your starting fitness."},{"q":"Which shoe should I choose to start?","a":"Go to a specialty store for a free gait analysis. Favor a well-cushioned shoe if you run on pavement — budget €100–150 minimum."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('running-cardio', 'de', '{"title":"Running & Cardio","tag":"Cardio","description":"Laufprogramme für alle Niveaus — vom 5-km-Lauf bis zum Marathon. Personalisierte Pläne mit GPS-Coaching und Herzfrequenz-Tracking.","stats":["+4.200 Läufer","120+ Pläne","Ø 12 Wochen"],"levels":["Anfänger","Fortgeschritten","Erfahren","Elite"]}'::jsonb, '{"tagline":"Lauf schneller, lauf länger, ohne dich zu verletzen.","heroStat":"4.200+ aktive Läufer","guide":{"technique":{"emoji":"👟","title":"Lauftechnik","items":["Setze auf dem Mittelfuß statt auf der Ferse auf — senkt das Verletzungsrisiko um 30%","Zielkadenz: 170–180 Schritte/Min für maximale Effizienz","Arme im 90°-Winkel mit lockeren Händen — spart Energie über lange Distanzen","Blick 10–15 m nach vorn gerichtet, um eine aufrechte Haltung zu bewahren","Atme im 3:2-Rhythmus (3 Schritte ein / 2 Schritte aus) bei lockerem Tempo"]},"equipment":{"emoji":"🛒","title":"Empfohlene Ausrüstung","items":["Laufschuhe passend zu deinem Laufstil (lass eine Laufanalyse im Fachgeschäft machen)","GPS-Uhr, um Tempo, Distanz und Herzfrequenz zu verfolgen","Atmungsaktive Funktionskleidung (vermeide Baumwolle)","Herzfrequenz-Brustgurt für präzise Trainingszonen","Tracking-App: Xenotif® + Garmin- / Apple-Watch-Integration"]},"nutrition":{"emoji":"🥑","title":"Ernährung & Hydration","items":["Mahlzeit reich an komplexen Kohlenhydraten 3 h vor einem langen Lauf (Reis, Pasta, Quinoa)","Energiegel oder Banane alle 40–45 Min ab 1 Std 30 Lauf","Hydration: 500 ml Wasser 2 h vorher, dann 150–200 ml alle 20 Min","Erholung: 20–30 g Protein innerhalb von 30 Min nach der Anstrengung","Koffein (3–5 mg/kg) 60 Min vor einem Wettkampf für die Leistung"]},"recovery":{"emoji":"💆","title":"Optimale Erholung","items":["Statisches Dehnen 10–15 Min nach dem Lauf (Beinbeuger, Waden, Quadrizeps)","Faszienrolle auf den Muskelketten 3× /Woche","Kaltes Bad (12–15 °C, 10 Min) nach intensiven Einheiten, um Entzündungen zu reduzieren","Mindestens 8 h Schlaf — der Muskelaufbau passiert nachts","Ein kompletter Ruhetag pro Woche ist Pflicht, um Übertraining vorzubeugen"]}},"tips":[{"icon":"⚡","title":"Die 10%-Regel","body":"Erhöhe dein Wochenvolumen nie um mehr als 10% — die goldene Regel, um Überlastungsverletzungen zu vermeiden."},{"icon":"🎯","title":"Trainiere in Zonen","body":"80% deines Volumens bei niedriger Intensität (Zone 2), 20% bei hoher Intensität — das ist die Formel der Ausdauer-Champions."},{"icon":"🧠","title":"Visualisierung vor dem Lauf","body":"5 Min mentale Visualisierung vor jedem harten Lauf verbessern laut Sportstudien die Leistung um 15%."},{"icon":"🌡️","title":"Monatlicher FTP-Check","body":"Teste deine Geschwindigkeit an der Laktatschwelle jeden Monat (12-Min-Cooper-Test), um deine Trainingszonen feinzujustieren."}],"exercises":[{"name":"Ausfallschritte im Gehen","muscles":"Quadrizeps, Gesäß, Beinbeuger","sets":"3×12/Bein","difficulty":"Anfänger","description":"Mach einen großen Schritt nach vorn, senke das hintere Knie nahe an den Boden, drücke dann über den vorderen Fuß ab, um das andere Bein nachzuführen. Halte den Rücken gerade."},{"name":"Jump Squat","muscles":"Quadrizeps, Gesäß, Cardio","sets":"3×15","difficulty":"Fortgeschritten","description":"Geh in eine parallele Kniebeuge, dann explodiere nach oben. Lande weich durch Beugen der Knie zum Abfedern. Baut Antriebskraft auf."},{"name":"Box Step-up","muscles":"Quadrizeps, Gesäß, Stabilisatoren","sets":"3×10/Bein","difficulty":"Anfänger","description":"Setze einen Fuß auf eine Box oder Stufe, drücke dich hoch, senke dann langsam ab. Simuliert bergauf laufen."},{"name":"Sprungausfallschritte","muscles":"Quadrizeps, Gesäß, Explosivität","sets":"3×10/Bein","difficulty":"Fortgeschritten","description":"Aus der Ausfallschrittposition springen und die Beine in der Luft wechseln. Exzellent für die Entwicklung von Beinkraft und Ausdauer."},{"name":"Einbeiniges Kreuzheben","muscles":"Beinbeuger, Gesäß, Gleichgewicht","sets":"3×8/Bein","difficulty":"Erfahren","description":"Beuge dich auf einem Bein nach vorn mit flachem Rücken, das andere Bein streckt sich nach hinten. Kehre zum Stand zurück, ohne den Fuß abzusetzen. Baut Propriozeption auf."},{"name":"Box Jumps","muscles":"Quadrizeps, Waden, Explosivität","sets":"4×8","difficulty":"Erfahren","description":"Springe mit beiden Füßen auf eine Box, fange die Landung in einer halben Kniebeuge ab. Steig außen herunter. Verbessert die explosive Beinkraft."},{"name":"Running A-Drills","muscles":"Hüftbeuger, Kadenz","sets":"3×20 m","difficulty":"Anfänger","description":"Gehe und treibe bei jedem Schritt die Knie hoch, Arme im Rhythmus. Verbessert die Laufmechanik und Kadenz durch Training der Hüftaktivierung."},{"name":"Seitlicher Unterarmstütz","muscles":"Schräge Bauchmuskeln, laterale Stabilität","sets":"3×30 s/Seite","difficulty":"Anfänger","description":"Stütze auf dem Ellbogen und der Fußaußenkante, Körper in einer geraden Linie. Stärkt die seitlichen Rumpfmuskeln, die für die Laufhaltung entscheidend sind."}],"program":[{"week":"Woche 1–2","theme":"Aerobe Grundlage","sessions":[{"name":"Z2 lockerer Lauf 30 Min","detail":"Gesprächstempo (Herzfrequenz 65–75% HFmax)"},{"name":"Hügel 8× 30 s","detail":"Bergauf-Sprint, beim Herunterlaufen erholen — verbessert Kraft und Laufschritt"},{"name":"Langer Lauf 50 Min","detail":"Sehr langsames Tempo, Ziel sind Dauer und Grundlagenausdauer"}]},{"week":"Woche 3–4","theme":"Schwellen-Entwicklung","sessions":[{"name":"Intervalle 5×5 Min","detail":"10-km-Tempo, 90 s Erholung dazwischen — Arbeit an der Laktatschwelle"},{"name":"Fartlek 35 Min","detail":"Wechsle freie Beschleunigungen / lockeres Traben nach Gefühl"},{"name":"Langer Lauf 65 Min","detail":"Mit 15 Min im Marathontempo in der zweiten Hälfte"}]},{"week":"Woche 5–6","theme":"Tempo & Spezifik","sessions":[{"name":"Tempolauf 45 Min","detail":"Halbmarathon-Tempo durchgehend gehalten — kontrollierte Anstrengung"},{"name":"Bahneinheit 12×400 m","detail":"5-km-Zieltempo, 200 m Trab-Erholung zwischen jeder Wiederholung"},{"name":"12-Min-Cooper-Test","detail":"Maximaler Lauf über 12 Min, um den VO2max-Fortschritt zu bewerten"}]},{"week":"Woche 7–8","theme":"Tapering & Wettkampf","sessions":[{"name":"Volumenreduktion −30%","detail":"Senke die Kilometer, aber behalte die Tempi — aktive Erholung"},{"name":"Steigerungsläufe 8×100 m","detail":"Progressive Beschleunigungen, um vor dem Wettkampf spritzig zu bleiben"},{"name":"Wettkampftag-Simulation","detail":"Aufwärmen + 20 Min im Zieltempo + Cool-down"}]}],"faq":[{"q":"Wie oft sollte ich pro Woche laufen?","a":"Anfänger: 3 Einheiten. Fortgeschritten: 4–5 Einheiten. Erfahren: 5–6 Einheiten mit einem kompletten Ruhetag. Qualität schlägt Quantität."},{"q":"Wie vermeide ich Knieschmerzen?","a":"Stärke dein Gesäß und deine Beinbeuger (Kniebeugen, Ausfallschritte), arbeite an deiner Kadenz (ziele auf 175 Schritte/Min) und bevorzuge anfangs weiche Untergründe."},{"q":"Soll ich nüchtern laufen, um mehr Fett zu verbrennen?","a":"Nüchternlaufen verbessert die Fettnutzung, reduziert aber die Leistung. Nur für lockere Läufe (< 45 Min) in Zone 2 empfohlen."},{"q":"Wie lange bis zu meinen ersten 5 km?","a":"Mit unserem Anfängerprogramm reichen 8 Wochen, um 5 km ohne Pause zu laufen, egal mit welcher Ausgangsform."},{"q":"Welchen Schuh wähle ich zum Start?","a":"Geh für eine kostenlose Laufanalyse ins Fachgeschäft. Bevorzuge einen gut gedämpften Schuh, wenn du auf Asphalt läufst — Budget mindestens 100–150 €."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('running-cardio', 0, array['Byjy-LzSNc0','BmJbKsV2r9o']::text[], 'pro', '{"fr":{"title":"9 Minutes pour corriger ta foulée","description":"Corrige ta technique de course en 9 min — posture, attaque, cadence détaillées étape par étape.","duration":"9 min","level":"Tous niveaux"},"en":{"title":"9 Minutes to fix your running form","description":"Fix your running technique in 9 min — posture, foot strike and cadence broken down step by step.","duration":"9 min","level":"All levels"},"de":{"title":"9 Minuten, um deine Lauftechnik zu korrigieren","description":"Korrigiere deine Lauftechnik in 9 Min — Haltung, Fußaufsatz und Kadenz Schritt für Schritt erklärt.","duration":"9 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('running-cardio', 1, array['sScNDZu2MWk','UrHOGy6jQ1g']::text[], 'pro', '{"fr":{"title":"Foulée parfaite — 5 conseils","description":"Les 5 secrets pour courir plus vite et sans douleur — technique validée par des coachs de haut niveau.","duration":"12 min","level":"Intermédiaire"},"en":{"title":"Perfect stride — 5 tips","description":"The 5 secrets to running faster and pain-free — technique validated by elite coaches.","duration":"12 min","level":"Intermediate"},"de":{"title":"Perfekter Laufschritt — 5 Tipps","description":"Die 5 Geheimnisse, um schneller und schmerzfrei zu laufen — von Elite-Coaches bestätigte Technik.","duration":"12 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('running-cardio', 2, array['_kGESn8ArrU','Xpg2JXiNwcY']::text[], 'pro', '{"fr":{"title":"Technique de course expliquée","description":"Guide complet de la technique de course — cadence, appui, respiration et prévention des blessures.","duration":"15 min","level":"Avancé"},"en":{"title":"Running technique explained","description":"Complete guide to running technique — cadence, foot strike, breathing and injury prevention.","duration":"15 min","level":"Advanced"},"de":{"title":"Lauftechnik erklärt","description":"Kompletter Leitfaden zur Lauftechnik — Kadenz, Fußaufsatz, Atmung und Verletzungsprävention.","duration":"15 Min","level":"Erfahren"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('running-cardio', 3, array['KxKJEIqS1HQ','SU3DqokJnjo']::text[], 'pro', '{"fr":{"title":"Séance interval run 20 min","description":"Entraînement fractionné complet de 20 minutes — alternance sprints et récupération pour progresser vite.","duration":"20 min","level":"Intermédiaire"},"en":{"title":"20-min interval run session","description":"A complete 20-minute interval workout — alternating sprints and recovery to progress quickly.","duration":"20 min","level":"Intermediate"},"de":{"title":"20-Min-Intervalllauf-Einheit","description":"Ein komplettes 20-minütiges Intervalltraining — Wechsel aus Sprints und Erholung für schnellen Fortschritt.","duration":"20 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('running-cardio', 4, array['HFUz5qazxn0','UdBR85D8e8g']::text[], 'pro', '{"fr":{"title":"Conseils pour les intervalles","description":"Comment bien structurer ses intervalles pour maximiser la progression en course à pied.","duration":"11 min","level":"Tous niveaux"},"en":{"title":"Tips for intervals","description":"How to structure your intervals well to maximize progress in running.","duration":"11 min","level":"All levels"},"de":{"title":"Tipps für Intervalle","description":"Wie du deine Intervalle gut strukturierst, um den Fortschritt beim Laufen zu maximieren.","duration":"11 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('running-cardio', 5, array['fbATY-sbqA8','9rX9m_bemB0']::text[], 'pro', '{"fr":{"title":"Pourquoi faire des intervalles ?","description":"La science derrière le fractionné — comment et pourquoi les intervalles boostent vos performances.","duration":"13 min","level":"Débutant"},"en":{"title":"Why do interval training?","description":"The science behind intervals — how and why interval work boosts your performance.","duration":"13 min","level":"Beginner"},"de":{"title":"Warum Intervalltraining?","description":"Die Wissenschaft hinter den Intervallen — wie und warum Intervallarbeit deine Leistung steigert.","duration":"13 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_disciplines (slug, sort_order, color, icon, min_plan) values ('musculation', 1, 'blue', 'dumbbell', 'free') on conflict (slug) do update set sort_order=excluded.sort_order, color=excluded.color, icon=excluded.icon, min_plan=excluded.min_plan, updated_at=now();
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('musculation', 'fr', '{"title":"Musculation","tag":"Strength","description":"Prise de masse, sèche ou tonification — nos coaches certifiés construisent ton programme sur mesure selon ta morphologie.","stats":["+3 800 membres","90+ programmes","8 semaines moy."],"levels":["Débutant","Intermédiaire","Avancé","Élite"]}'::jsonb, '{"tagline":"Construis ton physique avec une précision chirurgicale.","heroStat":"3 800+ membres actifs","guide":{"technique":{"emoji":"💪","title":"Technique & Exécution","items":["Range of motion complète — un squat parallèle sollicite 40 % plus de fibres musculaires","Tempo contrôlé : 2 s descente / 1 s pause / 1 s montée pour maximiser le stimulus hypertrophique","Connexion neuro-musculaire — pense au muscle ciblé pendant l''exercice (mind-muscle connection)","Respiration : expire sur l''effort concentrique, inspire sur l''excentrique","Échauffement spécifique obligatoire : 2–3 séries légères avant de charger lourd"]},"equipment":{"emoji":"🏋️","title":"Équipement clé","items":["Ceinture de musculation pour les charges lourdes (squat / deadlift > 80 % 1RM)","Chaussures spécifiques halterophilie (semelle plate) ou running à faible drop","Straps de poignet pour tirage et rowing — préserve les tendons sur le long terme","Chalk (magnésie) pour améliorer la prise en main sur barre et kettlebell","Carnet de suivi ou app Xenotif® pour tracker les charges et la progression"]},"nutrition":{"emoji":"🥩","title":"Nutrition pour la performance","items":["Apport protéique : 1,8–2,2 g de protéines / kg de poids corporel par jour","Surplus calorique de 200–300 kcal/j pour la prise de masse — prise de masse lente et propre","Répartition 4–5 repas/jour pour maintenir la synthèse protéique continue","Créatine monohydrate : 3–5 g/jour — le supplément le plus documenté scientifiquement","Fenêtre anabolique : 40 g de protéines dans les 60 min post-séance"]},"recovery":{"emoji":"😴","title":"Récupération musculaire","items":["Minimum 48h de repos par groupe musculaire avant de le retraviller","Sommeil 8–9h — la GH (hormone de croissance) est sécrétée principalement la nuit","Déload toutes les 4–6 semaines : réduction du volume de 40–50 % pour surcompensation","Massage / rouleau 15 min post-séance sur les muscles travaillés","Bain froid ou contraste chaud/froid pour accélérer l''élimination des déchets métaboliques"]}},"tips":[{"icon":"📊","title":"Surcharge progressive","body":"Augmente charge ou répétitions chaque semaine — même 500 g de plus sur la barre en une année, c''est 26 kg gagnés sur ton squat."},{"icon":"🔬","title":"Hypertrophie vs force","body":"Force : 1–5 reps à 85–100 % 1RM. Hypertrophie : 6–12 reps à 65–80 % 1RM. Varie les protocoles chaque mois."},{"icon":"⏱️","title":"Temps de repos optimal","body":"Hypertrophie : 60–90 s. Force maximale : 3–5 min. Raccourcir les repos n''est pas plus efficace — c''est moins efficace."},{"icon":"🎯","title":"Priorité aux polyarticulaires","body":"Squat, deadlift, bench press, overhead press et rowing donnent 80 % des résultats. Les isolations sont le bonus."}],"exercises":[{"name":"Squat barre","muscles":"Quadriceps, fessiers, ischio-jambiers, dos","sets":"4×8","difficulty":"Tous niveaux","description":"Barre en position haute dorsale, pieds à largeur d''épaules. Descend jusqu''au parallèle en gardant les genoux dans l''axe des pieds. Le roi des exercices de musculation."},{"name":"Deadlift","muscles":"Dos entier, fessiers, ischio-jambiers, trapèzes","sets":"4×5","difficulty":"Intermédiaire","description":"Attrape la barre en pronation, dos plat, hanches basses. Pousse dans le sol et tire jusqu''à l''extension complète. Mouvement fondamental pour la force totale."},{"name":"Développé couché","muscles":"Pectoraux, triceps, deltoïde antérieur","sets":"4×8","difficulty":"Tous niveaux","description":"Allongé sur le banc, barre au niveau de la poitrine. Pousse verticalement sans rebond. L''exercice de référence pour développer la poitrine et les triceps."},{"name":"Tractions / Pull-ups","muscles":"Grand dorsal, biceps, rhomboïdes","sets":"4×AMRAP","difficulty":"Intermédiaire","description":"Suspendu à la barre, prise en pronation. Tire jusqu''au menton au-dessus de la barre. Meilleur exercice pour l''épaisseur et la largeur du dos."},{"name":"Overhead Press","muscles":"Épaules, triceps, trapèzes","sets":"4×8","difficulty":"Intermédiaire","description":"Barre au niveau des clavicules, pousse verticalement jusqu''à extension complète. Rentre la tête dans les épaules en fin de mouvement pour un verrouillage sûr."},{"name":"Romanian Deadlift","muscles":"Ischio-jambiers, fessiers, bas du dos","sets":"3×10","difficulty":"Intermédiaire","description":"Barre tenue devant les cuisses, penche le buste en avant en gardant le dos plat et les genoux légèrement fléchis. Excellent pour l''hypertrophie des ischios."},{"name":"Dips","muscles":"Pectoraux, triceps, deltoïde antérieur","sets":"3×12","difficulty":"Intermédiaire","description":"Appui sur les barres parallèles, descends jusqu''à ce que les bras soient à 90°, remonte sans hyperextension des coudes. Ajoute un lest quand c''est trop facile."},{"name":"Rowing barre","muscles":"Grand dorsal, rhomboïdes, biceps, trapèzes","sets":"4×8","difficulty":"Avancé","description":"Penché à 45°, barre au sol, tire jusqu''au bas de la poitrine. Volume sur les muscles du dos indispensable pour un dos épais et un équilibre musculaire optimal."},{"name":"Leg press","muscles":"Quadriceps, fessiers, mollets","sets":"3×12","difficulty":"Débutant","description":"Machine leg press : pieds à largeur d''épaules, descends jusqu''au 90° puis pousse. Idéal pour augmenter le volume sur les jambes sans charger la colonne."},{"name":"Face pull","muscles":"Deltoïde postérieur, coiffe des rotateurs, rhomboïdes","sets":"3×20","difficulty":"Tous niveaux","description":"Poulie haute, tire la corde vers le visage en écartant les mains. Indispensable pour la santé des épaules et contre-balancer le volume en développé couché."}],"program":[{"week":"Semaine 1–2","theme":"Apprentissage technique","sessions":[{"name":"Push A : Poitrine + Épaules","detail":"Bench press 4×8, OHP 3×10, Dips 3×12, Latéral raises 3×15"},{"name":"Pull A : Dos + Biceps","detail":"Deadlift 4×5, Pull-ups 4×AMRAP, Rowing barre 3×10, Curl 3×12"},{"name":"Legs : Quadriceps + Ischios","detail":"Squat 4×8, Romanian DL 3×10, Leg press 3×12, Mollets 4×15"}]},{"week":"Semaine 3–4","theme":"Hypertrophie — Surcharge progressive","sessions":[{"name":"Push B : Volume élevé","detail":"Incliné 4×10, Dips lestés 3×8, Cable fly 3×15, Overhead DB 4×12"},{"name":"Pull B : Focus largeur dos","detail":"Pull-ups lestés 4×6, Seated row 4×12, Face pull 3×20, Hammer curl 3×15"},{"name":"Legs B : Force + Volume","detail":"Squat lourd 5×5, Hack squat 3×12, Leg extension 3×15, GHR 3×10"}]},{"week":"Semaine 5–6","theme":"Intensification — Test de force","sessions":[{"name":"Full body force","detail":"Squat 5×3, Bench 5×3, Deadlift 5×3 — charges maximales avec repos complets"},{"name":"Full body hypertrophie","detail":"Supersets antagonistes, 4×12, repos 60 s — volume total élevé"},{"name":"AMRAP bilan","detail":"Test max reps à 75 % 1RM sur squat / bench / deadlift — mesure progrès"}]},{"week":"Semaine 7–8","theme":"Déload & Reconstitution","sessions":[{"name":"Volume réduit −40 %","detail":"Même exercices, charges légères — récupération des tendons et système nerveux"},{"name":"Mobilité + gainage","detail":"Yoga muscu, travail de la ceinture scapulaire, planche et anti-rotation"},{"name":"Test 1RM jour J","detail":"Évaluation 1 rep max sur squat, bench et deadlift pour ajuster le prochain cycle"}]}],"faq":[{"q":"Combien de fois par semaine s''entraîner ?","a":"3–4 séances/semaine suffisent pour 90 % des objectifs en musculation. Plus n''est pas toujours mieux — la récupération est aussi importante que le stimulus."},{"q":"Faut-il prendre des compléments alimentaires ?","a":"Non obligatoire. La créatine et les protéines whey sont les seuls suppléments scientifiquement validés pour la performance. Priorise d''abord l''alimentation."},{"q":"Combien de temps avant de voir des résultats ?","a":"Les premiers changements neurologiques (force) apparaissent en 2–3 semaines. Les changements musculaires visibles prennent 6–12 semaines selon la génétique et la nutrition."},{"q":"Comment éviter les plateaux ?","a":"Varie les exercices, le volume, l''intensité et les temps de repos. Notre IA Xenotif® ajuste automatiquement ton programme pour éviter l''adaptation."},{"q":"Peut-on prendre du muscle et perdre de la graisse en même temps ?","a":"Oui, en débutant ou après une longue pause (recomposition corporelle). Nécessite un apport protéique élevé et un déficit calorique léger de 100–200 kcal."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('musculation', 'en', '{"title":"Strength training","tag":"Strength","description":"Bulking, cutting or toning — our certified coaches build a custom program tailored to your body type.","stats":["+3,800 members","90+ programs","8 weeks avg."],"levels":["Beginner","Intermediate","Advanced","Elite"]}'::jsonb, '{"tagline":"Build your physique with surgical precision.","heroStat":"3,800+ active members","guide":{"technique":{"emoji":"💪","title":"Technique & Execution","items":["Full range of motion — a parallel squat recruits 40% more muscle fibers","Controlled tempo: 2 s down / 1 s pause / 1 s up to maximize the hypertrophic stimulus","Mind-muscle connection — focus on the target muscle during the exercise","Breathing: exhale on the concentric effort, inhale on the eccentric","Specific warm-up is mandatory: 2–3 light sets before loading heavy"]},"equipment":{"emoji":"🏋️","title":"Key equipment","items":["A lifting belt for heavy loads (squat / deadlift > 80% 1RM)","Weightlifting shoes (flat sole) or low-drop running shoes","Wrist straps for pulling and rowing — protects the tendons long term","Chalk for a better grip on bars and kettlebells","A logbook or the Xenotif® app to track loads and progress"]},"nutrition":{"emoji":"🥩","title":"Nutrition for performance","items":["Protein intake: 1.8–2.2 g of protein per kg of body weight per day","Caloric surplus of 200–300 kcal/day for clean, slow muscle gain","4–5 meals/day to keep protein synthesis continuous","Creatine monohydrate: 3–5 g/day — the most scientifically documented supplement","Anabolic window: 40 g of protein within 60 min post-session"]},"recovery":{"emoji":"😴","title":"Muscle recovery","items":["At least 48h of rest per muscle group before training it again","8–9h of sleep — growth hormone is released mainly at night","Deload every 4–6 weeks: cut volume by 40–50% for supercompensation","Massage / roller 15 min post-session on the worked muscles","Cold bath or hot/cold contrast to speed up metabolic waste clearance"]}},"tips":[{"icon":"📊","title":"Progressive overload","body":"Add load or reps every week — even 500 g more on the bar over a year is 26 kg gained on your squat."},{"icon":"🔬","title":"Hypertrophy vs strength","body":"Strength: 1–5 reps at 85–100% 1RM. Hypertrophy: 6–12 reps at 65–80% 1RM. Vary the protocols every month."},{"icon":"⏱️","title":"Optimal rest time","body":"Hypertrophy: 60–90 s. Max strength: 3–5 min. Shortening rest is not more effective — it''s less effective."},{"icon":"🎯","title":"Prioritize compound lifts","body":"Squat, deadlift, bench press, overhead press and rowing give 80% of the results. Isolation work is the bonus."}],"exercises":[{"name":"Barbell squat","muscles":"Quads, glutes, hamstrings, back","sets":"4×8","difficulty":"All levels","description":"Bar in high-bar position, feet shoulder-width. Descend to parallel keeping the knees tracking over the feet. The king of strength exercises."},{"name":"Deadlift","muscles":"Whole back, glutes, hamstrings, traps","sets":"4×5","difficulty":"Intermediate","description":"Grip the bar overhand, flat back, hips low. Push through the floor and pull to full extension. A fundamental movement for total-body strength."},{"name":"Bench press","muscles":"Pecs, triceps, front delts","sets":"4×8","difficulty":"All levels","description":"Lying on the bench, bar at chest level. Press vertically without bouncing. The reference exercise for building the chest and triceps."},{"name":"Pull-ups","muscles":"Lats, biceps, rhomboids","sets":"4×AMRAP","difficulty":"Intermediate","description":"Hanging from the bar, overhand grip. Pull until your chin is above the bar. The best exercise for back thickness and width."},{"name":"Overhead press","muscles":"Shoulders, triceps, traps","sets":"4×8","difficulty":"Intermediate","description":"Bar at collarbone level, press vertically to full extension. Push your head through at the top for a safe lockout."},{"name":"Romanian deadlift","muscles":"Hamstrings, glutes, lower back","sets":"3×10","difficulty":"Intermediate","description":"Bar held in front of the thighs, hinge forward keeping a flat back and slightly bent knees. Excellent for hamstring hypertrophy."},{"name":"Dips","muscles":"Pecs, triceps, front delts","sets":"3×12","difficulty":"Intermediate","description":"Support on parallel bars, lower until the arms reach 90°, press up without hyperextending the elbows. Add weight when it gets too easy."},{"name":"Barbell row","muscles":"Lats, rhomboids, biceps, traps","sets":"4×8","difficulty":"Advanced","description":"Hinged at 45°, bar from the floor, pull to the lower chest. Back volume is essential for a thick back and balanced musculature."},{"name":"Leg press","muscles":"Quads, glutes, calves","sets":"3×12","difficulty":"Beginner","description":"On the leg press machine: feet shoulder-width, lower to 90° then press. Ideal to add leg volume without loading the spine."},{"name":"Face pull","muscles":"Rear delts, rotator cuff, rhomboids","sets":"3×20","difficulty":"All levels","description":"High pulley, pull the rope toward the face while spreading the hands. Essential for shoulder health and to balance bench-press volume."}],"program":[{"week":"Week 1–2","theme":"Learning technique","sessions":[{"name":"Push A: Chest + Shoulders","detail":"Bench press 4×8, OHP 3×10, Dips 3×12, Lateral raises 3×15"},{"name":"Pull A: Back + Biceps","detail":"Deadlift 4×5, Pull-ups 4×AMRAP, Barbell row 3×10, Curls 3×12"},{"name":"Legs: Quads + Hamstrings","detail":"Squat 4×8, Romanian DL 3×10, Leg press 3×12, Calves 4×15"}]},{"week":"Week 3–4","theme":"Hypertrophy — Progressive overload","sessions":[{"name":"Push B: High volume","detail":"Incline 4×10, Weighted dips 3×8, Cable fly 3×15, Overhead DB 4×12"},{"name":"Pull B: Back width focus","detail":"Weighted pull-ups 4×6, Seated row 4×12, Face pull 3×20, Hammer curl 3×15"},{"name":"Legs B: Strength + Volume","detail":"Heavy squat 5×5, Hack squat 3×12, Leg extension 3×15, GHR 3×10"}]},{"week":"Week 5–6","theme":"Intensification — Strength test","sessions":[{"name":"Full body strength","detail":"Squat 5×3, Bench 5×3, Deadlift 5×3 — maximal loads with full rest"},{"name":"Full body hypertrophy","detail":"Antagonist supersets, 4×12, 60 s rest — high total volume"},{"name":"AMRAP check","detail":"Max-reps test at 75% 1RM on squat / bench / deadlift — measure progress"}]},{"week":"Week 7–8","theme":"Deload & Rebuild","sessions":[{"name":"Volume reduced −40%","detail":"Same exercises, light loads — recovery of tendons and nervous system"},{"name":"Mobility + core","detail":"Yoga-strength, scapular work, plank and anti-rotation"},{"name":"1RM test day","detail":"1-rep-max assessment on squat, bench and deadlift to set the next cycle"}]}],"faq":[{"q":"How many times per week should I train?","a":"3–4 sessions/week are enough for 90% of strength goals. More is not always better — recovery is as important as the stimulus."},{"q":"Do I need supplements?","a":"Not mandatory. Creatine and whey protein are the only supplements scientifically validated for performance. Prioritize nutrition first."},{"q":"How long before I see results?","a":"The first neurological changes (strength) appear in 2–3 weeks. Visible muscle changes take 6–12 weeks depending on genetics and nutrition."},{"q":"How do I avoid plateaus?","a":"Vary the exercises, volume, intensity and rest times. Our Xenotif® AI automatically adjusts your program to prevent adaptation."},{"q":"Can you build muscle and lose fat at the same time?","a":"Yes, when you''re a beginner or after a long break (body recomposition). It requires high protein intake and a slight caloric deficit of 100–200 kcal."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('musculation', 'de', '{"title":"Krafttraining","tag":"Kraft","description":"Masseaufbau, Definition oder Tonisierung — unsere zertifizierten Coaches erstellen ein maßgeschneidertes Programm passend zu deinem Körpertyp.","stats":["+3.800 Mitglieder","90+ Programme","Ø 8 Wochen"],"levels":["Anfänger","Fortgeschritten","Erfahren","Elite"]}'::jsonb, '{"tagline":"Forme deinen Körper mit chirurgischer Präzision.","heroStat":"3.800+ aktive Mitglieder","guide":{"technique":{"emoji":"💪","title":"Technik & Ausführung","items":["Voller Bewegungsumfang — eine parallele Kniebeuge rekrutiert 40% mehr Muskelfasern","Kontrolliertes Tempo: 2 s ab / 1 s Pause / 1 s hoch, um den Hypertrophie-Reiz zu maximieren","Mind-Muscle-Connection — konzentriere dich während der Übung auf den Zielmuskel","Atmung: aus bei der konzentrischen Anstrengung, ein bei der exzentrischen","Spezifisches Aufwärmen ist Pflicht: 2–3 leichte Sätze, bevor du schwer lädst"]},"equipment":{"emoji":"🏋️","title":"Schlüssel-Ausrüstung","items":["Ein Gewichthebergürtel für schwere Lasten (Kniebeuge / Kreuzheben > 80% 1RM)","Gewichtheberschuhe (flache Sohle) oder Laufschuhe mit niedrigem Drop","Zughilfen für Ziehen und Rudern — schützt langfristig die Sehnen","Magnesia für besseren Halt an Stangen und Kettlebells","Ein Trainingstagebuch oder die Xenotif®-App, um Lasten und Fortschritt zu verfolgen"]},"nutrition":{"emoji":"🥩","title":"Ernährung für Leistung","items":["Proteinzufuhr: 1,8–2,2 g Protein pro kg Körpergewicht und Tag","Kalorienüberschuss von 200–300 kcal/Tag für sauberen, langsamen Muskelaufbau","4–5 Mahlzeiten/Tag, um die Proteinsynthese kontinuierlich zu halten","Kreatin-Monohydrat: 3–5 g/Tag — das wissenschaftlich am besten dokumentierte Supplement","Anaboles Fenster: 40 g Protein innerhalb von 60 Min nach der Einheit"]},"recovery":{"emoji":"😴","title":"Muskelregeneration","items":["Mindestens 48 h Ruhe pro Muskelgruppe, bevor du sie erneut trainierst","8–9 h Schlaf — das Wachstumshormon wird vor allem nachts ausgeschüttet","Deload alle 4–6 Wochen: senke das Volumen um 40–50% für die Superkompensation","Massage / Rolle 15 Min nach der Einheit auf den beanspruchten Muskeln","Kaltes Bad oder Warm/Kalt-Wechsel, um den Abtransport von Stoffwechselabfällen zu beschleunigen"]}},"tips":[{"icon":"📊","title":"Progressive Überlastung","body":"Füge jede Woche Last oder Wiederholungen hinzu — selbst 500 g mehr auf der Stange über ein Jahr sind 26 kg mehr in deiner Kniebeuge."},{"icon":"🔬","title":"Hypertrophie vs. Kraft","body":"Kraft: 1–5 Wdh bei 85–100% 1RM. Hypertrophie: 6–12 Wdh bei 65–80% 1RM. Variiere die Protokolle jeden Monat."},{"icon":"⏱️","title":"Optimale Pausenzeit","body":"Hypertrophie: 60–90 s. Maximalkraft: 3–5 Min. Die Pause zu verkürzen ist nicht effektiver — es ist weniger effektiv."},{"icon":"🎯","title":"Priorisiere Grundübungen","body":"Kniebeuge, Kreuzheben, Bankdrücken, Schulterdrücken und Rudern bringen 80% der Ergebnisse. Isolationsarbeit ist der Bonus."}],"exercises":[{"name":"Langhantel-Kniebeuge","muscles":"Quadrizeps, Gesäß, Beinbeuger, Rücken","sets":"4×8","difficulty":"Alle Niveaus","description":"Stange in High-Bar-Position, Füße schulterbreit. Senke bis zur Parallele, die Knie folgen den Füßen. Die Königin der Kraftübungen."},{"name":"Kreuzheben","muscles":"Ganzer Rücken, Gesäß, Beinbeuger, Trapez","sets":"4×5","difficulty":"Fortgeschritten","description":"Greife die Stange im Obergriff, flacher Rücken, Hüfte tief. Drücke durch den Boden und zieh bis zur vollen Streckung. Eine fundamentale Bewegung für die Ganzkörperkraft."},{"name":"Bankdrücken","muscles":"Brust, Trizeps, vordere Schulter","sets":"4×8","difficulty":"Alle Niveaus","description":"Auf der Bank liegend, Stange auf Brusthöhe. Drücke senkrecht ohne Abprallen. Die Referenzübung für Brust und Trizeps."},{"name":"Klimmzüge","muscles":"Latissimus, Bizeps, Rhomboiden","sets":"4×AMRAP","difficulty":"Fortgeschritten","description":"An der Stange hängend, Obergriff. Zieh, bis das Kinn über der Stange ist. Die beste Übung für Rückendicke und -breite."},{"name":"Schulterdrücken","muscles":"Schultern, Trizeps, Trapez","sets":"4×8","difficulty":"Fortgeschritten","description":"Stange auf Schlüsselbeinhöhe, drücke senkrecht bis zur vollen Streckung. Schiebe den Kopf am Ende durch für einen sicheren Lockout."},{"name":"Rumänisches Kreuzheben","muscles":"Beinbeuger, Gesäß, unterer Rücken","sets":"3×10","difficulty":"Fortgeschritten","description":"Stange vor den Oberschenkeln, beuge dich nach vorn mit flachem Rücken und leicht gebeugten Knien. Exzellent für die Hypertrophie der Beinbeuger."},{"name":"Dips","muscles":"Brust, Trizeps, vordere Schulter","sets":"3×12","difficulty":"Fortgeschritten","description":"Stütze an Parallelbarren, senke, bis die Arme 90° erreichen, drücke hoch ohne die Ellbogen zu überstrecken. Füge Gewicht hinzu, wenn es zu leicht wird."},{"name":"Langhantelrudern","muscles":"Latissimus, Rhomboiden, Bizeps, Trapez","sets":"4×8","difficulty":"Erfahren","description":"Vorgebeugt bei 45°, Stange vom Boden, zieh zur unteren Brust. Rückenvolumen ist essenziell für einen dicken Rücken und ausgewogene Muskulatur."},{"name":"Beinpresse","muscles":"Quadrizeps, Gesäß, Waden","sets":"3×12","difficulty":"Anfänger","description":"An der Beinpresse: Füße schulterbreit, senke auf 90°, dann drücke. Ideal, um Beinvolumen aufzubauen, ohne die Wirbelsäule zu belasten."},{"name":"Face Pull","muscles":"Hintere Schulter, Rotatorenmanschette, Rhomboiden","sets":"3×20","difficulty":"Alle Niveaus","description":"Hoher Kabelzug, zieh das Seil zum Gesicht und spreize die Hände. Essenziell für die Schultergesundheit und zum Ausgleich des Bankdrück-Volumens."}],"program":[{"week":"Woche 1–2","theme":"Technik lernen","sessions":[{"name":"Push A: Brust + Schultern","detail":"Bankdrücken 4×8, Schulterdrücken 3×10, Dips 3×12, Seitheben 3×15"},{"name":"Pull A: Rücken + Bizeps","detail":"Kreuzheben 4×5, Klimmzüge 4×AMRAP, Langhantelrudern 3×10, Curls 3×12"},{"name":"Beine: Quadrizeps + Beinbeuger","detail":"Kniebeuge 4×8, RDL 3×10, Beinpresse 3×12, Waden 4×15"}]},{"week":"Woche 3–4","theme":"Hypertrophie — Progressive Überlastung","sessions":[{"name":"Push B: Hohes Volumen","detail":"Schrägbank 4×10, Dips mit Gewicht 3×8, Cable Fly 3×15, Kurzhantel-Schulterdrücken 4×12"},{"name":"Pull B: Fokus Rückenbreite","detail":"Klimmzüge mit Gewicht 4×6, Sitzendes Rudern 4×12, Face Pull 3×20, Hammer-Curl 3×15"},{"name":"Beine B: Kraft + Volumen","detail":"Schwere Kniebeuge 5×5, Hackenschmidt-Kniebeuge 3×12, Beinstrecker 3×15, GHR 3×10"}]},{"week":"Woche 5–6","theme":"Intensivierung — Krafttest","sessions":[{"name":"Ganzkörper Kraft","detail":"Kniebeuge 5×3, Bank 5×3, Kreuzheben 5×3 — maximale Lasten mit voller Pause"},{"name":"Ganzkörper Hypertrophie","detail":"Antagonisten-Supersätze, 4×12, 60 s Pause — hohes Gesamtvolumen"},{"name":"AMRAP-Check","detail":"Max-Wiederholungstest bei 75% 1RM auf Kniebeuge / Bank / Kreuzheben — Fortschritt messen"}]},{"week":"Woche 7–8","theme":"Deload & Wiederaufbau","sessions":[{"name":"Volumen reduziert −40%","detail":"Gleiche Übungen, leichte Lasten — Erholung von Sehnen und Nervensystem"},{"name":"Mobilität + Rumpf","detail":"Yoga-Kraft, Schulterblattarbeit, Plank und Anti-Rotation"},{"name":"1RM-Testtag","detail":"1-Wiederholungs-Maximum auf Kniebeuge, Bank und Kreuzheben, um den nächsten Zyklus festzulegen"}]}],"faq":[{"q":"Wie oft pro Woche sollte ich trainieren?","a":"3–4 Einheiten/Woche reichen für 90% der Kraftziele. Mehr ist nicht immer besser — Erholung ist so wichtig wie der Reiz."},{"q":"Brauche ich Supplemente?","a":"Nicht zwingend. Kreatin und Whey-Protein sind die einzigen wissenschaftlich für die Leistung validierten Supplemente. Priorisiere zuerst die Ernährung."},{"q":"Wie lange bis ich Ergebnisse sehe?","a":"Die ersten neuronalen Veränderungen (Kraft) treten in 2–3 Wochen auf. Sichtbare Muskelveränderungen brauchen 6–12 Wochen, je nach Genetik und Ernährung."},{"q":"Wie vermeide ich Plateaus?","a":"Variiere Übungen, Volumen, Intensität und Pausenzeiten. Unsere Xenotif®-KI passt dein Programm automatisch an, um Gewöhnung zu verhindern."},{"q":"Kann man gleichzeitig Muskeln aufbauen und Fett verlieren?","a":"Ja, als Anfänger oder nach einer langen Pause (Körper-Rekomposition). Es erfordert hohe Proteinzufuhr und ein leichtes Kaloriendefizit von 100–200 kcal."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('musculation', 0, array['DUuh5wrkLIY','tunVzHcch-w']::text[], 'free', '{"fr":{"title":"Tutoriel ultime du Deadlift","description":"Le soulevé de terre parfait avec Martins Licis (Champion du Monde Strongman 2019) — technique complète.","duration":"18 min","level":"Tous niveaux"},"en":{"title":"The ultimate Deadlift tutorial","description":"The perfect deadlift with Martins Licis (2019 World''s Strongest Man) — complete technique.","duration":"18 min","level":"All levels"},"de":{"title":"Das ultimative Kreuzheben-Tutorial","description":"Das perfekte Kreuzheben mit Martins Licis (Strongest Man 2019) — komplette Technik.","duration":"18 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
