insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('musculation', 2, array['gNdZuaYZz7E']::text[], 'pro', '{"fr":{"title":"Soulevé de terre — Tutoriel complet","description":"Guide en français du deadlift : position de départ, dos plat, verrouillage et variantes selon l''objectif.","duration":"16 min","level":"Intermédiaire"},"en":{"title":"Deadlift — complete tutorial","description":"A full deadlift guide: starting position, flat back, lockout and variations depending on the goal.","duration":"16 min","level":"Intermediate"},"de":{"title":"Kreuzheben — komplettes Tutorial","description":"Ein vollständiger Kreuzheben-Leitfaden: Startposition, flacher Rücken, Lockout und Varianten je nach Ziel.","duration":"16 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
