insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('musculation', 5, array['h--woXuXXmk']::text[], 'pro', '{"fr":{"title":"SBD pour débutants — Squat, Bench, Deadlift","description":"Introduction aux trois mouvements fondamentaux de la force — tout ce qu''un débutant doit savoir.","duration":"20 min","level":"Débutant"},"en":{"title":"SBD for beginners — Squat, Bench, Deadlift","description":"Introduction to the three fundamental strength lifts — everything a beginner needs to know.","duration":"20 min","level":"Beginner"},"de":{"title":"SBD für Anfänger — Kniebeuge, Bank, Kreuzheben","description":"Einführung in die drei fundamentalen Kraftübungen — alles, was ein Anfänger wissen muss.","duration":"20 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
