insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('hiit', 'fr', '{"title":"HIIT","tag":"Fat Burn","description":"Séances courtes et intenses pour brûler un maximum de calories et booster ton métabolisme durablement en 20 à 30 min.","stats":["+2 100 membres","60+ circuits","20–30 min / séance"],"levels":["Débutant","Intermédiaire","Avancé"]}'::jsonb, '{"tagline":"Brûle 500 kcal en 25 minutes. Prouvé scientifiquement.","heroStat":"2 100+ membres actifs","guide":{"technique":{"emoji":"⚡","title":"Principes HIIT","items":["Ratio effort/repos : 1:1 pour débutants (20 s effort / 20 s repos), 2:1 pour avancés","Intensité cible : 85–95 % FCmax pendant les phases d''effort — sinon ce n''est pas du HIIT","Exercices polyarticulaires prioritaires : burpees, squat jumps, mountain climbers, sprints","Temps total recommandé : 15–25 min — les séances longues ne sont pas plus efficaces","L''EPOC (post-combustion) brûle des calories encore 24–48h après une bonne séance HIIT"]},"equipment":{"emoji":"🏃","title":"Matériel requis","items":["Zéro équipement nécessaire — le HIIT au poids du corps est aussi efficace que la salle","Option salle : rameur, vélo assault bike, TRX pour varier les stimuli","Montre cardiaque pour s''assurer de rester dans la bonne zone d''intensité","Tapis de sol pour les exercices au sol (burpees, mountain climbers)","Timer application (Interval Timer) — Xenotif® intègre des minuteries HIIT pré-programmées"]},"nutrition":{"emoji":"🍌","title":"Nutrition HIIT","items":["Collation légère 30–60 min avant : banane, toast avec beurre d''amande","Évite les repas lourds dans les 2h avant une séance — risque de nausées","Hydratation critique : 500 ml d''eau avant, boire pendant si séance > 20 min","Post-HIIT : combinaison glucides + protéines dans les 30 min (shaker whey + fruit)","La caféine (café noir, pre-workout) améliore la performance HIIT de 10–15 %"]},"recovery":{"emoji":"🧘","title":"Récupération entre séances","items":["Maximum 3–4 séances HIIT / semaine — alternance obligatoire avec jours légers","Cool-down 5–10 min de marche + stretching dynamique post-séance","Le HIIT quotidien mène au surentraînement en 2–3 semaines — respecte les jours off","Qualité du sommeil primordiale : le HIIT tardif (< 3h avant dormir) perturbe le sommeil","Bain froid 10 min ou douche froide immédiatement post-séance — réduction de l''inflammation"]}},"tips":[{"icon":"🔥","title":"L''effet EPOC","body":"Une séance HIIT de 20 min brûle autant de calories qu''un footing de 45 min — et continue à brûler 24h plus tard grâce à l''EPOC post-combustion."},{"icon":"📈","title":"Progressivité obligatoire","body":"Commence à 30 s/30 s × 8 rounds. Augmente les rounds avant d''augmenter l''intensité. Trop vite = blessure ou abandon."},{"icon":"🎵","title":"La musique booste de 15 %","body":"Une playlist rythmée à 140–160 BPM améliore significativement la performance HIIT. Précharge ta playlist avant chaque séance."},{"icon":"🧪","title":"Varie les protocoles","body":"Tabata (20/10), EMOM, Pyramid, AMRAPs — alterner les formats prévient l''adaptation et brise les plateaux."}],"exercises":[{"name":"Burpees","muscles":"Full body, cardio","sets":"3×15","difficulty":"Intermédiaire","description":"Position debout, descends en squat, pose les mains, étends les jambes en position pompe, fais une pompe, ramène les pieds, saute. L''exercice HIIT ultime."},{"name":"Mountain climbers","muscles":"Abdominaux, fléchisseurs de hanche, cardio","sets":"3×30 s","difficulty":"Débutant","description":"Position de planche haute, ramène les genoux vers la poitrine en alternance à vitesse maximum. Maintiens le bassin stable et les hanches basses."},{"name":"Squat jumps","muscles":"Quadriceps, fessiers, explosivité cardio","sets":"3×15","difficulty":"Intermédiaire","description":"Squat à 90° puis explose vers le haut en sautant, bras propulsés. Atterris en amortissant avec les genoux fléchis. Développe la puissance et le cardio simultanément."},{"name":"High knees","muscles":"Fléchisseurs de hanche, cardio","sets":"3×30 s","difficulty":"Débutant","description":"Course sur place en montant les genoux à hauteur des hanches. Bras en rythme à 90°. Excellent échauffement HIIT ou exercice d''intensification cardio."},{"name":"Ice skaters","muscles":"Fessiers, abducteurs, coordination cardio","sets":"3×20/côté","difficulty":"Intermédiaire","description":"Saute latéralement d''un pied à l''autre en mimant le patineur. Touche le sol avec la main opposée au pied d''appui. Travaille les déplacements latéraux et le cardio."},{"name":"Push-up clapping","muscles":"Pectoraux, triceps, explosivité","sets":"3×10","difficulty":"Avancé","description":"Pompe explosive avec claquement des mains en l''air avant de revenir. Nécessite une bonne base de pompes classiques. Développe la puissance du haut du corps."},{"name":"Box jumps","muscles":"Quadriceps, mollets, puissance cardio","sets":"4×10","difficulty":"Intermédiaire","description":"Monte sur une caisse en sautant, amortis en demi-squat. Descends par l''extérieur. Hauteur progressive : 40, 50, 60, 70 cm selon le niveau."},{"name":"Planche dynamique","muscles":"Abdominaux, épaules, gainage","sets":"3×30 s","difficulty":"Intermédiaire","description":"Depuis la planche haute, descends sur les avant-bras et remonte en alternant les bras. Garde les hanches stables et évite la rotation du bassin."},{"name":"Sprint 30 m","muscles":"Cardio max, quadriceps, mollets","sets":"10×30 m","difficulty":"Avancé","description":"Sprint à 100 % de la vitesse maximale sur 30 mètres. Récupération complète (90 s) entre chaque. Développe la puissance anaérobie et la vitesse de pointe."}],"program":[{"week":"Semaine 1–2","theme":"Initiation — Découverte de l''intensité","sessions":[{"name":"Tabata découverte 4×4 min","detail":"Squat, mountain climber, jumping jack, planche — 20 s actif / 10 s repos"},{"name":"Circuit AMRAP 15 min","detail":"5 burpees + 10 squat jumps + 15 mountain climbers — max tours possible"},{"name":"Active recovery","detail":"Marche rapide 30 min + yoga mobilité 15 min"}]},{"week":"Semaine 3–4","theme":"Progression — Intensité 85 % FCmax","sessions":[{"name":"EMOM 20 min","detail":"Chaque minute : 10 burpees + 15 squat jumps — terminer avant la fin de la minute"},{"name":"Pyramid HIIT","detail":"30/30 → 40/20 → 50/10 → 40/20 → 30/30 — 3 cycles complets"},{"name":"Sprint pyramide","detail":"10-20-30-40-30-20-10 m sprints avec récup complète entre chaque"}]},{"week":"Semaine 5–6","theme":"Performance — Dépassement","sessions":[{"name":"Death by burpees","detail":"Minute 1 : 1 burpee. Minute 2 : 2 burpees. Continue jusqu''à ne plus tenir le rythme"},{"name":"Partner WOD","detail":"3 rounds : 50 squat jumps + 40 push-ups + 30 sit-ups + 20 burpees — en duo"},{"name":"Test VO2max HIIT","detail":"Protocol Yo-Yo niveau 1 — évaluation cardio pour ajuster les zones de travail"}]},{"week":"Semaine 7–8","theme":"Maintenance & Consolidation","sessions":[{"name":"Circuit \"best of\"","detail":"Tes 3 exercices préférés des semaines précédentes — 5 rounds à intensité max"},{"name":"Active recovery week","detail":"Volume réduit de 50 % — maintien de la forme sans surcharge"},{"name":"Bilan performance","detail":"Test Cooper + test Tabata + mesures corporelles — évaluation globale"}]}],"faq":[{"q":"Le HIIT est-il efficace pour perdre du poids ?","a":"Oui — la combinaison de forte dépense calorique + EPOC post-combustion en fait l''un des meilleurs outils pour la perte de masse grasse, surtout abdominal."},{"q":"Peut-on faire du HIIT tous les jours ?","a":"Non — le corps a besoin de 48h pour récupérer d''une vraie séance HIIT. 3–4 séances/semaine avec des jours de repos actif est le maximum conseillé."},{"q":"Le HIIT est-il adapté aux débutants ?","a":"Oui, à condition de commencer avec des protocoles doux (30 s/30 s) et des exercices à faible impact (pas de sauts). Notre programme débutant est progressif sur 4 semaines."},{"q":"Combien de calories brûle une séance HIIT ?","a":"Entre 300 et 600 kcal pour 20–30 min selon le poids et l''intensité — plus que 45 min de footing grâce à l''EPOC."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('hiit', 'en', '{"title":"HIIT","tag":"Fat Burn","description":"Short, intense sessions to burn maximum calories and boost your metabolism for the long run in 20 to 30 min.","stats":["+2,100 members","60+ circuits","20–30 min / session"],"levels":["Beginner","Intermediate","Advanced"]}'::jsonb, '{"tagline":"Burn 500 kcal in 25 minutes. Scientifically proven.","heroStat":"2,100+ active members","guide":{"technique":{"emoji":"⚡","title":"HIIT principles","items":["Work/rest ratio: 1:1 for beginners (20 s work / 20 s rest), 2:1 for advanced","Target intensity: 85–95% HRmax during the work phases — otherwise it isn''t HIIT","Prioritize compound exercises: burpees, squat jumps, mountain climbers, sprints","Recommended total time: 15–25 min — longer sessions are not more effective","EPOC (afterburn) keeps burning calories 24–48h after a good HIIT session"]},"equipment":{"emoji":"🏃","title":"Required gear","items":["Zero equipment needed — bodyweight HIIT is as effective as the gym","Gym option: rower, assault bike, TRX to vary the stimuli","A heart-rate monitor to make sure you stay in the right intensity zone","A floor mat for ground exercises (burpees, mountain climbers)","A timer app (Interval Timer) — Xenotif® includes preset HIIT timers"]},"nutrition":{"emoji":"🍌","title":"HIIT nutrition","items":["Light snack 30–60 min before: banana, toast with almond butter","Avoid heavy meals within 2h before a session — risk of nausea","Hydration is critical: 500 ml of water before, drink during if the session is > 20 min","Post-HIIT: carbs + protein combo within 30 min (whey shake + fruit)","Caffeine (black coffee, pre-workout) improves HIIT performance by 10–15%"]},"recovery":{"emoji":"🧘","title":"Recovery between sessions","items":["Maximum 3–4 HIIT sessions / week — alternate with easy days","Cool-down 5–10 min of walking + dynamic stretching post-session","Daily HIIT leads to overtraining in 2–3 weeks — respect your off days","Sleep quality is essential: late HIIT (< 3h before bed) disrupts sleep","Cold bath 10 min or cold shower right after the session — reduces inflammation"]}},"tips":[{"icon":"🔥","title":"The EPOC effect","body":"A 20-min HIIT session burns as many calories as a 45-min run — and keeps burning 24h later thanks to the EPOC afterburn."},{"icon":"📈","title":"Progression is mandatory","body":"Start at 30 s/30 s × 8 rounds. Increase the rounds before increasing the intensity. Too fast = injury or burnout."},{"icon":"🎵","title":"Music boosts you by 15%","body":"A rhythmic playlist at 140–160 BPM significantly improves HIIT performance. Preload your playlist before each session."},{"icon":"🧪","title":"Vary the protocols","body":"Tabata (20/10), EMOM, Pyramid, AMRAPs — alternating formats prevents adaptation and breaks plateaus."}],"exercises":[{"name":"Burpees","muscles":"Full body, cardio","sets":"3×15","difficulty":"Intermediate","description":"From standing, drop into a squat, place the hands, kick the legs back to a push-up position, do a push-up, bring the feet back, jump. The ultimate HIIT exercise."},{"name":"Mountain climbers","muscles":"Abs, hip flexors, cardio","sets":"3×30 s","difficulty":"Beginner","description":"High plank position, drive the knees toward the chest alternately at maximum speed. Keep the hips stable and low."},{"name":"Squat jumps","muscles":"Quads, glutes, explosive cardio","sets":"3×15","difficulty":"Intermediate","description":"Squat to 90° then explode upward jumping, arms driving up. Land softly with bent knees. Builds power and cardio at the same time."},{"name":"High knees","muscles":"Hip flexors, cardio","sets":"3×30 s","difficulty":"Beginner","description":"Run in place driving the knees to hip height. Arms in rhythm at 90°. A great HIIT warm-up or cardio intensifier."},{"name":"Ice skaters","muscles":"Glutes, abductors, cardio coordination","sets":"3×20/side","difficulty":"Intermediate","description":"Jump laterally from one foot to the other mimicking a skater. Touch the floor with the hand opposite the supporting foot. Works lateral movement and cardio."},{"name":"Clapping push-ups","muscles":"Pecs, triceps, explosiveness","sets":"3×10","difficulty":"Advanced","description":"Explosive push-up with a hand clap in the air before landing. Requires a solid base of regular push-ups. Builds upper-body power."},{"name":"Box jumps","muscles":"Quads, calves, explosive cardio","sets":"4×10","difficulty":"Intermediate","description":"Jump onto a box, absorb in a half-squat. Step down on the outside. Progressive height: 40, 50, 60, 70 cm depending on level."},{"name":"Dynamic plank","muscles":"Abs, shoulders, core","sets":"3×30 s","difficulty":"Intermediate","description":"From a high plank, lower onto the forearms and back up alternating arms. Keep the hips stable and avoid rotating the pelvis."},{"name":"30 m sprint","muscles":"Max cardio, quads, calves","sets":"10×30 m","difficulty":"Advanced","description":"Sprint at 100% of max speed over 30 meters. Full recovery (90 s) between each. Builds anaerobic power and top speed."}],"program":[{"week":"Week 1–2","theme":"Initiation — Discovering intensity","sessions":[{"name":"Tabata intro 4×4 min","detail":"Squat, mountain climber, jumping jack, plank — 20 s active / 10 s rest"},{"name":"AMRAP circuit 15 min","detail":"5 burpees + 10 squat jumps + 15 mountain climbers — as many rounds as possible"},{"name":"Active recovery","detail":"Brisk walk 30 min + mobility yoga 15 min"}]},{"week":"Week 3–4","theme":"Progression — Intensity 85% HRmax","sessions":[{"name":"EMOM 20 min","detail":"Every minute: 10 burpees + 15 squat jumps — finish before the minute is up"},{"name":"Pyramid HIIT","detail":"30/30 → 40/20 → 50/10 → 40/20 → 30/30 — 3 full cycles"},{"name":"Sprint pyramid","detail":"10-20-30-40-30-20-10 m sprints with full recovery between each"}]},{"week":"Week 5–6","theme":"Performance — Pushing limits","sessions":[{"name":"Death by burpees","detail":"Minute 1: 1 burpee. Minute 2: 2 burpees. Continue until you can''t keep the pace"},{"name":"Partner WOD","detail":"3 rounds: 50 squat jumps + 40 push-ups + 30 sit-ups + 20 burpees — in pairs"},{"name":"HIIT VO2max test","detail":"Yo-Yo level 1 protocol — cardio assessment to fine-tune your work zones"}]},{"week":"Week 7–8","theme":"Maintenance & Consolidation","sessions":[{"name":"\"Best of\" circuit","detail":"Your 3 favorite exercises from previous weeks — 5 rounds at max intensity"},{"name":"Active recovery week","detail":"Volume reduced by 50% — maintain fitness without overload"},{"name":"Performance check","detail":"Cooper test + Tabata test + body measurements — overall assessment"}]}],"faq":[{"q":"Is HIIT effective for losing weight?","a":"Yes — the combination of high caloric expenditure + EPOC afterburn makes it one of the best tools for losing body fat, especially abdominal fat."},{"q":"Can you do HIIT every day?","a":"No — the body needs 48h to recover from a true HIIT session. 3–4 sessions/week with active rest days is the recommended maximum."},{"q":"Is HIIT suitable for beginners?","a":"Yes, as long as you start with gentle protocols (30 s/30 s) and low-impact exercises (no jumping). Our beginner program is progressive over 4 weeks."},{"q":"How many calories does a HIIT session burn?","a":"Between 300 and 600 kcal for 20–30 min depending on weight and intensity — more than 45 min of running thanks to EPOC."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('hiit', 'de', '{"title":"HIIT","tag":"Fettverbrennung","description":"Kurze, intensive Einheiten, um maximal Kalorien zu verbrennen und deinen Stoffwechsel dauerhaft in 20 bis 30 Min anzukurbeln.","stats":["+2.100 Mitglieder","60+ Circuits","20–30 Min / Einheit"],"levels":["Anfänger","Fortgeschritten","Erfahren"]}'::jsonb, '{"tagline":"Verbrenne 500 kcal in 25 Minuten. Wissenschaftlich belegt.","heroStat":"2.100+ aktive Mitglieder","guide":{"technique":{"emoji":"⚡","title":"HIIT-Prinzipien","items":["Belastungs-/Pausenverhältnis: 1:1 für Anfänger (20 s Arbeit / 20 s Pause), 2:1 für Fortgeschrittene","Zielintensität: 85–95% HFmax während der Arbeitsphasen — sonst ist es kein HIIT","Priorisiere Grundübungen: Burpees, Squat Jumps, Mountain Climbers, Sprints","Empfohlene Gesamtdauer: 15–25 Min — längere Einheiten sind nicht effektiver","EPOC (Nachbrenneffekt) verbrennt 24–48 h nach einer guten HIIT-Einheit weiter Kalorien"]},"equipment":{"emoji":"🏃","title":"Benötigte Ausrüstung","items":["Null Ausrüstung nötig — HIIT mit dem eigenen Körpergewicht ist so effektiv wie das Studio","Studio-Option: Rudergerät, Assault Bike, TRX, um die Reize zu variieren","Ein Herzfrequenzmesser, um sicherzustellen, dass du in der richtigen Intensitätszone bleibst","Eine Bodenmatte für Bodenübungen (Burpees, Mountain Climbers)","Eine Timer-App (Interval Timer) — Xenotif® enthält voreingestellte HIIT-Timer"]},"nutrition":{"emoji":"🍌","title":"HIIT-Ernährung","items":["Leichter Snack 30–60 Min vorher: Banane, Toast mit Mandelmus","Vermeide schwere Mahlzeiten in den 2 h vor einer Einheit — Übelkeitsrisiko","Hydration ist entscheidend: 500 ml Wasser vorher, während trinken, wenn die Einheit > 20 Min dauert","Nach dem HIIT: Kombi aus Kohlenhydraten + Protein innerhalb von 30 Min (Whey-Shake + Obst)","Koffein (schwarzer Kaffee, Pre-Workout) verbessert die HIIT-Leistung um 10–15%"]},"recovery":{"emoji":"🧘","title":"Erholung zwischen den Einheiten","items":["Maximal 3–4 HIIT-Einheiten / Woche — wechsle mit lockeren Tagen ab","Cool-down 5–10 Min Gehen + dynamisches Dehnen nach der Einheit","Tägliches HIIT führt in 2–3 Wochen zu Übertraining — respektiere deine freien Tage","Schlafqualität ist essenziell: spätes HIIT (< 3 h vor dem Bett) stört den Schlaf","Kaltes Bad 10 Min oder kalte Dusche direkt nach der Einheit — reduziert Entzündungen"]}},"tips":[{"icon":"🔥","title":"Der EPOC-Effekt","body":"Eine 20-Min-HIIT-Einheit verbrennt so viele Kalorien wie ein 45-Min-Lauf — und verbrennt dank des EPOC-Nachbrenneffekts 24 h später weiter."},{"icon":"📈","title":"Progression ist Pflicht","body":"Starte mit 30 s/30 s × 8 Runden. Erhöhe die Runden, bevor du die Intensität erhöhst. Zu schnell = Verletzung oder Burnout."},{"icon":"🎵","title":"Musik pusht dich um 15%","body":"Eine rhythmische Playlist bei 140–160 BPM verbessert die HIIT-Leistung deutlich. Lade deine Playlist vor jeder Einheit."},{"icon":"🧪","title":"Variiere die Protokolle","body":"Tabata (20/10), EMOM, Pyramide, AMRAPs — der Wechsel der Formate verhindert Gewöhnung und durchbricht Plateaus."}],"exercises":[{"name":"Burpees","muscles":"Ganzkörper, Cardio","sets":"3×15","difficulty":"Fortgeschritten","description":"Aus dem Stand in die Hocke, Hände aufsetzen, Beine nach hinten in die Liegestützposition, ein Liegestütz, Füße zurück, springen. Die ultimative HIIT-Übung."},{"name":"Mountain Climbers","muscles":"Bauch, Hüftbeuger, Cardio","sets":"3×30 s","difficulty":"Anfänger","description":"Hohe Plank-Position, treibe die Knie abwechselnd mit maximaler Geschwindigkeit zur Brust. Halte die Hüfte stabil und tief."},{"name":"Squat Jumps","muscles":"Quadrizeps, Gesäß, explosives Cardio","sets":"3×15","difficulty":"Fortgeschritten","description":"Kniebeuge auf 90°, dann explosiv nach oben springen, Arme treiben hoch. Lande weich mit gebeugten Knien. Baut Kraft und Cardio gleichzeitig auf."},{"name":"Knieheben (High Knees)","muscles":"Hüftbeuger, Cardio","sets":"3×30 s","difficulty":"Anfänger","description":"Laufe auf der Stelle und treibe die Knie auf Hüfthöhe. Arme im Rhythmus bei 90°. Ein tolles HIIT-Aufwärmen oder Cardio-Intensivierer."},{"name":"Ice Skaters","muscles":"Gesäß, Abduktoren, Cardio-Koordination","sets":"3×20/Seite","difficulty":"Fortgeschritten","description":"Springe seitlich von einem Fuß auf den anderen wie ein Eisläufer. Berühre mit der Hand gegenüber dem Standfuß den Boden. Trainiert Seitwärtsbewegung und Cardio."},{"name":"Klatsch-Liegestütze","muscles":"Brust, Trizeps, Explosivität","sets":"3×10","difficulty":"Erfahren","description":"Explosiver Liegestütz mit Händeklatschen in der Luft vor der Landung. Erfordert eine solide Basis regulärer Liegestütze. Baut Oberkörperkraft auf."},{"name":"Box Jumps","muscles":"Quadrizeps, Waden, explosives Cardio","sets":"4×10","difficulty":"Fortgeschritten","description":"Springe auf eine Box, fange in einer halben Kniebeuge ab. Steig außen herunter. Progressive Höhe: 40, 50, 60, 70 cm je nach Niveau."},{"name":"Dynamische Plank","muscles":"Bauch, Schultern, Rumpf","sets":"3×30 s","difficulty":"Fortgeschritten","description":"Aus der hohen Plank abwechselnd auf die Unterarme ab und wieder hoch. Halte die Hüfte stabil und vermeide das Rotieren des Beckens."},{"name":"30-m-Sprint","muscles":"Max Cardio, Quadrizeps, Waden","sets":"10×30 m","difficulty":"Erfahren","description":"Sprinte mit 100% Höchstgeschwindigkeit über 30 Meter. Volle Erholung (90 s) zwischen jedem. Baut anaerobe Leistung und Spitzengeschwindigkeit auf."}],"program":[{"week":"Woche 1–2","theme":"Einführung — Intensität entdecken","sessions":[{"name":"Tabata-Intro 4×4 Min","detail":"Kniebeuge, Mountain Climber, Jumping Jack, Plank — 20 s aktiv / 10 s Pause"},{"name":"AMRAP-Circuit 15 Min","detail":"5 Burpees + 10 Squat Jumps + 15 Mountain Climbers — so viele Runden wie möglich"},{"name":"Aktive Erholung","detail":"Zügiges Gehen 30 Min + Mobilitäts-Yoga 15 Min"}]},{"week":"Woche 3–4","theme":"Progression — Intensität 85% HFmax","sessions":[{"name":"EMOM 20 Min","detail":"Jede Minute: 10 Burpees + 15 Squat Jumps — fertig sein, bevor die Minute um ist"},{"name":"Pyramiden-HIIT","detail":"30/30 → 40/20 → 50/10 → 40/20 → 30/30 — 3 volle Zyklen"},{"name":"Sprint-Pyramide","detail":"10-20-30-40-30-20-10 m Sprints mit voller Erholung dazwischen"}]},{"week":"Woche 5–6","theme":"Leistung — Grenzen verschieben","sessions":[{"name":"Death by Burpees","detail":"Minute 1: 1 Burpee. Minute 2: 2 Burpees. Weiter, bis du das Tempo nicht halten kannst"},{"name":"Partner-WOD","detail":"3 Runden: 50 Squat Jumps + 40 Liegestütze + 30 Sit-ups + 20 Burpees — zu zweit"},{"name":"HIIT-VO2max-Test","detail":"Yo-Yo-Level-1-Protokoll — Cardio-Bewertung zur Feinjustierung deiner Arbeitszonen"}]},{"week":"Woche 7–8","theme":"Erhalt & Festigung","sessions":[{"name":"„Best of“-Circuit","detail":"Deine 3 Lieblingsübungen der vorherigen Wochen — 5 Runden bei max. Intensität"},{"name":"Woche der aktiven Erholung","detail":"Volumen um 50% reduziert — Fitness halten ohne Überlastung"},{"name":"Leistungs-Check","detail":"Cooper-Test + Tabata-Test + Körpermaße — Gesamtbewertung"}]}],"faq":[{"q":"Ist HIIT effektiv zum Abnehmen?","a":"Ja — die Kombination aus hohem Kalorienverbrauch + EPOC-Nachbrenneffekt macht es zu einem der besten Werkzeuge zum Abbau von Körperfett, besonders Bauchfett."},{"q":"Kann man jeden Tag HIIT machen?","a":"Nein — der Körper braucht 48 h, um sich von einer echten HIIT-Einheit zu erholen. 3–4 Einheiten/Woche mit aktiven Ruhetagen sind das empfohlene Maximum."},{"q":"Ist HIIT für Anfänger geeignet?","a":"Ja, solange du mit sanften Protokollen (30 s/30 s) und gelenkschonenden Übungen (ohne Springen) startest. Unser Anfängerprogramm ist über 4 Wochen progressiv."},{"q":"Wie viele Kalorien verbrennt eine HIIT-Einheit?","a":"Zwischen 300 und 600 kcal für 20–30 Min, je nach Gewicht und Intensität — dank EPOC mehr als 45 Min Laufen."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('hiit', 0, array['5C8Ew76sxVY']::text[], 'pro', '{"fr":{"title":"HIIT 20 min — Brûle-graisse total","description":"Séance HIIT débutant sans équipement — brûle des graisses, construit l''endurance, améliore la condition physique.","duration":"20 min","level":"Débutant"},"en":{"title":"20-min HIIT — Total fat burner","description":"A beginner HIIT session with no equipment — burn fat, build endurance, improve fitness.","duration":"20 min","level":"Beginner"},"de":{"title":"20-Min-HIIT — Totaler Fettverbrenner","description":"Eine HIIT-Einheit für Anfänger ohne Ausrüstung — verbrenne Fett, baue Ausdauer auf, verbessere die Fitness.","duration":"20 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('hiit', 1, array['J8EeluUr4ak']::text[], 'pro', '{"fr":{"title":"HIIT sans impact — Full body","description":"HIIT basse intensité 20 min, sans sauts — idéal pour débuter ou protéger les articulations.","duration":"20 min","level":"Débutant"},"en":{"title":"Low-impact HIIT — Full body","description":"A 20-min low-intensity HIIT, no jumping — ideal to get started or protect your joints.","duration":"20 min","level":"Beginner"},"de":{"title":"Low-Impact-HIIT — Ganzkörper","description":"Ein 20-Min-HIIT mit niedriger Intensität, ohne Springen — ideal zum Start oder um deine Gelenke zu schonen.","duration":"20 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('hiit', 2, array['fIuACtB2ZZs']::text[], 'pro', '{"fr":{"title":"20 min HIIT — Zéro équipement","description":"Entraînement HIIT complet pour débutants — poids du corps, full body, résultats rapides.","duration":"20 min","level":"Intermédiaire"},"en":{"title":"20-min HIIT — No equipment","description":"A complete HIIT workout for beginners — bodyweight, full body, fast results.","duration":"20 min","level":"Intermediate"},"de":{"title":"20-Min-HIIT — Ohne Ausrüstung","description":"Ein komplettes HIIT-Workout für Anfänger — Körpergewicht, Ganzkörper, schnelle Ergebnisse.","duration":"20 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('hiit', 3, array['V4MqB6q3w44']::text[], 'pro', '{"fr":{"title":"Tabata 24 min — Niveau avancé","description":"Séance Tabata intense pour sportifs confirmés — 24 minutes de travail à haute intensité.","duration":"24 min","level":"Avancé"},"en":{"title":"Tabata 24 min — Advanced level","description":"An intense Tabata session for seasoned athletes — 24 minutes of high-intensity work.","duration":"24 min","level":"Advanced"},"de":{"title":"Tabata 24 Min — Erfahren-Niveau","description":"Eine intensive Tabata-Einheit für erfahrene Athleten — 24 Minuten hochintensive Arbeit.","duration":"24 Min","level":"Erfahren"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('hiit', 4, array['1u5eO7AvPjk']::text[], 'pro', '{"fr":{"title":"Tabata Full Body 24 min","description":"Circuit Tabata complet : full body, 24 minutes, sans équipement — brûle calories et booste le cardio.","duration":"24 min","level":"Intermédiaire"},"en":{"title":"Full Body Tabata 24 min","description":"A complete Tabata circuit: full body, 24 minutes, no equipment — burns calories and boosts cardio.","duration":"24 min","level":"Intermediate"},"de":{"title":"Ganzkörper-Tabata 24 Min","description":"Ein kompletter Tabata-Circuit: Ganzkörper, 24 Minuten, ohne Ausrüstung — verbrennt Kalorien und pusht das Cardio.","duration":"24 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('hiit', 5, array['aoKrGARP634']::text[], 'pro', '{"fr":{"title":"Tabata + Force 42 min","description":"Combinaison Tabata et musculation en 42 minutes — le meilleur des deux mondes pour la condition physique.","duration":"42 min","level":"Avancé"},"en":{"title":"Tabata + Strength 42 min","description":"A combination of Tabata and strength training in 42 minutes — the best of both worlds for fitness.","duration":"42 min","level":"Advanced"},"de":{"title":"Tabata + Kraft 42 Min","description":"Eine Kombination aus Tabata und Krafttraining in 42 Minuten — das Beste aus beiden Welten für die Fitness.","duration":"42 Min","level":"Erfahren"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_disciplines (slug, sort_order, color, icon, min_plan) values ('cyclisme', 3, 'blue', 'bike', 'pro') on conflict (slug) do update set sort_order=excluded.sort_order, color=excluded.color, icon=excluded.icon, min_plan=excluded.min_plan, updated_at=now();
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('cyclisme', 'fr', '{"title":"Cyclisme","tag":"Endurance","description":"Entraînements indoor et outdoor avec puissance-mètre. De la sportive au grimpeur de cols, un plan adapté à chaque profil.","stats":["+1 500 cyclistes","45+ plans","16 semaines moy."],"levels":["Débutant","Intermédiaire","Avancé","Compétition"]}'::jsonb, '{"tagline":"De la sportive au grimpeur de cols — un plan pour chaque roue.","heroStat":"1 500+ cyclistes actifs","guide":{"technique":{"emoji":"🚴","title":"Technique de pédalage","items":["Cadence optimale : 85–95 RPM pour les routes plates, 70–80 RPM en montée","Position sur le vélo : vérification tri-annuelle de la mise en selle (professionnelle)","Pousser ET tirer — pensez à \"gratter\" au bas du coup de pédale pour maximiser la puissance","Position aéro : descente de buste progressif — chaque 5 cm économise 20–30 W de résistance","Changement de vitesses anticipé avant la côte — jamais en poussant fort dans le braquet"]},"equipment":{"emoji":"⚙️","title":"Équipement performance","items":["Capteur de puissance — l''outil le plus précis pour quantifier l''entraînement (à partir de 400 €)","Cardiofréquencemètre (sangle thoracique plus précise que le poignet)","Casque aéro homologué + lunettes de protection anti-UV","Chaussures SPD-SL avec cales alignées — évite les douleurs aux genoux","Hometrainer connecté (Tacx, Wahoo) pour l''entraînement intérieur en hiver"]},"nutrition":{"emoji":"🍝","title":"Nutrition longue distance","items":["Loading glucidique J-2 et J-1 avant une compétition : pâtes, riz, pain","Sur vélo : 60–90 g de glucides/heure sur les efforts > 90 min (gel + boisson + barres)","Boisson isotonique maison : 500 ml eau + 30 g maltodextrine + 1 g sel + jus citron","Bouteilles de 750 ml minimum — déshydratation de 2 % réduit la puissance de 10 %","Récupération : riz + poulet ou pasta + thon dans les 30 min post-effort long"]},"recovery":{"emoji":"🔧","title":"Récupération et entretien","items":["Pédalage léger 20–30 min le lendemain d''un effort intense — circulation active","Massage des jambes : focus sur les quadriceps, ischio-jambiers, mollets et fessiers","Élévation des jambes 15 min post-sortie longue pour réduire les oedèmes","Nutrition récupération cycliste : ratio 4:1 glucides/protéines dans la première heure","Entretien du vélo après chaque sortie pluvieuse : chaîne, freins, jantes"]}},"tips":[{"icon":"📡","title":"Entraîne-toi par zones","body":"Zone 2 (65–75 % FTP) pour 80 % du volume — la zone que les pros appellent \"le chemin vers la performance\". Sous-estimée par 95 % des amateurs."},{"icon":"🧱","title":"FTP est ta boussole","body":"Teste ton FTP (seuil fonctionnel de puissance) toutes les 4–6 semaines avec un test 20 min à bloc. Toutes tes zones en découlent."},{"icon":"🌬️","title":"L''aérodynamisme prime","body":"Sur un plat à 35 km/h, 80 % de la résistance est aérodynamique. Descends le buste avant d''acheter une roue carbone."},{"icon":"🏔️","title":"La montagne se roule en watts","body":"En côte, vise un ratio W/kg constant — évite les à-coups qui vident les réserves. Un effort régulier est toujours plus économique."}],"exercises":[{"name":"Pédalage unijambiste","muscles":"Quadriceps, fessiers, technique pédalage","sets":"3×2 min/jambe","difficulty":"Tous niveaux","description":"Pédale avec une seule jambe pendant 2 minutes, l''autre repose sur le cadre. Révèle les points faibles du coup de pédale et corrige les asymétries de puissance."},{"name":"Sprints sur vélo 30 s","muscles":"Puissance anaérobie, quadriceps, mollets","sets":"8×30 s","difficulty":"Intermédiaire","description":"Sprint maximum pendant 30 secondes, récupération 4 min en pédalage léger. Développe la puissance de pointe et la capacité à accélérer dans les finales."},{"name":"Sweet spot 2×20 min","muscles":"Endurance seuil, cardio-respiratoire","sets":"2×20 min","difficulty":"Intermédiaire","description":"Pédale à 88–95 % de ton FTP pendant 20 minutes avec 5 min de repos entre. Le meilleur rapport bénéfice/fatigue pour progresser en cyclisme."},{"name":"Cadence drills 100+ RPM","muscles":"Technique, efficacité musculaire","sets":"5×3 min","difficulty":"Débutant","description":"Pédale à cadence élevée (100+ RPM) en braquet léger pendant 3 min. Améliore la fluidité du coup de pédale et réduit la charge sur les genoux."},{"name":"Squat bulgare (cross-training)","muscles":"Quadriceps, fessiers, stabilité","sets":"3×10/jambe","difficulty":"Intermédiaire","description":"Pied arrière posé sur un banc, descends en fente profonde. Renforce les jambes de façon asymétrique, corrige les déséquilibres droite/gauche courants en cyclisme."},{"name":"Gainage planche","muscles":"Core, stabilité lombaire","sets":"3×45 s","difficulty":"Débutant","description":"Appui sur les avant-bras et les pointes des pieds, corps en ligne droite. Un core fort permet de transmettre la puissance des jambes efficacement sur le vélo."},{"name":"Étirements fléchisseurs de hanche","muscles":"Psoas, fléchisseurs de hanche","sets":"3×60 s/côté","difficulty":"Tous niveaux","description":"En fente basse, maintiens la position en allongeant le psoas. Les fléchisseurs raccourcis en cyclisme réduisent la puissance et augmentent le risque de lombalgie."},{"name":"Climbing intervals 5 min","muscles":"Puissance/poids, cardio seuil","sets":"5×5 min","difficulty":"Avancé","description":"En montée réelle ou simulée (pente > 5 %), maintiens une cadence de 70–75 RPM à 95–100 % FTP. Développe le rapport puissance/poids indispensable pour grimper."}],"program":[{"week":"Semaine 1–2","theme":"Base aérobie","sessions":[{"name":"Endurance Z2 90 min","detail":"Cadence 90 RPM, FC 65–75 % FCmax — ne pas dépasser la zone"},{"name":"Intervals VO2max 4×8 min","detail":"À 106–120 % FTP, récup 4 min entre chaque — développement VO2max"},{"name":"Récupération active 60 min","detail":"Pédalage très léger Z1 pour activer la circulation sans fatiguer"}]},{"week":"Semaine 3–4","theme":"Seuil & Sweet spot","sessions":[{"name":"Sweet spot 2×20 min","detail":"À 88–95 % FTP avec 5 min repos — le ratio bénéfice/fatigue optimal"},{"name":"Cadence drills","detail":"Alternance 100+ RPM / 60 RPM toutes les 3 min sur 60 min total"},{"name":"Gran fondo simulé 3h","detail":"Long ride avec 40 min en sweet spot intégré — endurance spécifique compétition"}]},{"week":"Semaine 5–6","theme":"Intensification haute","sessions":[{"name":"VO2max 5×5 min","detail":"110–120 % FTP, récup 5 min — augmentation du plafond aérobie"},{"name":"Sprints neuromusculaires 10×10 s","detail":"Puissance maximale, récup 5 min complètes — développement puissance de sprint"},{"name":"Test FTP 20 min","detail":"Effort maximal soutenu 20 min — recalibration de toutes les zones"}]},{"week":"Semaine 7–8","theme":"Affûtage & Performance","sessions":[{"name":"Volume −30 %, intensité maintenue","detail":"Réduction du volume mais pas de l''intensité — supracompensation"},{"name":"Race-pace intervals 3×10 min","detail":"Simulation vitesse course — mental et physique prêts"},{"name":"Sortie décontraction 2h","detail":"Paysage, plaisir, jambes libres — arriver frais au jour J"}]}],"faq":[{"q":"Indoor ou outdoor — lequel est plus efficace ?","a":"L''indoor (hometrainer) est plus efficace par heure d''entraînement car il n''y a pas de temps mort (feux, descentes). L''outdoor est meilleur pour la technique et la motivation. Combiner les deux est idéal."},{"q":"Quelle puissance pour débuter le cyclisme compétition ?","a":"Un W/kg de 2,5–3 est suffisant pour débuter les cyclosportives. Avec 6 mois d''entraînement structuré, atteindre 3–3,5 W/kg est accessible."},{"q":"Combien d''heures par semaine pour progresser ?","a":"Minimum 8h/semaine pour une progression significative. Les pros font 20–25h. Entre les deux, 12–15h est le sweet spot amateur compétitif."},{"q":"Faut-il un hometrainer en hiver ?","a":"Très recommandé — l''hiver est la période idéale pour construire la base aérobie (Z2) sans les dangers de la route. Zwift ou RGT rendent l''indoor motivant."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('cyclisme', 'en', '{"title":"Cycling","tag":"Endurance","description":"Indoor and outdoor training with a power meter. From road racer to climber, a plan tailored to every profile.","stats":["+1,500 cyclists","45+ plans","16 weeks avg."],"levels":["Beginner","Intermediate","Advanced","Competition"]}'::jsonb, '{"tagline":"From road racer to mountain climber — a plan for every wheel.","heroStat":"1,500+ active cyclists","guide":{"technique":{"emoji":"🚴","title":"Pedaling technique","items":["Optimal cadence: 85–95 RPM on the flats, 70–80 RPM uphill","Bike position: have your fit checked by a professional every few years","Push AND pull — think of \"scraping\" at the bottom of the pedal stroke to maximize power","Aero position: lower the torso gradually — every 5 cm saves 20–30 W of drag","Shift gears before the hill — never while pushing hard in the gear"]},"equipment":{"emoji":"⚙️","title":"Performance equipment","items":["A power meter — the most accurate tool to quantify training (from €400)","A heart-rate monitor (chest strap more accurate than the wrist)","A certified aero helmet + UV-protection glasses","SPD-SL shoes with aligned cleats — avoids knee pain","A connected indoor trainer (Tacx, Wahoo) for winter indoor training"]},"nutrition":{"emoji":"🍝","title":"Long-distance nutrition","items":["Carb loading D-2 and D-1 before a race: pasta, rice, bread","On the bike: 60–90 g of carbs/hour on efforts > 90 min (gel + drink + bars)","Homemade isotonic drink: 500 ml water + 30 g maltodextrin + 1 g salt + lemon juice","Bottles of 750 ml minimum — 2% dehydration cuts power by 10%","Recovery: rice + chicken or pasta + tuna within 30 min after a long effort"]},"recovery":{"emoji":"🔧","title":"Recovery and maintenance","items":["Easy spin 20–30 min the day after an intense effort — active circulation","Leg massage: focus on the quads, hamstrings, calves and glutes","Elevate the legs 15 min after a long ride to reduce swelling","Cyclist recovery nutrition: 4:1 carb/protein ratio in the first hour","Service the bike after every rainy ride: chain, brakes, rims"]}},"tips":[{"icon":"📡","title":"Train by zones","body":"Zone 2 (65–75% FTP) for 80% of the volume — the zone pros call \"the path to performance.\" Underrated by 95% of amateurs."},{"icon":"🧱","title":"FTP is your compass","body":"Test your FTP (functional threshold power) every 4–6 weeks with an all-out 20-min test. All your zones flow from it."},{"icon":"🌬️","title":"Aerodynamics rule","body":"On the flat at 35 km/h, 80% of the resistance is aerodynamic. Lower your torso before buying a carbon wheel."},{"icon":"🏔️","title":"Climb in watts","body":"On a climb, aim for a constant W/kg ratio — avoid surges that drain your reserves. A steady effort is always more economical."}],"exercises":[{"name":"Single-leg pedaling","muscles":"Quads, glutes, pedaling technique","sets":"3×2 min/leg","difficulty":"All levels","description":"Pedal with one leg only for 2 minutes, the other resting on the frame. Reveals weak points in the pedal stroke and corrects power asymmetries."},{"name":"30 s bike sprints","muscles":"Anaerobic power, quads, calves","sets":"8×30 s","difficulty":"Intermediate","description":"Maximal sprint for 30 seconds, 4 min easy-spin recovery. Builds top-end power and the ability to accelerate in the finale."},{"name":"Sweet spot 2×20 min","muscles":"Threshold endurance, cardio-respiratory","sets":"2×20 min","difficulty":"Intermediate","description":"Pedal at 88–95% of your FTP for 20 minutes with 5 min rest between. The best benefit/fatigue ratio for cycling progress."},{"name":"Cadence drills 100+ RPM","muscles":"Technique, muscular efficiency","sets":"5×3 min","difficulty":"Beginner","description":"Pedal at high cadence (100+ RPM) in a light gear for 3 min. Improves pedal-stroke smoothness and reduces knee load."},{"name":"Bulgarian squat (cross-training)","muscles":"Quads, glutes, stability","sets":"3×10/leg","difficulty":"Intermediate","description":"Back foot on a bench, descend into a deep lunge. Strengthens the legs asymmetrically and corrects the left/right imbalances common in cycling."},{"name":"Plank core","muscles":"Core, lumbar stability","sets":"3×45 s","difficulty":"Beginner","description":"Support on the forearms and toes, body in a straight line. A strong core lets you transfer leg power efficiently on the bike."},{"name":"Hip-flexor stretch","muscles":"Psoas, hip flexors","sets":"3×60 s/side","difficulty":"All levels","description":"In a low lunge, hold the position while lengthening the psoas. Shortened hip flexors from cycling reduce power and increase low-back pain risk."},{"name":"Climbing intervals 5 min","muscles":"Power-to-weight, threshold cardio","sets":"5×5 min","difficulty":"Advanced","description":"On a real or simulated climb (gradient > 5%), hold a cadence of 70–75 RPM at 95–100% FTP. Builds the power-to-weight ratio essential for climbing."}],"program":[{"week":"Week 1–2","theme":"Aerobic base","sessions":[{"name":"Z2 endurance 90 min","detail":"90 RPM cadence, HR 65–75% HRmax — don''t exceed the zone"},{"name":"VO2max intervals 4×8 min","detail":"At 106–120% FTP, 4 min recovery between each — VO2max development"},{"name":"Active recovery 60 min","detail":"Very easy Z1 spin to boost circulation without fatigue"}]},{"week":"Week 3–4","theme":"Threshold & Sweet spot","sessions":[{"name":"Sweet spot 2×20 min","detail":"At 88–95% FTP with 5 min rest — the optimal benefit/fatigue ratio"},{"name":"Cadence drills","detail":"Alternate 100+ RPM / 60 RPM every 3 min over 60 min total"},{"name":"Simulated gran fondo 3h","detail":"Long ride with 40 min of sweet spot built in — race-specific endurance"}]},{"week":"Week 5–6","theme":"High intensification","sessions":[{"name":"VO2max 5×5 min","detail":"110–120% FTP, 5 min recovery — raises the aerobic ceiling"},{"name":"Neuromuscular sprints 10×10 s","detail":"Maximal power, full 5 min recovery — sprint-power development"},{"name":"FTP test 20 min","detail":"Maximal sustained 20-min effort — recalibration of all zones"}]},{"week":"Week 7–8","theme":"Tapering & Performance","sessions":[{"name":"Volume −30%, intensity kept","detail":"Reduce volume but not intensity — supercompensation"},{"name":"Race-pace intervals 3×10 min","detail":"Race-speed simulation — mentally and physically ready"},{"name":"Easy ride 2h","detail":"Scenery, fun, free legs — arrive fresh on race day"}]}],"faq":[{"q":"Indoor or outdoor — which is more effective?","a":"Indoor (trainer) is more effective per training hour because there''s no dead time (lights, descents). Outdoor is better for technique and motivation. Combining both is ideal."},{"q":"What power do I need to start racing?","a":"A W/kg of 2.5–3 is enough to start sportives. With 6 months of structured training, reaching 3–3.5 W/kg is achievable."},{"q":"How many hours per week to progress?","a":"A minimum of 8h/week for meaningful progress. Pros do 20–25h. In between, 12–15h is the competitive-amateur sweet spot."},{"q":"Do I need an indoor trainer in winter?","a":"Highly recommended — winter is the ideal time to build the aerobic base (Z2) without the dangers of the road. Zwift or RGT make indoor riding motivating."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('cyclisme', 'de', '{"title":"Radfahren","tag":"Ausdauer","description":"Indoor- und Outdoor-Training mit Wattmesser. Vom Rennfahrer bis zum Bergkletterer — ein Plan für jedes Profil.","stats":["+1.500 Radfahrer","45+ Pläne","Ø 16 Wochen"],"levels":["Anfänger","Fortgeschritten","Erfahren","Wettkampf"]}'::jsonb, '{"tagline":"Vom Rennfahrer bis zum Bergkletterer — ein Plan für jedes Rad.","heroStat":"1.500+ aktive Radfahrer","guide":{"technique":{"emoji":"🚴","title":"Tritttechnik","items":["Optimale Trittfrequenz: 85–95 RPM in der Ebene, 70–80 RPM bergauf","Sitzposition: lass dein Bike-Fitting alle paar Jahre von einem Profi prüfen","Drücken UND ziehen — denke ans „Auskratzen“ am unteren Totpunkt, um die Leistung zu maximieren","Aero-Position: senke den Oberkörper schrittweise — jede 5 cm sparen 20–30 W Luftwiderstand","Schalte vor dem Anstieg — nie, während du im Gang stark drückst"]},"equipment":{"emoji":"⚙️","title":"Leistungsausrüstung","items":["Ein Wattmesser — das präziseste Werkzeug zur Quantifizierung des Trainings (ab 400 €)","Ein Herzfrequenzmesser (Brustgurt genauer als am Handgelenk)","Ein zertifizierter Aero-Helm + Brille mit UV-Schutz","SPD-SL-Schuhe mit ausgerichteten Cleats — verhindert Knieschmerzen","Ein vernetzter Indoor-Trainer (Tacx, Wahoo) für das Wintertraining drinnen"]},"nutrition":{"emoji":"🍝","title":"Langstrecken-Ernährung","items":["Carb-Loading 2 und 1 Tag vor einem Wettkampf: Pasta, Reis, Brot","Auf dem Rad: 60–90 g Kohlenhydrate/Stunde bei Belastungen > 90 Min (Gel + Getränk + Riegel)","Hausgemachtes Isogetränk: 500 ml Wasser + 30 g Maltodextrin + 1 g Salz + Zitronensaft","Flaschen mit mindestens 750 ml — 2% Dehydrierung senken die Leistung um 10%","Erholung: Reis + Hühnchen oder Pasta + Thunfisch innerhalb von 30 Min nach langer Anstrengung"]},"recovery":{"emoji":"🔧","title":"Erholung und Wartung","items":["Lockeres Ausfahren 20–30 Min am Tag nach intensiver Belastung — aktive Durchblutung","Beinmassage: konzentriere dich auf Quadrizeps, Beinbeuger, Waden und Gesäß","Lege die Beine 15 Min nach einer langen Fahrt hoch, um Schwellungen zu reduzieren","Radfahrer-Erholungsernährung: 4:1 Kohlenhydrat/Protein-Verhältnis in der ersten Stunde","Warte das Rad nach jeder Regenfahrt: Kette, Bremsen, Felgen"]}},"tips":[{"icon":"📡","title":"Trainiere in Zonen","body":"Zone 2 (65–75% FTP) für 80% des Volumens — die Zone, die Profis „den Weg zur Leistung“ nennen. Von 95% der Amateure unterschätzt."},{"icon":"🧱","title":"FTP ist dein Kompass","body":"Teste deine FTP (funktionelle Schwellenleistung) alle 4–6 Wochen mit einem 20-Min-All-out-Test. Alle deine Zonen leiten sich daraus ab."},{"icon":"🌬️","title":"Aerodynamik regiert","body":"In der Ebene bei 35 km/h sind 80% des Widerstands aerodynamisch. Senke deinen Oberkörper, bevor du eine Carbon-Felge kaufst."},{"icon":"🏔️","title":"Klettere in Watt","body":"Am Anstieg ziele auf ein konstantes W/kg-Verhältnis — vermeide Antritte, die deine Reserven leeren. Eine gleichmäßige Anstrengung ist immer ökonomischer."}],"exercises":[{"name":"Einbeiniges Treten","muscles":"Quadrizeps, Gesäß, Tritttechnik","sets":"3×2 Min/Bein","difficulty":"Alle Niveaus","description":"Tritt 2 Minuten nur mit einem Bein, das andere ruht am Rahmen. Deckt Schwachstellen im Tretzyklus auf und korrigiert Leistungsasymmetrien."},{"name":"30-s-Bike-Sprints","muscles":"Anaerobe Leistung, Quadrizeps, Waden","sets":"8×30 s","difficulty":"Fortgeschritten","description":"Maximaler Sprint für 30 Sekunden, 4 Min lockeres Ausrollen zur Erholung. Baut Spitzenleistung und die Fähigkeit auf, im Finale zu beschleunigen."},{"name":"Sweet Spot 2×20 Min","muscles":"Schwellenausdauer, Herz-Kreislauf","sets":"2×20 Min","difficulty":"Fortgeschritten","description":"Tritt 20 Minuten bei 88–95% deiner FTP mit 5 Min Pause dazwischen. Das beste Nutzen/Ermüdungs-Verhältnis für den Radfortschritt."},{"name":"Kadenz-Drills 100+ RPM","muscles":"Technik, muskuläre Effizienz","sets":"5×3 Min","difficulty":"Anfänger","description":"Tritt mit hoher Kadenz (100+ RPM) in einem leichten Gang 3 Min lang. Verbessert die Rundheit des Tretzyklus und reduziert die Kniebelastung."},{"name":"Bulgarische Kniebeuge (Cross-Training)","muscles":"Quadrizeps, Gesäß, Stabilität","sets":"3×10/Bein","difficulty":"Fortgeschritten","description":"Hinterer Fuß auf einer Bank, senke in einen tiefen Ausfallschritt. Stärkt die Beine asymmetrisch und korrigiert die im Radsport häufigen Links/Rechts-Ungleichgewichte."},{"name":"Plank Rumpf","muscles":"Rumpf, Lendenstabilität","sets":"3×45 s","difficulty":"Anfänger","description":"Stütze auf Unterarmen und Zehen, Körper in gerader Linie. Ein starker Rumpf lässt dich die Beinkraft effizient aufs Rad übertragen."},{"name":"Hüftbeuger-Dehnung","muscles":"Psoas, Hüftbeuger","sets":"3×60 s/Seite","difficulty":"Alle Niveaus","description":"In einem tiefen Ausfallschritt halte die Position und längere den Psoas. Durch Radfahren verkürzte Hüftbeuger reduzieren die Leistung und erhöhen das Risiko von Rückenschmerzen."},{"name":"Berg-Intervalle 5 Min","muscles":"Leistung-zu-Gewicht, Schwellen-Cardio","sets":"5×5 Min","difficulty":"Erfahren","description":"An einem echten oder simulierten Anstieg (Steigung > 5%) halte eine Kadenz von 70–75 RPM bei 95–100% FTP. Baut das für das Klettern essenzielle Leistung-zu-Gewicht-Verhältnis auf."}],"program":[{"week":"Woche 1–2","theme":"Aerobe Basis","sessions":[{"name":"Z2-Ausdauer 90 Min","detail":"90 RPM Kadenz, HF 65–75% HFmax — überschreite die Zone nicht"},{"name":"VO2max-Intervalle 4×8 Min","detail":"Bei 106–120% FTP, 4 Min Erholung dazwischen — VO2max-Entwicklung"},{"name":"Aktive Erholung 60 Min","detail":"Sehr lockeres Z1-Ausrollen zur Durchblutung ohne Ermüdung"}]},{"week":"Woche 3–4","theme":"Schwelle & Sweet Spot","sessions":[{"name":"Sweet Spot 2×20 Min","detail":"Bei 88–95% FTP mit 5 Min Pause — das optimale Nutzen/Ermüdungs-Verhältnis"},{"name":"Kadenz-Drills","detail":"Wechsle 100+ RPM / 60 RPM alle 3 Min über 60 Min gesamt"},{"name":"Simulierter Gran Fondo 3 h","detail":"Lange Fahrt mit 40 Min Sweet Spot eingebaut — wettkampfspezifische Ausdauer"}]},{"week":"Woche 5–6","theme":"Hohe Intensivierung","sessions":[{"name":"VO2max 5×5 Min","detail":"110–120% FTP, 5 Min Erholung — hebt die aerobe Decke an"},{"name":"Neuromuskuläre Sprints 10×10 s","detail":"Maximale Leistung, volle 5 Min Erholung — Sprint-Leistungsentwicklung"},{"name":"FTP-Test 20 Min","detail":"Maximale gehaltene 20-Min-Anstrengung — Neukalibrierung aller Zonen"}]},{"week":"Woche 7–8","theme":"Tapering & Leistung","sessions":[{"name":"Volumen −30%, Intensität gehalten","detail":"Reduziere das Volumen, aber nicht die Intensität — Superkompensation"},{"name":"Wettkampftempo-Intervalle 3×10 Min","detail":"Simulation des Renntempos — mental und körperlich bereit"},{"name":"Lockere Fahrt 2 h","detail":"Landschaft, Spaß, freie Beine — frisch am Wettkampftag ankommen"}]}],"faq":[{"q":"Indoor oder Outdoor — was ist effektiver?","a":"Indoor (Trainer) ist pro Trainingsstunde effektiver, weil es keine Totzeiten gibt (Ampeln, Abfahrten). Outdoor ist besser für Technik und Motivation. Beides zu kombinieren ist ideal."},{"q":"Welche Leistung brauche ich, um mit Rennen anzufangen?","a":"Ein W/kg von 2,5–3 reicht, um mit Jedermann-Rennen anzufangen. Mit 6 Monaten strukturiertem Training sind 3–3,5 W/kg erreichbar."},{"q":"Wie viele Stunden pro Woche, um voranzukommen?","a":"Mindestens 8 h/Woche für spürbaren Fortschritt. Profis fahren 20–25 h. Dazwischen sind 12–15 h der Sweet Spot für ambitionierte Amateure."},{"q":"Brauche ich im Winter einen Indoor-Trainer?","a":"Sehr empfehlenswert — der Winter ist die ideale Zeit, um die aerobe Basis (Z2) ohne die Gefahren der Straße aufzubauen. Zwift oder RGT machen das Indoor-Fahren motivierend."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('cyclisme', 0, array['NnFGvxDoutY','oTZh4uyfxQA']::text[], 'pro', '{"fr":{"title":"FTP et zones d''entraînement cyclisme","description":"Les bases du cyclisme structuré — FTP, zones de puissance et comment les utiliser pour progresser.","duration":"18 min","level":"Tous niveaux"},"en":{"title":"FTP and cycling training zones","description":"The basics of structured cycling — FTP, power zones and how to use them to progress.","duration":"18 min","level":"All levels"},"de":{"title":"FTP und Trainingszonen im Radsport","description":"Die Grundlagen des strukturierten Radtrainings — FTP, Leistungszonen und wie du sie zum Fortschritt nutzt.","duration":"18 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('cyclisme', 1, array['TTGkXtfzUxk','IvhYkLSm_pQ']::text[], 'pro', '{"fr":{"title":"Zones 1 à 7 — Setup & guide complet","description":"Configuration et utilisation de tes zones de puissance avec un capteur — guide pratique complet.","duration":"22 min","level":"Intermédiaire"},"en":{"title":"Zones 1 to 7 — Setup & full guide","description":"Setting up and using your power zones with a meter — a complete practical guide.","duration":"22 min","level":"Intermediate"},"de":{"title":"Zonen 1 bis 7 — Einrichtung & kompletter Leitfaden","description":"Einrichten und Nutzen deiner Leistungszonen mit Wattmesser — ein kompletter Praxisleitfaden.","duration":"22 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('cyclisme', 2, array['IKhK5RQ2RXI','D0rZ1ecC8c0']::text[], 'pro', '{"fr":{"title":"Zones d''entraînement — Tout comprendre","description":"Ce que sont les zones, pourquoi les utiliser et comment elles transforment le cyclisme amateur.","duration":"20 min","level":"Avancé"},"en":{"title":"Training zones — Understand it all","description":"What zones are, why to use them and how they transform amateur cycling.","duration":"20 min","level":"Advanced"},"de":{"title":"Trainingszonen — Alles verstehen","description":"Was Zonen sind, warum man sie nutzt und wie sie den Amateur-Radsport verändern.","duration":"20 Min","level":"Erfahren"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('cyclisme', 3, array['5e5qS3t17gg','2BQD-khdL1Y']::text[], 'pro', '{"fr":{"title":"HIIT Indoor Cycling — Zwift workout","description":"Séance HIIT à l''intérieur sur hometrainer — structure d''entraînement par intervalles avec Zwift.","duration":"30 min","level":"Intermédiaire"},"en":{"title":"HIIT Indoor Cycling — Zwift workout","description":"An indoor HIIT session on the trainer — interval training structure with Zwift.","duration":"30 min","level":"Intermediate"},"de":{"title":"HIIT Indoor Cycling — Zwift-Workout","description":"Eine Indoor-HIIT-Einheit auf dem Trainer — Aufbau eines Intervalltrainings mit Zwift.","duration":"30 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('cyclisme', 4, array['_NQE6XbcTcA','tX_b-hkCEAA']::text[], 'pro', '{"fr":{"title":"Débuter le cyclisme indoor","description":"Guide complet pour commencer le vélo d''appartement — matériel, réglages, premières séances structurées.","duration":"16 min","level":"Débutant"},"en":{"title":"Getting started with indoor cycling","description":"A complete guide to starting indoor cycling — gear, setup, first structured sessions.","duration":"16 min","level":"Beginner"},"de":{"title":"Einstieg ins Indoor Cycling","description":"Ein kompletter Leitfaden für den Einstieg ins Indoor Cycling — Ausrüstung, Einrichtung, erste strukturierte Einheiten.","duration":"16 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('cyclisme', 5, array['17HZsFrbZLs','Z5tTDRfbs50']::text[], 'pro', '{"fr":{"title":"Indoor cycling — 30 min intervalles","description":"Séance de 30 minutes avec intervalles progressifs sur vélo d''intérieur — parfait pour progresser rapidement.","duration":"30 min","level":"Intermédiaire"},"en":{"title":"Indoor cycling — 30-min intervals","description":"A 30-minute session with progressive intervals on the indoor bike — perfect to progress quickly.","duration":"30 min","level":"Intermediate"},"de":{"title":"Indoor Cycling — 30-Min-Intervalle","description":"Eine 30-minütige Einheit mit progressiven Intervallen auf dem Indoor-Bike — perfekt für schnellen Fortschritt.","duration":"30 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
