insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('natation', 'fr', '{"title":"Natation","tag":"Aquatique","description":"Techniques de nage, préparation triathlon, open water — progressez dans tous les styles avec des drills vidéo HD.","stats":["+900 nageurs","30+ programmes","10 semaines moy."],"levels":["Débutant","Intermédiaire","Avancé","Triathlon"]}'::jsonb, '{"tagline":"Technique, efficacité, performance — l''eau ne ment pas.","heroStat":"900+ nageurs actifs","guide":{"technique":{"emoji":"🏊","title":"Technique de nage","items":["Position hydrodynamique : tête dans l''axe du corps, regard vers le fond du bassin","Rotation des hanches 45° à chaque mouvement de bras — source principale de puissance","Extension maximale du bras avant l''entrée dans l''eau — \"atteindre le mur du bout des doigts\"","Jambes : battements petits et rapides depuis les hanches, genoux légèrement fléchis","Virage flip-turn : toucher le mur à 1 m, roulade, poussée explosive — économise 2–3 s / 100 m"]},"equipment":{"emoji":"🥽","title":"Équipement de nage","items":["Lunettes de natation anti-buée adaptées à la morphologie du visage","Bonnet en silicone pour réduire la traînée et protéger les cheveux","Pull-buoy entre les cuisses pour les séances de travail bras uniquement","Plaquettes de natation pour renforcer les appuis et améliorer la technique bras","Montre de natation (Garmin Swim) pour suivi des longueurs, SWOLF et temps"]},"nutrition":{"emoji":"💧","title":"Hydratation et nutrition","items":["L''eau fausse la sensation de soif — boire activement même sans ressentir la soif","Repas principal 2h avant la séance : glucides lents + protéines légères","Bouteille d''eau ou boisson isotonique au bord du bassin pour les séances > 60 min","Les séances à jeun sont déconseillées pour la natation — glycémie stable indispensable","Post-natation : protéines rapides (whey) + glucides simples dans les 30 min"]},"recovery":{"emoji":"♨️","title":"Récupération aquatique","items":["Natation lente 200–400 m de cool-down en fin de séance — retour veino-musculaire","Stretching épaules et pectoraux — zones les plus sollicitées en crawl","Jacuzzi ou bain chaud post-séance pour détendre les muscles du dos et des épaules","Massage des épaules et du cou 2× /semaine — prévention tendinite de la coiffe","Minimum 24h entre deux séances intenses — les muscles respiratoires aussi doivent récupérer"]}},"tips":[{"icon":"📐","title":"Le SWOLF est ton allié","body":"SWOLF = temps (secondes) + nombre de mouvements par longueur. Diminuer ton score SWOLF signifie que tu es plus efficace — mieux que de regarder le chrono."},{"icon":"🌊","title":"La résistance change tout","body":"L''eau est 800× plus dense que l''air. Une amélioration technique mineure (angle d''entrée, rotation) peut faire gagner 5–10 s aux 100 m sans gagner en condition physique."},{"icon":"🎯","title":"Drills ciblés","body":"Consacre 20–30 % de chaque séance aux drills techniques (catch-up, finger drag, high elbow) — plus efficace que nager vite pendant 1h."},{"icon":"🤿","title":"Vidéo sous-marine","body":"Filme-toi (ou fais-toi filmer) sous l''eau 1× par mois. La self-analyse révèle des défauts invisibles sur prise de temps."}],"exercises":[{"name":"Crawl drills catch-up","muscles":"Épaules, grand dorsal, technique bras","sets":"6×50 m","difficulty":"Tous niveaux","description":"Nage en attendant que la main avant touche l''autre avant de démarrer le bras suivant. Améliore l''extension du bras et la rotation des hanches."},{"name":"Planche jambes","muscles":"Fléchisseurs de cheville, quadriceps, technique kick","sets":"4×25 m","difficulty":"Débutant","description":"Tiens la planche devant toi à bout de bras et travaille uniquement les jambes. Battements petits et rapides depuis les hanches, genoux légèrement fléchis."},{"name":"Pull-buoy bras","muscles":"Épaules, grand dorsal, pectoraux","sets":"4×50 m","difficulty":"Débutant","description":"Pull-buoy entre les cuisses, travaille uniquement les bras. Concentration maximale sur la traction dans l''eau et le catch en haut du mouvement."},{"name":"Flip-turn isolé","muscles":"Technique virage, abdominaux","sets":"3×10 virages","difficulty":"Intermédiaire","description":"Approche le mur à 1 m, exécute la roulade complète et pousse fort sur le mur. Pratique les virages hors de l''eau d''abord. Peut faire gagner 2–3 s aux 100 m."},{"name":"Intervals 10×100 m","muscles":"Endurance aérobie, cardio-respiratoire","sets":"10×100 m","difficulty":"Intermédiaire","description":"Nage 100 m à 85 % de ta vitesse max, départ toutes les 2 min. Compte tes longueurs et chronomètre chaque 100 m pour suivre la régularité."},{"name":"Sprints 50 m","muscles":"Vitesse maximale, puissance bras","sets":"8×50 m","difficulty":"Avancé","description":"Départ plongé ou culbute, sprint à 100 % sur 50 m. Récupération complète de 2 min entre chaque. Développe la vitesse de pointe et l''explosivité en nage."},{"name":"Nage avec plaquettes","muscles":"Force appuis eau, épaules, dos","sets":"4×50 m","difficulty":"Intermédiaire","description":"Plaquettes aux mains pour augmenter la surface d''appui. Améliore la force et la proprioception de la prise d''eau. Ne pas utiliser plus de 20 % du volume total."},{"name":"Brasse technique lente","muscles":"Coordination globale, hanches, genoux","sets":"6×50 m","difficulty":"Tous niveaux","description":"Brasse très lente avec accent sur la glisse : après chaque traction, les bras s''étendent en avant et les jambes se rejoignent — maintiens la glisse 2 s minimum."},{"name":"Dos crawlé","muscles":"Trapèzes, grand dorsal, épaules, coordination","sets":"4×50 m","difficulty":"Débutant","description":"Sur le dos, entrée du bras dans l''axe de l''épaule, rotation des hanches à 45°. Regard vers le plafond, oreilles dans l''eau. Travaille la coordination dos/bras."}],"program":[{"week":"Semaine 1–2","theme":"Technique crawl","sessions":[{"name":"Séance drills 1 500 m","detail":"Échauffement 400 m + 6×100 m drills (catch-up, 6-3-6, finger drag) + 400 m cool-down"},{"name":"Dos crawlé technique","detail":"Travail amplitude + rotation hanches + entrée des bras — 1 200 m total"},{"name":"Endurance crawl 2 000 m","detail":"Continu à allure confortable — focus sur la constance des mouvements"}]},{"week":"Semaine 3–4","theme":"Vitesse et intervalles","sessions":[{"name":"Intervals 10×100 m","detail":"À 85 % vitesse max, départ toutes les 2 min — travail seuil aérobie"},{"name":"Technique brasse","detail":"Ondulation + coordination bras-jambes-glisse — 1 000 m technique + 500 m libre"},{"name":"Open water simulation","detail":"Nage en piscine sans toucher les lignes : orientation + départ groupé simulé"}]},{"week":"Semaine 5–6","theme":"Performance","sessions":[{"name":"Sprints 50 m × 20","detail":"Départ toutes les 90 s — puissance et vitesse de nage sur courte distance"},{"name":"Série triathlon 3 × 750 m","detail":"Avec transitions simulées en bord de bassin — préparation triathlon"},{"name":"Test chrono 1 500 m","detail":"Nage continue à bloc — comparaison avec la semaine 1 pour mesurer la progression"}]},{"week":"Semaine 7–8","theme":"Affûtage & Open water","sessions":[{"name":"Volume −25 % + sprints courts","detail":"Maintien de la vivacité sans accumuler de fatigue — fraîcheur pour la compétition"},{"name":"Séance open water réelle","detail":"Lac ou mer : orientation, eau froide, balisage — simulation conditions réelles"},{"name":"Test bilan 400 m","detail":"Crawl à bloc 400 m chrono — référence performance finale du cycle"}]}],"faq":[{"q":"Je coule les jambes — comment corriger ?","a":"Les jambes qui coulent viennent souvent d''une tête trop haute ou d''un kick trop puissant. Travaille le drill \"torpedo\" (bras le long du corps, tête dans l''eau) pour corriger la position."},{"q":"Combien de fois par semaine nager pour progresser ?","a":"3 séances/semaine minimum pour une progression technique visible. La natation est une activité très technique — la répétition est clé."},{"q":"Je me fatigue après 50 m — est-ce normal ?","a":"Oui pour un débutant — c''est un problème technique, pas physique. Travaille d''abord la respiration bilatérale et le relâchement dans l''eau. La condition physique vient après."},{"q":"La natation aide-t-elle pour d''autres sports ?","a":"Oui — développe la capacité pulmonaire, la souplesse des épaules et la conscience corporelle. Excellent complément pour le running, le cyclisme et la récupération active."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('natation', 'en', '{"title":"Swimming","tag":"Aquatic","description":"Stroke technique, triathlon prep, open water — progress in every style with HD video drills.","stats":["+900 swimmers","30+ programs","10 weeks avg."],"levels":["Beginner","Intermediate","Advanced","Triathlon"]}'::jsonb, '{"tagline":"Technique, efficiency, performance — the water never lies.","heroStat":"900+ active swimmers","guide":{"technique":{"emoji":"🏊","title":"Swimming technique","items":["Hydrodynamic position: head in line with the body, gaze toward the bottom of the pool","Hip rotation of 45° on each arm stroke — the main source of power","Maximum arm extension before the hand enters the water — \"reach the wall with your fingertips\"","Legs: small fast kicks from the hips, knees slightly bent","Flip-turn: touch the wall at 1 m, somersault, explosive push-off — saves 2–3 s / 100 m"]},"equipment":{"emoji":"🥽","title":"Swimming gear","items":["Anti-fog goggles fitted to your face shape","A silicone cap to reduce drag and protect the hair","A pull-buoy between the thighs for arm-only sets","Hand paddles to strengthen the catch and improve arm technique","A swim watch (Garmin Swim) to track laps, SWOLF and times"]},"nutrition":{"emoji":"💧","title":"Hydration and nutrition","items":["Water dulls the sensation of thirst — drink actively even without feeling thirsty","Main meal 2h before the session: slow carbs + light protein","Water bottle or isotonic drink at the poolside for sessions > 60 min","Fasted sessions are not recommended for swimming — stable blood sugar is essential","Post-swim: fast protein (whey) + simple carbs within 30 min"]},"recovery":{"emoji":"♨️","title":"Aquatic recovery","items":["Slow swim 200–400 m cool-down at the end of the session — venous-muscular return","Stretch the shoulders and pecs — the areas most used in freestyle","Jacuzzi or hot bath post-session to relax the back and shoulder muscles","Massage the shoulders and neck 2× /week — rotator-cuff tendinitis prevention","At least 24h between two intense sessions — the breathing muscles need recovery too"]}},"tips":[{"icon":"📐","title":"SWOLF is your ally","body":"SWOLF = time (seconds) + number of strokes per length. Lowering your SWOLF score means you''re more efficient — better than watching the clock."},{"icon":"🌊","title":"Resistance changes everything","body":"Water is 800× denser than air. A minor technical improvement (entry angle, rotation) can save 5–10 s per 100 m without any fitness gain."},{"icon":"🎯","title":"Targeted drills","body":"Spend 20–30% of each session on technical drills (catch-up, finger drag, high elbow) — more effective than swimming hard for an hour."},{"icon":"🤿","title":"Underwater video","body":"Film yourself (or get filmed) underwater once a month. Self-analysis reveals flaws invisible on a stopwatch."}],"exercises":[{"name":"Catch-up freestyle drill","muscles":"Shoulders, lats, arm technique","sets":"6×50 m","difficulty":"All levels","description":"Swim waiting for the lead hand to touch the other before starting the next arm. Improves arm extension and hip rotation."},{"name":"Kickboard legs","muscles":"Ankle flexors, quads, kick technique","sets":"4×25 m","difficulty":"Beginner","description":"Hold the kickboard in front of you at arm''s length and work the legs only. Small fast kicks from the hips, knees slightly bent."},{"name":"Pull-buoy arms","muscles":"Shoulders, lats, pecs","sets":"4×50 m","difficulty":"Beginner","description":"Pull-buoy between the thighs, work the arms only. Maximum focus on the pull in the water and the catch at the top of the stroke."},{"name":"Isolated flip-turn","muscles":"Turn technique, abs","sets":"3×10 turns","difficulty":"Intermediate","description":"Approach the wall at 1 m, perform the full somersault and push hard off the wall. Practice the turns out of the water first. Can save 2–3 s per 100 m."},{"name":"Intervals 10×100 m","muscles":"Aerobic endurance, cardio-respiratory","sets":"10×100 m","difficulty":"Intermediate","description":"Swim 100 m at 85% of your max speed, leaving every 2 min. Count your laps and time each 100 m to track consistency."},{"name":"50 m sprints","muscles":"Max speed, arm power","sets":"8×50 m","difficulty":"Advanced","description":"Dive or push-off start, sprint at 100% over 50 m. Full 2 min recovery between each. Builds top speed and explosiveness in the water."},{"name":"Swim with paddles","muscles":"Water-catch strength, shoulders, back","sets":"4×50 m","difficulty":"Intermediate","description":"Paddles on the hands to increase the catch surface. Improves strength and feel for the water. Don''t use for more than 20% of total volume."},{"name":"Slow technical breaststroke","muscles":"Whole-body coordination, hips, knees","sets":"6×50 m","difficulty":"All levels","description":"Very slow breaststroke with emphasis on the glide: after each pull, the arms extend forward and the legs come together — hold the glide at least 2 s."},{"name":"Backstroke","muscles":"Traps, lats, shoulders, coordination","sets":"4×50 m","difficulty":"Beginner","description":"On your back, arm entry in line with the shoulder, hip rotation at 45°. Gaze toward the ceiling, ears in the water. Works back/arm coordination."}],"program":[{"week":"Week 1–2","theme":"Freestyle technique","sessions":[{"name":"Drills session 1,500 m","detail":"Warm-up 400 m + 6×100 m drills (catch-up, 6-3-6, finger drag) + 400 m cool-down"},{"name":"Backstroke technique","detail":"Amplitude + hip rotation + arm entry work — 1,200 m total"},{"name":"Freestyle endurance 2,000 m","detail":"Continuous at a comfortable pace — focus on stroke consistency"}]},{"week":"Week 3–4","theme":"Speed and intervals","sessions":[{"name":"Intervals 10×100 m","detail":"At 85% max speed, leaving every 2 min — aerobic-threshold work"},{"name":"Breaststroke technique","detail":"Undulation + arm-leg-glide coordination — 1,000 m technique + 500 m free"},{"name":"Open-water simulation","detail":"Swim in the pool without touching the lanes: sighting + simulated mass start"}]},{"week":"Week 5–6","theme":"Performance","sessions":[{"name":"50 m sprints × 20","detail":"Leaving every 90 s — power and swim speed over short distance"},{"name":"Triathlon set 3 × 750 m","detail":"With simulated poolside transitions — triathlon preparation"},{"name":"1,500 m time trial","detail":"Continuous all-out swim — compare with week 1 to measure progress"}]},{"week":"Week 7–8","theme":"Tapering & Open water","sessions":[{"name":"Volume −25% + short sprints","detail":"Keep the sharpness without accumulating fatigue — freshness for race day"},{"name":"Real open-water session","detail":"Lake or sea: sighting, cold water, buoys — real-condition simulation"},{"name":"400 m benchmark test","detail":"All-out 400 m freestyle time trial — final performance reference of the cycle"}]}],"faq":[{"q":"My legs sink — how do I fix it?","a":"Sinking legs often come from a head held too high or a kick that''s too powerful. Work the \"torpedo\" drill (arms by your sides, head in the water) to correct the position."},{"q":"How often should I swim to progress?","a":"3 sessions/week minimum for visible technical progress. Swimming is a very technical activity — repetition is key."},{"q":"I get tired after 50 m — is that normal?","a":"Yes for a beginner — it''s a technical problem, not a physical one. Work first on bilateral breathing and relaxing in the water. Fitness comes after."},{"q":"Does swimming help for other sports?","a":"Yes — it develops lung capacity, shoulder mobility and body awareness. An excellent complement for running, cycling and active recovery."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('natation', 'de', '{"title":"Schwimmen","tag":"Wasser","description":"Schwimmtechnik, Triathlon-Vorbereitung, Freiwasser — verbessere dich in allen Stilen mit HD-Video-Drills.","stats":["+900 Schwimmer","30+ Programme","Ø 10 Wochen"],"levels":["Anfänger","Fortgeschritten","Erfahren","Triathlon"]}'::jsonb, '{"tagline":"Technik, Effizienz, Leistung — das Wasser lügt nie.","heroStat":"900+ aktive Schwimmer","guide":{"technique":{"emoji":"🏊","title":"Schwimmtechnik","items":["Hydrodynamische Position: Kopf in einer Linie mit dem Körper, Blick zum Beckenboden","Hüftrotation von 45° bei jedem Armzug — die Hauptquelle der Kraft","Maximale Armstreckung, bevor die Hand ins Wasser eintaucht — „erreiche die Wand mit den Fingerspitzen“","Beine: kleine schnelle Schläge aus der Hüfte, Knie leicht gebeugt","Wende (Rollwende): Wand bei 1 m berühren, Rolle, explosiver Abstoß — spart 2–3 s / 100 m"]},"equipment":{"emoji":"🥽","title":"Schwimmausrüstung","items":["Anti-Beschlag-Brille passend zu deiner Gesichtsform","Eine Silikonkappe, um den Widerstand zu reduzieren und die Haare zu schützen","Ein Pull-Buoy zwischen den Oberschenkeln für reine Arm-Sätze","Handpaddles, um den Zug zu stärken und die Armtechnik zu verbessern","Eine Schwimmuhr (Garmin Swim), um Bahnen, SWOLF und Zeiten zu verfolgen"]},"nutrition":{"emoji":"💧","title":"Hydration und Ernährung","items":["Wasser dämpft das Durstgefühl — trinke aktiv, auch ohne Durst","Hauptmahlzeit 2 h vor der Einheit: langsame Kohlenhydrate + leichtes Protein","Trinkflasche oder Isogetränk am Beckenrand für Einheiten > 60 Min","Nüchterne Einheiten sind beim Schwimmen nicht empfohlen — ein stabiler Blutzucker ist essenziell","Nach dem Schwimmen: schnelles Protein (Whey) + einfache Kohlenhydrate innerhalb von 30 Min"]},"recovery":{"emoji":"♨️","title":"Erholung im Wasser","items":["Langsames Ausschwimmen 200–400 m am Ende der Einheit — venös-muskulärer Rückfluss","Dehne Schultern und Brust — die im Kraul am meisten genutzten Bereiche","Whirlpool oder warmes Bad nach der Einheit, um Rücken- und Schultermuskeln zu entspannen","Massiere Schultern und Nacken 2× /Woche — Vorbeugung von Rotatorenmanschetten-Tendinitis","Mindestens 24 h zwischen zwei intensiven Einheiten — auch die Atemmuskeln brauchen Erholung"]}},"tips":[{"icon":"📐","title":"SWOLF ist dein Verbündeter","body":"SWOLF = Zeit (Sekunden) + Anzahl der Züge pro Bahn. Deinen SWOLF-Wert zu senken bedeutet, effizienter zu sein — besser, als auf die Uhr zu schauen."},{"icon":"🌊","title":"Widerstand verändert alles","body":"Wasser ist 800× dichter als Luft. Eine kleine technische Verbesserung (Eintauchwinkel, Rotation) kann 5–10 s pro 100 m sparen, ganz ohne Fitnesszuwachs."},{"icon":"🎯","title":"Gezielte Drills","body":"Verbringe 20–30% jeder Einheit mit technischen Drills (Catch-up, Finger Drag, hoher Ellbogen) — effektiver, als eine Stunde hart zu schwimmen."},{"icon":"🤿","title":"Unterwasservideo","body":"Filme dich (oder lass dich filmen) einmal im Monat unter Wasser. Die Selbstanalyse deckt Fehler auf, die auf der Stoppuhr unsichtbar sind."}],"exercises":[{"name":"Catch-up-Kraul-Drill","muscles":"Schultern, Latissimus, Armtechnik","sets":"6×50 m","difficulty":"Alle Niveaus","description":"Schwimme und warte, bis die führende Hand die andere berührt, bevor du den nächsten Arm startest. Verbessert die Armstreckung und die Hüftrotation."},{"name":"Beine mit Schwimmbrett","muscles":"Knöchelbeuger, Quadrizeps, Beinschlagtechnik","sets":"4×25 m","difficulty":"Anfänger","description":"Halte das Brett mit ausgestreckten Armen vor dir und arbeite nur mit den Beinen. Kleine schnelle Schläge aus der Hüfte, Knie leicht gebeugt."},{"name":"Arme mit Pull-Buoy","muscles":"Schultern, Latissimus, Brust","sets":"4×50 m","difficulty":"Anfänger","description":"Pull-Buoy zwischen den Oberschenkeln, arbeite nur mit den Armen. Maximaler Fokus auf den Zug im Wasser und das Fassen am Anfang des Zugs."},{"name":"Isolierte Rollwende","muscles":"Wendetechnik, Bauch","sets":"3×10 Wenden","difficulty":"Fortgeschritten","description":"Nähere dich der Wand bei 1 m, mach die volle Rolle und stoße dich kräftig von der Wand ab. Übe die Wenden zuerst außerhalb des Wassers. Kann 2–3 s pro 100 m sparen."},{"name":"Intervalle 10×100 m","muscles":"Aerobe Ausdauer, Herz-Kreislauf","sets":"10×100 m","difficulty":"Fortgeschritten","description":"Schwimme 100 m bei 85% deiner Höchstgeschwindigkeit, starte alle 2 Min. Zähle deine Bahnen und stoppe jede 100 m, um die Konstanz zu verfolgen."},{"name":"50-m-Sprints","muscles":"Höchstgeschwindigkeit, Armkraft","sets":"8×50 m","difficulty":"Erfahren","description":"Start mit Sprung oder Abstoß, sprinte mit 100% über 50 m. Volle 2 Min Erholung dazwischen. Baut Spitzengeschwindigkeit und Explosivität im Wasser auf."},{"name":"Schwimmen mit Paddles","muscles":"Wasserzug-Kraft, Schultern, Rücken","sets":"4×50 m","difficulty":"Fortgeschritten","description":"Paddles an den Händen, um die Zugfläche zu vergrößern. Verbessert Kraft und Wassergefühl. Nicht für mehr als 20% des Gesamtvolumens nutzen."},{"name":"Langsames technisches Brustschwimmen","muscles":"Ganzkörperkoordination, Hüfte, Knie","sets":"6×50 m","difficulty":"Alle Niveaus","description":"Sehr langsames Brustschwimmen mit Betonung des Gleitens: Nach jedem Zug strecken sich die Arme nach vorn und die Beine schließen — halte das Gleiten mindestens 2 s."},{"name":"Rückenschwimmen","muscles":"Trapez, Latissimus, Schultern, Koordination","sets":"4×50 m","difficulty":"Anfänger","description":"Auf dem Rücken, Armeintauchen in Schulterlinie, Hüftrotation bei 45°. Blick zur Decke, Ohren im Wasser. Trainiert die Rücken-Arm-Koordination."}],"program":[{"week":"Woche 1–2","theme":"Kraultechnik","sessions":[{"name":"Drill-Einheit 1.500 m","detail":"Aufwärmen 400 m + 6×100 m Drills (Catch-up, 6-3-6, Finger Drag) + 400 m Ausschwimmen"},{"name":"Rückenschwimm-Technik","detail":"Arbeit an Amplitude + Hüftrotation + Armeintauchen — 1.200 m gesamt"},{"name":"Kraul-Ausdauer 2.000 m","detail":"Durchgehend in komfortablem Tempo — Fokus auf gleichmäßigen Zug"}]},{"week":"Woche 3–4","theme":"Geschwindigkeit und Intervalle","sessions":[{"name":"Intervalle 10×100 m","detail":"Bei 85% Höchstgeschwindigkeit, Start alle 2 Min — Arbeit an der aeroben Schwelle"},{"name":"Brustschwimm-Technik","detail":"Wellenbewegung + Arm-Bein-Gleit-Koordination — 1.000 m Technik + 500 m frei"},{"name":"Freiwasser-Simulation","detail":"Schwimme im Becken ohne die Leinen zu berühren: Orientieren + simulierter Massenstart"}]},{"week":"Woche 5–6","theme":"Leistung","sessions":[{"name":"50-m-Sprints × 20","detail":"Start alle 90 s — Leistung und Schwimmgeschwindigkeit über kurze Distanz"},{"name":"Triathlon-Set 3 × 750 m","detail":"Mit simulierten Wechseln am Beckenrand — Triathlon-Vorbereitung"},{"name":"1.500-m-Zeitfahren","detail":"Durchgehender All-out-Schwimm — Vergleich mit Woche 1, um den Fortschritt zu messen"}]},{"week":"Woche 7–8","theme":"Tapering & Freiwasser","sessions":[{"name":"Volumen −25% + kurze Sprints","detail":"Halte die Spritzigkeit, ohne Ermüdung anzusammeln — Frische für den Wettkampftag"},{"name":"Echte Freiwasser-Einheit","detail":"See oder Meer: Orientieren, kaltes Wasser, Bojen — Simulation unter realen Bedingungen"},{"name":"400-m-Benchmark-Test","detail":"All-out 400-m-Kraul-Zeitfahren — finale Leistungsreferenz des Zyklus"}]}],"faq":[{"q":"Meine Beine sinken — wie behebe ich das?","a":"Sinkende Beine kommen oft von einem zu hoch gehaltenen Kopf oder einem zu kräftigen Beinschlag. Arbeite mit dem „Torpedo“-Drill (Arme an den Seiten, Kopf im Wasser), um die Position zu korrigieren."},{"q":"Wie oft sollte ich schwimmen, um voranzukommen?","a":"Mindestens 3 Einheiten/Woche für sichtbaren technischen Fortschritt. Schwimmen ist eine sehr technische Aktivität — Wiederholung ist der Schlüssel."},{"q":"Ich bin nach 50 m müde — ist das normal?","a":"Ja, für einen Anfänger — es ist ein technisches, kein körperliches Problem. Arbeite zuerst an der beidseitigen Atmung und am Entspannen im Wasser. Die Fitness kommt danach."},{"q":"Hilft Schwimmen für andere Sportarten?","a":"Ja — es entwickelt Lungenkapazität, Schultermobilität und Körpergefühl. Eine exzellente Ergänzung für Laufen, Radfahren und aktive Erholung."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('natation', 0, array['6_vXycbD2TM','WciCYtnGbkM']::text[], 'pro', '{"fr":{"title":"Apprendre le crawl — Guide étape par étape","description":"Guide complet du crawl pour débutants : position du corps, mouvement des bras, respiration et jambes.","duration":"22 min","level":"Débutant"},"en":{"title":"Learn freestyle — Step by step","description":"A complete freestyle guide for beginners: body position, arm movement, breathing and legs.","duration":"22 min","level":"Beginner"},"de":{"title":"Kraulen lernen — Schritt für Schritt","description":"Ein kompletter Kraul-Leitfaden für Anfänger: Körperposition, Armbewegung, Atmung und Beine.","duration":"22 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
