insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('natation', 2, array['DUpfLigoWEc','0BELcjhKOlc']::text[], 'pro', '{"fr":{"title":"Crawl débutant — Apprends vite","description":"Méthode rapide pour maîtriser le crawl — les erreurs les plus courantes corrigées en une vidéo.","duration":"16 min","level":"Débutant"},"en":{"title":"Beginner freestyle — Learn fast","description":"A fast method to master freestyle — the most common mistakes corrected in one video.","duration":"16 min","level":"Beginner"},"de":{"title":"Anfänger-Kraul — Schnell lernen","description":"Eine schnelle Methode, um das Kraulen zu meistern — die häufigsten Fehler in einem Video korrigiert.","duration":"16 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('natation', 3, array['K5RMFjHBPHE']::text[], 'pro', '{"fr":{"title":"Les 4 meilleurs drills de dos crawlé","description":"Quatre exercices ciblés pour améliorer ta technique de dos crawlé — rotation, entrée de bras, position.","duration":"12 min","level":"Intermédiaire"},"en":{"title":"The 4 best backstroke drills","description":"Four targeted exercises to improve your backstroke technique — rotation, arm entry, position.","duration":"12 min","level":"Intermediate"},"de":{"title":"Die 4 besten Rückenschwimm-Drills","description":"Vier gezielte Übungen, um deine Rückenschwimm-Technik zu verbessern — Rotation, Armeintauchen, Position.","duration":"12 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('natation', 4, array['WiMMuE7P7P4']::text[], 'pro', '{"fr":{"title":"3 drills de brasse essentiels","description":"Trois exercices clés pour perfectionner ta brasse — coordination bras-jambes, glisse et timing.","duration":"10 min","level":"Tous niveaux"},"en":{"title":"3 essential breaststroke drills","description":"Three key exercises to perfect your breaststroke — arm-leg coordination, glide and timing.","duration":"10 min","level":"All levels"},"de":{"title":"3 essenzielle Brustschwimm-Drills","description":"Drei Schlüsselübungen, um dein Brustschwimmen zu perfektionieren — Arm-Bein-Koordination, Gleiten und Timing.","duration":"10 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('natation', 5, array['aU7sdctpxck']::text[], 'pro', '{"fr":{"title":"Maîtriser le dos crawlé — 6 drills","description":"Six exercices progressifs pour maîtriser le dos crawlé de la technique de base aux niveaux avancés.","duration":"18 min","level":"Avancé"},"en":{"title":"Master the backstroke — 6 drills","description":"Six progressive exercises to master the backstroke from the basics to advanced levels.","duration":"18 min","level":"Advanced"},"de":{"title":"Meistere das Rückenschwimmen — 6 Drills","description":"Sechs progressive Übungen, um das Rückenschwimmen von den Grundlagen bis zum fortgeschrittenen Niveau zu meistern.","duration":"18 Min","level":"Erfahren"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
