insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('crossfit', 'fr', '{"title":"CrossFit","tag":"Functional","description":"WODs quotidiens, mouvements fonctionnels et challenges communautaires pour repousser tes limites chaque semaine.","stats":["+1 800 athlètes","365 WODs/an","5× / semaine"],"levels":["Débutant","Intermédiaire","RX","Compétition"]}'::jsonb, '{"tagline":"Forged in fire. Tested every day.","heroStat":"1 800+ athlètes actifs","guide":{"technique":{"emoji":"🏋️","title":"Mouvements fondamentaux","items":["Les 9 mouvements fondamentaux CrossFit doivent être maîtrisés avant de charger lourd","Snatch et Clean & Jerk : travail technique seul minimum 4–6 semaines avant d''ajouter du poids","Gymnastic skills : string pull-ups avant strict, kipping après — la force précède le kip","Box jumps : atterrissage sur la boîte, descente par l''extérieur (sécurité genou)","Double-unders : patience — 3–6 mois pour maîtriser, mais ça vaut chaque essai raté"]},"equipment":{"emoji":"🔗","title":"Équipement CrossFit","items":["Chaussures versatiles (Nike Metcon, Reebok Nano) — compromis entre stabilité et course","Ceinture olympique pour les soulevés de terre et mouvements overhead lourds","Grip pads ou spartiates pour les barres kipping — prévention ampoules","Corde à sauter de speed (câble acier) pour les double-unders","Chalk libre — indispensable pour les workouts avec barbell et pull-ups chargés"]},"nutrition":{"emoji":"🥗","title":"Fuel for CrossFit","items":["CrossFit est anaérobie-aérobie : glucides rapides avant le WOD (banane, riz)","Protéines 2 g/kg/jour — la reconstruction musculaire post-WOD est intensive","Créatine 5 g/jour — améliorations mesurables sur les mouvements de puissance","Bêta-alanine pour les WODs longs (> 10 min) — réduction de l''acidose musculaire","Hydratation : peser avant/après — chaque kg perdu = 1L d''eau à compenser"]},"recovery":{"emoji":"🏥","title":"Récupération CrossFit","items":["Cool-down obligatoire : 10 min mobility + 5 min breathing après chaque WOD intense","Glace sur les articulations sensibles (poignets, épaules, genoux) post-workout","Foam rolling sur les zones de garde musculaire : thorax, hanches, ischio-jambiers","Maximum 2 jours consécutifs sans repos — le CrossFit détruit autant qu''il construit","Sommeil : l''IGF-1 (insulin-like growth factor) nécessite minimum 7,5h de sommeil récupérateur"]}},"tips":[{"icon":"🎯","title":"Scale intelligemment","body":"Il n''y a aucune honte à scaler un WOD. Faire \"Fran\" en 12 min avec charges adaptées est plus bénéfique que de souffrir 25 min avec trop lourd."},{"icon":"⏱️","title":"Stratégie beats fitness","body":"Diviser un WOD (sets de 10 → 7-3, 21s → 12-9) avant de fatiguer est toujours plus rapide que partir à bloc et s''effondrer."},{"icon":"📓","title":"Loggue chaque WOD","body":"Note ton temps, tes charges et tes notes. Repasser un benchmark WOD en sachant l''objectif à battre est le moteur de progression numéro 1."},{"icon":"🤝","title":"La communauté est le programme","body":"L''effet box — s''entraîner avec d''autres — améliore la performance de 20 % en moyenne. La compétition amicale est le meilleur pre-workout."}],"exercises":[{"name":"Thrusters","muscles":"Quadriceps, fessiers, épaules, triceps","sets":"5×5","difficulty":"Intermédiaire","description":"Squat avec la barre en rack frontal puis poussée overhead dans la continuité du mouvement. Exercice \"roi\" du CrossFit — combinaison squat et shoulder press en un."},{"name":"Pull-ups kipping","muscles":"Grand dorsal, biceps, abdominal","sets":"5×10","difficulty":"Intermédiaire","description":"Traction avec balancier du corps pour maximiser l''efficacité sur les WODs longs. Maîtrise d''abord les strict pull-ups avant de passer au kipping pour protéger les épaules."},{"name":"Box jumps","muscles":"Quadriceps, mollets, gainage, explosivité","sets":"5×10","difficulty":"Tous niveaux","description":"Saute sur la caisse en deux pieds, absorbe en demi-squat, descends par l''extérieur. Commence à 40 cm et monte progressivement. Fondamental des WODs CrossFit."},{"name":"Snatch technique","muscles":"Full body, coordination, puissance","sets":"4×3","difficulty":"Avancé","description":"L''arraché olympique — de la barre au sol au verrouillage overhead en un mouvement explosif. Travail technique indispensable avant de charger. Commencer à la barre seule."},{"name":"Double-unders","muscles":"Mollets, coordination, cardio","sets":"5×50","difficulty":"Intermédiaire","description":"La corde passe deux fois sous les pieds à chaque saut. Sauts légèrement plus hauts que les simples, poignets très rapides. 3–6 mois de pratique pour les maîtriser."},{"name":"Wall balls","muscles":"Quadriceps, fessiers, épaules, coordination","sets":"5×15","difficulty":"Débutant","description":"Squat profond puis projette la medball (9/6 kg) contre la cible à 3 m. Attrape la balle à la descente et enchaîne directement. Développe l''endurance musculaire globale."},{"name":"GHD sit-ups","muscles":"Abdominaux, fléchisseurs de hanche, extenseurs dos","sets":"3×15","difficulty":"Avancé","description":"Sur le GHD machine, descends jusqu''à l''horizontale et remonte en utilisant les abdos. Commence avec petit range of motion — douleurs de DOMS intenses chez les débutants."},{"name":"Muscle-ups","muscles":"Dos, triceps, pectoraux, coordination","sets":"3×3","difficulty":"Avancé","description":"Depuis la suspension, combine traction et dips en un seul mouvement pour passer au-dessus de la barre. Nécessite une base solide de pull-ups et dips avant de progresser vers cet objectif."},{"name":"Clean & Jerk","muscles":"Full body, puissance, technique olympique","sets":"4×3","difficulty":"Avancé","description":"Épaulé-jeté olympique en deux temps — épaulé (barre de sol en rack) puis jeté (barre overhead). Le mouvement qui définit le CrossFit de haut niveau. Technique avant charge."},{"name":"Burpees box jumps","muscles":"Full body, cardio, explosivité","sets":"4×10","difficulty":"Intermédiaire","description":"Burpee classique puis saute sur la caisse au lieu de sauter en l''air. Combine l''endurance du burpee et la puissance du box jump. Fréquent dans les WODs compétition."}],"program":[{"week":"Semaine 1–2","theme":"Technique & Fondamentaux","sessions":[{"name":"Skills : Snatch progressif","detail":"Bar only → 40 kg → 60 % 1RM — technique avant tout, 45 min + WOD léger 10 min"},{"name":"WOD : Fran scalée","detail":"21-15-9 : Thrusters (35/25 kg) + Pull-ups — cible < 10 min"},{"name":"Gymnastic : HSPU drills","detail":"Wall walk + negative HSPU + pike push-up — 4×5 progressifs"}]},{"week":"Semaine 3–4","theme":"Volume & Intensity","sessions":[{"name":"WOD : Murph 50 %","detail":"50 pull-ups, 100 push-ups, 150 squats + 1 mile run — partition libre avec gilet si possible"},{"name":"Barbell cycling 20 min","detail":"Clean & Jerk : EMOM 3 reps à 70 % 1RM — technique sous fatigue"},{"name":"WOD : Death by pull-ups","detail":"Minute 1 : 1 pull-up. Continue jusqu''à l''échec — teste l''endurance gymnastic"}]},{"week":"Semaine 5–6","theme":"Benchmarks & Records","sessions":[{"name":"Benchmark : Grace","detail":"30 Clean & Jerks (60/40 kg) for time — cible < 5 min pour RX"},{"name":"Open WOD simulation","detail":"WOD style Open avec structure 20 min AMRAP — entraînement compétition"},{"name":"Test : Chest-to-bar max unbroken","detail":"Évaluation C2B pull-ups, bar muscle-up et TTB — baseline gymnastic"}]},{"week":"Semaine 7–8","theme":"Peaking & Competition","sessions":[{"name":"Volume allégé + skills","detail":"Focus sur les points faibles identifiés — double-unders, pistol squats, snatch balance"},{"name":"WOD test PR","detail":"Refaire un WOD de la semaine 1–2 pour mesurer la progression — benchmark obligatoire"},{"name":"Fun WOD communauté","detail":"WOD en groupe, poids léger, plaisir — terminer le cycle sur une bonne énergie"}]}],"faq":[{"q":"Le CrossFit est-il dangereux ?","a":"Non si bien encadré. Le risque de blessure au CrossFit est comparable à la gym traditionnelle. La technique prime toujours sur la charge ou la vitesse — scaler est toujours la bonne décision."},{"q":"Faut-il être déjà en forme pour commencer ?","a":"Non — tout le monde commence le CrossFit en scalant. La programmatique est universelle, seules les charges et modifications varient selon le niveau."},{"q":"Combien de WODs par semaine ?","a":"3 WODs/semaine est idéal pour débutant. 4–5 pour intermédiaire avec un jour de mobilité. Les athlètes de niveau compétition font 5–6 sessions + récupération active."},{"q":"Le CrossFit aide-t-il à maigrir ?","a":"Oui — la combinaison de force, cardio et intensité variable brûle 500–800 kcal/séance et génère un EPOC significatif. Associé à une alimentation adaptée, c''est très efficace."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('crossfit', 'en', '{"title":"CrossFit","tag":"Functional","description":"Daily WODs, functional movements and community challenges to push your limits every week.","stats":["+1,800 athletes","365 WODs/yr","5× / week"],"levels":["Beginner","Intermediate","RX","Competition"]}'::jsonb, '{"tagline":"Forged in fire. Tested every day.","heroStat":"1,800+ active athletes","guide":{"technique":{"emoji":"🏋️","title":"Fundamental movements","items":["The 9 fundamental CrossFit movements must be mastered before loading heavy","Snatch and Clean & Jerk: technical work alone for at least 4–6 weeks before adding weight","Gymnastic skills: strict pull-ups before, kipping after — strength precedes the kip","Box jumps: land on the box, step down on the outside (knee safety)","Double-unders: be patient — 3–6 months to master, but worth every missed attempt"]},"equipment":{"emoji":"🔗","title":"CrossFit equipment","items":["Versatile shoes (Nike Metcon, Reebok Nano) — a compromise between stability and running","An Olympic belt for deadlifts and heavy overhead movements","Grip pads or hand guards for kipping bars — blister prevention","A speed jump rope (steel cable) for double-unders","Loose chalk — essential for barbell workouts and loaded pull-ups"]},"nutrition":{"emoji":"🥗","title":"Fuel for CrossFit","items":["CrossFit is anaerobic-aerobic: fast carbs before the WOD (banana, rice)","Protein 2 g/kg/day — post-WOD muscle rebuilding is intense","Creatine 5 g/day — measurable improvements on power movements","Beta-alanine for long WODs (> 10 min) — reduces muscle acidosis","Hydration: weigh before/after — each kg lost = 1L of water to replace"]},"recovery":{"emoji":"🏥","title":"CrossFit recovery","items":["Cool-down is mandatory: 10 min mobility + 5 min breathing after every intense WOD","Ice on sensitive joints (wrists, shoulders, knees) post-workout","Foam rolling on the muscle-guarding areas: chest, hips, hamstrings","Maximum 2 consecutive days without rest — CrossFit breaks down as much as it builds","Sleep: IGF-1 (insulin-like growth factor) requires at least 7.5h of restorative sleep"]}},"tips":[{"icon":"🎯","title":"Scale smartly","body":"There''s no shame in scaling a WOD. Doing \"Fran\" in 12 min with adapted loads is more beneficial than suffering 25 min with too much weight."},{"icon":"⏱️","title":"Strategy beats fitness","body":"Breaking up a WOD (sets of 10 → 7-3, 21s → 12-9) before you fatigue is always faster than going all-out and falling apart."},{"icon":"📓","title":"Log every WOD","body":"Note your time, loads and notes. Redoing a benchmark WOD knowing the target to beat is the number-one driver of progress."},{"icon":"🤝","title":"The community is the program","body":"The box effect — training with others — improves performance by 20% on average. Friendly competition is the best pre-workout."}],"exercises":[{"name":"Thrusters","muscles":"Quads, glutes, shoulders, triceps","sets":"5×5","difficulty":"Intermediate","description":"Front-rack squat then overhead press in one continuous movement. The \"king\" CrossFit exercise — a squat and shoulder press combined."},{"name":"Kipping pull-ups","muscles":"Lats, biceps, abs","sets":"5×10","difficulty":"Intermediate","description":"Pull-up with a body swing to maximize efficiency on long WODs. Master strict pull-ups first before switching to kipping to protect the shoulders."},{"name":"Box jumps","muscles":"Quads, calves, core, explosiveness","sets":"5×10","difficulty":"All levels","description":"Jump onto the box with both feet, absorb in a half-squat, step down on the outside. Start at 40 cm and build up. A CrossFit WOD staple."},{"name":"Snatch technique","muscles":"Full body, coordination, power","sets":"4×3","difficulty":"Advanced","description":"The Olympic snatch — from the bar on the floor to the overhead lockout in one explosive movement. Technical work is essential before loading. Start with the empty bar."},{"name":"Double-unders","muscles":"Calves, coordination, cardio","sets":"5×50","difficulty":"Intermediate","description":"The rope passes twice under the feet on each jump. Jumps slightly higher than singles, very fast wrists. 3–6 months of practice to master."},{"name":"Wall balls","muscles":"Quads, glutes, shoulders, coordination","sets":"5×15","difficulty":"Beginner","description":"Deep squat then throw the medball (9/6 kg) at the target 3 m up. Catch the ball on the way down and chain directly. Builds overall muscular endurance."},{"name":"GHD sit-ups","muscles":"Abs, hip flexors, back extensors","sets":"3×15","difficulty":"Advanced","description":"On the GHD machine, lower to horizontal and come back up using the abs. Start with a small range of motion — intense DOMS for beginners."},{"name":"Muscle-ups","muscles":"Back, triceps, pecs, coordination","sets":"3×3","difficulty":"Advanced","description":"From a hang, combine a pull-up and a dip in one movement to get above the bar. Requires a solid base of pull-ups and dips before progressing toward this goal."},{"name":"Clean & Jerk","muscles":"Full body, power, Olympic technique","sets":"4×3","difficulty":"Advanced","description":"The Olympic clean and jerk in two phases — clean (floor to rack) then jerk (bar overhead). The movement that defines high-level CrossFit. Technique before load."},{"name":"Burpee box jumps","muscles":"Full body, cardio, explosiveness","sets":"4×10","difficulty":"Intermediate","description":"A classic burpee then jump onto the box instead of jumping in the air. Combines burpee endurance and box-jump power. Common in competition WODs."}],"program":[{"week":"Week 1–2","theme":"Technique & Fundamentals","sessions":[{"name":"Skills: Progressive Snatch","detail":"Bar only → 40 kg → 60% 1RM — technique first, 45 min + light WOD 10 min"},{"name":"WOD: Scaled Fran","detail":"21-15-9: Thrusters (35/25 kg) + Pull-ups — target < 10 min"},{"name":"Gymnastic: HSPU drills","detail":"Wall walk + negative HSPU + pike push-up — 4×5 progressive"}]},{"week":"Week 3–4","theme":"Volume & Intensity","sessions":[{"name":"WOD: Murph 50%","detail":"50 pull-ups, 100 push-ups, 150 squats + 1 mile run — free partitioning, with vest if possible"},{"name":"Barbell cycling 20 min","detail":"Clean & Jerk: EMOM 3 reps at 70% 1RM — technique under fatigue"},{"name":"WOD: Death by pull-ups","detail":"Minute 1: 1 pull-up. Continue to failure — tests gymnastic endurance"}]},{"week":"Week 5–6","theme":"Benchmarks & Records","sessions":[{"name":"Benchmark: Grace","detail":"30 Clean & Jerks (60/40 kg) for time — target < 5 min for RX"},{"name":"Open WOD simulation","detail":"Open-style WOD with a 20-min AMRAP structure — competition training"},{"name":"Test: Chest-to-bar max unbroken","detail":"Assess C2B pull-ups, bar muscle-up and TTB — gymnastic baseline"}]},{"week":"Week 7–8","theme":"Peaking & Competition","sessions":[{"name":"Reduced volume + skills","detail":"Focus on identified weaknesses — double-unders, pistol squats, snatch balance"},{"name":"WOD PR test","detail":"Redo a WOD from week 1–2 to measure progress — mandatory benchmark"},{"name":"Fun community WOD","detail":"Group WOD, light weight, fun — finish the cycle on good energy"}]}],"faq":[{"q":"Is CrossFit dangerous?","a":"No when well coached. The injury risk in CrossFit is comparable to traditional gym training. Technique always comes before load or speed — scaling is always the right call."},{"q":"Do I need to be fit already to start?","a":"No — everyone starts CrossFit by scaling. The programming is universal; only the loads and modifications vary by level."},{"q":"How many WODs per week?","a":"3 WODs/week is ideal for beginners. 4–5 for intermediate with a mobility day. Competition-level athletes do 5–6 sessions + active recovery."},{"q":"Does CrossFit help you lose weight?","a":"Yes — the combination of strength, cardio and variable intensity burns 500–800 kcal/session and generates significant EPOC. Paired with proper nutrition, it''s very effective."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('crossfit', 'de', '{"title":"CrossFit","tag":"Funktional","description":"Tägliche WODs, funktionelle Bewegungen und Community-Challenges, um deine Grenzen jede Woche zu erweitern.","stats":["+1.800 Athleten","365 WODs/Jahr","5× / Woche"],"levels":["Anfänger","Fortgeschritten","RX","Wettkampf"]}'::jsonb, '{"tagline":"Im Feuer geschmiedet. Jeden Tag getestet.","heroStat":"1.800+ aktive Athleten","guide":{"technique":{"emoji":"🏋️","title":"Fundamentale Bewegungen","items":["Die 9 fundamentalen CrossFit-Bewegungen müssen beherrscht werden, bevor man schwer lädt","Snatch und Clean & Jerk: technische Arbeit allein für mindestens 4–6 Wochen, bevor Gewicht hinzukommt","Gymnastik-Skills: strikte Klimmzüge zuerst, Kipping danach — Kraft geht dem Kip voraus","Box Jumps: auf der Box landen, außen heruntersteigen (Kniesicherheit)","Double-Unders: hab Geduld — 3–6 Monate bis zur Beherrschung, aber jeden Fehlversuch wert"]},"equipment":{"emoji":"🔗","title":"CrossFit-Ausrüstung","items":["Vielseitige Schuhe (Nike Metcon, Reebok Nano) — ein Kompromiss zwischen Stabilität und Laufen","Ein Olympia-Gürtel für Kreuzheben und schwere Überkopfbewegungen","Grip-Pads oder Handschützer für Kipping-Stangen — Blasenprävention","Ein Speed-Springseil (Stahlkabel) für Double-Unders","Loses Magnesia — essenziell für Langhantel-Workouts und beladene Klimmzüge"]},"nutrition":{"emoji":"🥗","title":"Treibstoff für CrossFit","items":["CrossFit ist anaerob-aerob: schnelle Kohlenhydrate vor dem WOD (Banane, Reis)","Protein 2 g/kg/Tag — der Muskelwiederaufbau nach dem WOD ist intensiv","Kreatin 5 g/Tag — messbare Verbesserungen bei Kraftbewegungen","Beta-Alanin für lange WODs (> 10 Min) — reduziert die Muskelazidose","Hydration: vorher/nachher wiegen — jedes verlorene kg = 1 L Wasser ersetzen"]},"recovery":{"emoji":"🏥","title":"CrossFit-Erholung","items":["Cool-down ist Pflicht: 10 Min Mobilität + 5 Min Atmung nach jedem intensiven WOD","Eis auf empfindliche Gelenke (Handgelenke, Schultern, Knie) nach dem Workout","Foam Rolling auf den verspannten Bereichen: Brust, Hüften, Beinbeuger","Maximal 2 aufeinanderfolgende Tage ohne Ruhe — CrossFit baut so viel ab, wie es aufbaut","Schlaf: IGF-1 (insulinähnlicher Wachstumsfaktor) erfordert mindestens 7,5 h erholsamen Schlaf"]}},"tips":[{"icon":"🎯","title":"Skaliere klug","body":"Es ist keine Schande, ein WOD zu skalieren. „Fran“ in 12 Min mit angepassten Lasten zu machen ist sinnvoller, als 25 Min mit zu viel Gewicht zu leiden."},{"icon":"⏱️","title":"Strategie schlägt Fitness","body":"Ein WOD aufzuteilen (Sätze von 10 → 7-3, 21er → 12-9), bevor du ermüdest, ist immer schneller, als all-out zu gehen und einzubrechen."},{"icon":"📓","title":"Protokolliere jedes WOD","body":"Notiere deine Zeit, Lasten und Notizen. Ein Benchmark-WOD zu wiederholen, das Ziel zum Schlagen kennend, ist der Antrieb Nr. 1 für Fortschritt."},{"icon":"🤝","title":"Die Community ist das Programm","body":"Der Box-Effekt — mit anderen zu trainieren — verbessert die Leistung im Schnitt um 20%. Freundschaftlicher Wettbewerb ist das beste Pre-Workout."}],"exercises":[{"name":"Thrusters","muscles":"Quadrizeps, Gesäß, Schultern, Trizeps","sets":"5×5","difficulty":"Fortgeschritten","description":"Front-Rack-Kniebeuge, dann Schulterdrücken über Kopf in einer durchgehenden Bewegung. Die „Königs“-CrossFit-Übung — eine Kniebeuge und ein Schulterdrücken kombiniert."},{"name":"Kipping-Klimmzüge","muscles":"Latissimus, Bizeps, Bauch","sets":"5×10","difficulty":"Fortgeschritten","description":"Klimmzug mit Körperschwung zur Maximierung der Effizienz bei langen WODs. Beherrsche zuerst strikte Klimmzüge, bevor du zum Kipping wechselst, um die Schultern zu schützen."},{"name":"Box Jumps","muscles":"Quadrizeps, Waden, Rumpf, Explosivität","sets":"5×10","difficulty":"Alle Niveaus","description":"Springe mit beiden Füßen auf die Box, fange in einer halben Kniebeuge ab, steig außen herunter. Starte bei 40 cm und steigere dich. Ein CrossFit-WOD-Klassiker."},{"name":"Snatch-Technik","muscles":"Ganzkörper, Koordination, Power","sets":"4×3","difficulty":"Erfahren","description":"Der olympische Snatch — von der Stange am Boden bis zum Overhead-Lockout in einer explosiven Bewegung. Technische Arbeit ist essenziell vor dem Laden. Starte mit der leeren Stange."},{"name":"Double-Unders","muscles":"Waden, Koordination, Cardio","sets":"5×50","difficulty":"Fortgeschritten","description":"Das Seil läuft bei jedem Sprung zweimal unter den Füßen durch. Etwas höhere Sprünge als bei Singles, sehr schnelle Handgelenke. 3–6 Monate Übung bis zur Beherrschung."},{"name":"Wall Balls","muscles":"Quadrizeps, Gesäß, Schultern, Koordination","sets":"5×15","difficulty":"Anfänger","description":"Tiefe Kniebeuge, dann wirf den Medizinball (9/6 kg) auf das Ziel 3 m hoch. Fange den Ball beim Herunterkommen und verkette direkt. Baut allgemeine Muskelausdauer auf."},{"name":"GHD-Sit-ups","muscles":"Bauch, Hüftbeuger, Rückenstrecker","sets":"3×15","difficulty":"Erfahren","description":"An der GHD-Maschine bis zur Horizontalen absenken und mit den Bauchmuskeln zurückkommen. Starte mit kleinem Bewegungsumfang — intensiver Muskelkater für Anfänger."},{"name":"Muscle-ups","muscles":"Rücken, Trizeps, Brust, Koordination","sets":"3×3","difficulty":"Erfahren","description":"Aus dem Hang kombiniere einen Klimmzug und einen Dip in einer Bewegung, um über die Stange zu kommen. Erfordert eine solide Basis an Klimmzügen und Dips vor der Progression zu diesem Ziel."},{"name":"Clean & Jerk","muscles":"Ganzkörper, Power, olympische Technik","sets":"4×3","difficulty":"Erfahren","description":"Das olympische Umsetzen und Stoßen in zwei Phasen — Clean (Boden zum Rack), dann Jerk (Stange über Kopf). Die Bewegung, die High-Level-CrossFit definiert. Technik vor Last."},{"name":"Burpee Box Jumps","muscles":"Ganzkörper, Cardio, Explosivität","sets":"4×10","difficulty":"Fortgeschritten","description":"Ein klassischer Burpee, dann auf die Box springen statt in die Luft. Kombiniert Burpee-Ausdauer und Box-Jump-Power. Häufig in Wettkampf-WODs."}],"program":[{"week":"Woche 1–2","theme":"Technik & Grundlagen","sessions":[{"name":"Skills: Progressiver Snatch","detail":"Nur Stange → 40 kg → 60% 1RM — Technik zuerst, 45 Min + leichtes WOD 10 Min"},{"name":"WOD: Scaled Fran","detail":"21-15-9: Thrusters (35/25 kg) + Klimmzüge — Ziel < 10 Min"},{"name":"Gymnastik: HSPU-Drills","detail":"Wall Walk + negative HSPU + Pike Push-up — 4×5 progressiv"}]},{"week":"Woche 3–4","theme":"Volumen & Intensität","sessions":[{"name":"WOD: Murph 50%","detail":"50 Klimmzüge, 100 Liegestütze, 150 Kniebeugen + 1 Meile Lauf — freie Aufteilung, mit Weste wenn möglich"},{"name":"Barbell Cycling 20 Min","detail":"Clean & Jerk: EMOM 3 Wdh bei 70% 1RM — Technik unter Ermüdung"},{"name":"WOD: Death by Pull-ups","detail":"Minute 1: 1 Klimmzug. Weiter bis zum Versagen — testet die Gymnastik-Ausdauer"}]},{"week":"Woche 5–6","theme":"Benchmarks & Rekorde","sessions":[{"name":"Benchmark: Grace","detail":"30 Clean & Jerks (60/40 kg) auf Zeit — Ziel < 5 Min für RX"},{"name":"Open-WOD-Simulation","detail":"WOD im Open-Stil mit 20-Min-AMRAP-Struktur — Wettkampftraining"},{"name":"Test: Chest-to-bar max unbroken","detail":"Bewerte C2B-Klimmzüge, Bar Muscle-up und TTB — Gymnastik-Ausgangswert"}]},{"week":"Woche 7–8","theme":"Peaking & Wettkampf","sessions":[{"name":"Reduziertes Volumen + Skills","detail":"Fokus auf identifizierte Schwächen — Double-Unders, Pistol Squats, Snatch Balance"},{"name":"WOD-PR-Test","detail":"Wiederhole ein WOD aus Woche 1–2, um den Fortschritt zu messen — Pflicht-Benchmark"},{"name":"Fun-Community-WOD","detail":"Gruppen-WOD, leichtes Gewicht, Spaß — beende den Zyklus mit guter Energie"}]}],"faq":[{"q":"Ist CrossFit gefährlich?","a":"Nein, wenn gut gecoacht. Das Verletzungsrisiko im CrossFit ist vergleichbar mit klassischem Studiotraining. Technik geht immer vor Last oder Geschwindigkeit — Skalieren ist immer die richtige Wahl."},{"q":"Muss ich schon fit sein, um anzufangen?","a":"Nein — jeder beginnt CrossFit mit Skalieren. Die Programmierung ist universell; nur die Lasten und Modifikationen variieren je nach Niveau."},{"q":"Wie viele WODs pro Woche?","a":"3 WODs/Woche sind ideal für Anfänger. 4–5 für Fortgeschrittene mit einem Mobilitätstag. Athleten auf Wettkampfniveau machen 5–6 Einheiten + aktive Erholung."},{"q":"Hilft CrossFit beim Abnehmen?","a":"Ja — die Kombination aus Kraft, Cardio und variabler Intensität verbrennt 500–800 kcal/Einheit und erzeugt einen deutlichen EPOC. Mit guter Ernährung kombiniert ist es sehr effektiv."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('crossfit', 0, array['mLDxJTk6xj8']::text[], 'pro', '{"fr":{"title":"9 exercices fondamentaux CrossFit","description":"Maîtrise les 9 mouvements de base avant de te lancer dans les WODs — guide pour débutants complets.","duration":"20 min","level":"Débutant"},"en":{"title":"9 fundamental CrossFit exercises","description":"Master the 9 basic movements before diving into WODs — a guide for complete beginners.","duration":"20 min","level":"Beginner"},"de":{"title":"9 fundamentale CrossFit-Übungen","description":"Beherrsche die 9 Grundbewegungen, bevor du in WODs eintauchst — ein Leitfaden für absolute Anfänger.","duration":"20 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('crossfit', 1, array['nJWMnyTaU0Y']::text[], 'pro', '{"fr":{"title":"Top 5 WODs benchmark débutants","description":"Les 5 WODs de référence à connaître quand on débute le CrossFit — stratégie et scaling expliqués.","duration":"15 min","level":"Débutant"},"en":{"title":"Top 5 beginner benchmark WODs","description":"The 5 reference WODs to know when starting CrossFit — strategy and scaling explained.","duration":"15 min","level":"Beginner"},"de":{"title":"Top 5 Anfänger-Benchmark-WODs","description":"Die 5 Referenz-WODs, die man zum CrossFit-Start kennen sollte — Strategie und Skalierung erklärt.","duration":"15 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('crossfit', 2, array['XwmDh9qQtTc']::text[], 'pro', '{"fr":{"title":"3 WODs CrossFit sans équipement","description":"Trois séances CrossFit au poids du corps à faire à la maison — efficaces, sans matériel requis.","duration":"25 min","level":"Intermédiaire"},"en":{"title":"3 no-equipment CrossFit WODs","description":"Three bodyweight CrossFit sessions to do at home — effective, no gear required.","duration":"25 min","level":"Intermediate"},"de":{"title":"3 CrossFit-WODs ohne Ausrüstung","description":"Drei CrossFit-Einheiten mit dem eigenen Körpergewicht für zu Hause — effektiv, kein Equipment nötig.","duration":"25 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('crossfit', 3, array['tCbRldfx7jk']::text[], 'pro', '{"fr":{"title":"J''ai essayé le WOD Murph","description":"Retour d''expérience complet sur le WOD Murph — préparation, stratégie et ressenti après l''effort.","duration":"18 min","level":"Tous niveaux"},"en":{"title":"I tried the Murph WOD","description":"A complete experience report on the Murph WOD — preparation, strategy and how it felt afterward.","duration":"18 min","level":"All levels"},"de":{"title":"Ich habe das Murph-WOD ausprobiert","description":"Ein kompletter Erfahrungsbericht zum Murph-WOD — Vorbereitung, Strategie und wie es sich danach anfühlte.","duration":"18 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('crossfit', 4, array['M_ry-0rLRoc']::text[], 'pro', '{"fr":{"title":"Murph Hero WOD — Démonstration complète","description":"Exécution complète du WOD Murph avec conseils de stratégie, partition et rythme pour le finir.","duration":"22 min","level":"Avancé"},"en":{"title":"Murph Hero WOD — Full demonstration","description":"A complete run-through of the Murph WOD with strategy tips, pacing and partitioning to finish it.","duration":"22 min","level":"Advanced"},"de":{"title":"Murph-Hero-WOD — Komplette Demonstration","description":"Ein kompletter Durchlauf des Murph-WODs mit Strategietipps, Pacing und Aufteilung, um es zu schaffen.","duration":"22 Min","level":"Erfahren"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('crossfit', 5, array['j77_rHevrm4']::text[], 'pro', '{"fr":{"title":"Conseils live pour le Murph","description":"Stratégie détaillée pour le WOD Murph — partition optimale, gestion de l''énergie et tips pour se dépasser.","duration":"20 min","level":"Intermédiaire"},"en":{"title":"Live tips for the Murph","description":"Detailed strategy for the Murph WOD — optimal partitioning, energy management and tips to push through.","duration":"20 min","level":"Intermediate"},"de":{"title":"Live-Tipps für das Murph","description":"Detaillierte Strategie für das Murph-WOD — optimale Aufteilung, Energiemanagement und Tipps zum Durchhalten.","duration":"20 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_disciplines (slug, sort_order, color, icon, min_plan) values ('yoga', 6, 'lime', 'leaf', 'pro') on conflict (slug) do update set sort_order=excluded.sort_order, color=excluded.color, icon=excluded.icon, min_plan=excluded.min_plan, updated_at=now();
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('yoga', 'fr', '{"title":"Yoga","tag":"Bien-être","description":"Flexibilité, force intérieure et pleine conscience — des flows débutants au yoga avancé pour un corps et un esprit équilibrés.","stats":["+2 000 pratiquants","40+ séquences","20–60 min / séance"],"levels":["Débutant","Intermédiaire","Avancé","Tous niveaux"]}'::jsonb, '{"tagline":"Flexibilité, force intérieure et sérénité — sur et hors du tapis.","heroStat":"2 900+ pratiquants actifs","guide":{"technique":{"emoji":"🧘","title":"Technique & Alignement","items":["Alignement corporel : oreilles, épaules, hanches et chevilles dans le même axe en postures debout","Respiration ujjayi — souffle lent par le nez, gorge légèrement contractée, synchronisé avec chaque mouvement","Engage le bandha abdominal (uddiyana) pour protéger le bas du dos dans les flexions et extensions","Progression posturale : ne force jamais une posture — utilise des briques et sangles pour adapter l''amplitude","Maintiens chaque posture de 5 à 10 respirations — la tenue dans le temps est plus bénéfique que la profondeur"]},"equipment":{"emoji":"🛒","title":"Équipement recommandé","items":["Tapis antidérapant 4–6 mm (TPE ou caoutchouc naturel) — indispensable pour la stabilité et le confort articulaire","Deux briques yoga (liège ou mousse) pour adapter les postures à ta souplesse actuelle","Sangle de yoga pour les postures de flexion avant et d''ouverture des hanches","Bolster cylindrique pour le yoga restauratif et les postures de récupération passives","Vêtements ajustés et respirants (pas de vêtements trop amples qui gênent la vision de l''alignement)"]},"nutrition":{"emoji":"🥗","title":"Nutrition & Hydratation","items":["Pratique à jeun ou au moins 2h après un repas — l''estomac plein gêne les torsions et les inversions","Hydratation douce : bois 300–400 ml d''eau avant la séance, pas pendant les postures actives","Thé vert ou infusion gingembre-citron 30 min avant la pratique pour activer la digestion","Post-séance : repas léger riche en protéines végétales (lentilles, quinoa, tofu) pour la récupération","Évite sucre raffiné et alcool les jours de pratique intensive — ils amplifient l''inflammation"]},"recovery":{"emoji":"💆","title":"Récupération & Bien-être","items":["Savasana obligatoire 5–10 min à chaque fin de séance — c''est là que le corps intègre le travail","Yoga nidra (yoga du sommeil) 20 min remplace 1h de sommeil conventionnel selon les études","Auto-massage des pieds et des mollets avec balle de tennis après les séances en debout","Douche chaude post-pratique pour relâcher les tensions musculaires profondes","Journal de pratique : note tes ressentis après chaque séance pour suivre tes progrès subtils"]}},"tips":[{"icon":"🌬️","title":"Le souffle est roi","body":"Si tu perds le contrôle de ta respiration, tu as dépassé ta limite. La respiration guide la posture — jamais l''inverse."},{"icon":"📅","title":"Régularité > Durée","body":"20 minutes chaque jour transforment le corps en 4 semaines. Une heure une fois par semaine ne produit que peu de changements durables."},{"icon":"🧠","title":"Yoga = entraînement du cerveau","body":"Les études IRM montrent que 8 semaines de pratique régulière augmentent le volume du cortex préfrontal, réduisant l''anxiété de 40 %."},{"icon":"🔄","title":"Enchaîne yin et yang","body":"Alterne yoga dynamique (vinyasa, ashtanga) et yoga passif (yin, restauratif) dans la semaine pour équilibrer renforcement et récupération."}],"exercises":[{"name":"Chien tête en bas (Adho Mukha)","muscles":"Ischio-jambiers, mollets, épaules, dos","sets":"5 respirations","difficulty":"Débutant","description":"Depuis la planche, pousse les hanches vers le plafond en formant un V inversé. Talons vers le sol, dos allongé. Posture de référence qui étire et renforce simultanément."},{"name":"Guerrier I (Virabhadrasana I)","muscles":"Quadriceps, fessiers, fléchisseurs de hanche","sets":"5–8 respirations/côté","difficulty":"Débutant","description":"Pied avant à 90°, pied arrière à 45°, genou avant au-dessus de la cheville. Bras levés, épaules relâchées. Renforce les jambes et ouvre la poitrine."},{"name":"Guerrier II (Virabhadrasana II)","muscles":"Quadriceps, fessiers, abducteurs, épaules","sets":"5–8 respirations/côté","difficulty":"Débutant","description":"Pieds sur une même ligne, genou avant dans l''axe du pied. Bras horizontaux, regard au-dessus de la main avant. Développe la force des jambes et la concentration."},{"name":"Triangle (Trikonasana)","muscles":"Ischio-jambiers, obliques, fléchisseurs de hanche","sets":"5 respirations/côté","difficulty":"Intermédiaire","description":"Jambes écartées, buste incliné latéralement, main basse sur le tibia ou le sol. Torsion ouvrant la poitrine. Améliore la souplesse latérale et l''équilibre."},{"name":"Planche (Phalakasana)","muscles":"Abdominaux, épaules, fessiers, gainage global","sets":"3×30–60 s","difficulty":"Débutant","description":"Corps en ligne droite, poignets sous les épaules. Active les abdominaux, les fessiers et les jambes. La planche de yoga renforce sans comprimer les lombaires."},{"name":"Corbeau (Bakasana)","muscles":"Abdominaux, triceps, avant-bras, équilibre","sets":"3×5 respirations","difficulty":"Avancé","description":"Accroupi, pose les genoux sur les bras fléchis, incline le buste en avant et soulève les pieds. Renforce profondément le core et les bras. Posture d''équilibre emblématique."},{"name":"Posture de l''enfant (Balasana)","muscles":"Bas du dos, fessiers, épaules (étirement)","sets":"1–3 min","difficulty":"Tous niveaux","description":"Assis sur les talons, allonge les bras devant ou le long du corps. Relâche complètement le dos et les épaules. Posture de repos et de récupération entre les séquences."},{"name":"Demi-pont (Setu Bandha)","muscles":"Fessiers, ischio-jambiers, colonne vertébrale","sets":"3×10 respirations","difficulty":"Débutant","description":"Allongé sur le dos, genoux fléchis, pousse les hanches vers le plafond. Presse les pieds dans le sol. Ouvre la poitrine, renforce les fessiers et étire la colonne."},{"name":"Torsion assise (Ardha Matsyendrasana)","muscles":"Obliques, muscles paravertébraux, hanche","sets":"5 respirations/côté","difficulty":"Intermédiaire","description":"Assis au sol, pied d''une jambe posé à l''extérieur du genou opposé, torsion du buste. Détoxifie les organes abdominaux et améliore la mobilité thoracique."},{"name":"Équilibre sur une jambe (Vrksasana)","muscles":"Muscles stabilisateurs de la cheville, fessiers","sets":"5 respirations/côté","difficulty":"Débutant","description":"Debout sur une jambe, pied de l''autre posé sur le tibia ou la cuisse. Mains en prière ou bras levés. Développe la proprioception et la concentration mentale."}],"program":[{"week":"Semaine 1–2","theme":"Fondations — Postures de base","sessions":[{"name":"Flow débutant 30 min","detail":"Salutation au soleil A × 5, guerriers I & II, chien tête en bas, posture de l''enfant"},{"name":"Yin yoga 40 min","detail":"Papillon, demi-grenouille, torsion allongée — postures tenues 3–5 min chacune"},{"name":"Yoga du matin 20 min","detail":"Séquence réveil : chat-vache, chien tête en bas, fentes basses, demi-pont"}]},{"week":"Semaine 3–4","theme":"Renforcement & Équilibre","sessions":[{"name":"Vinyasa flow 45 min","detail":"Salutation au soleil B, guerrier III, triangle, planche latérale, chaturanga"},{"name":"Yoga core 30 min","detail":"Planche, bateau, demi-bateau, planche latérale, boat crunches — renforcement profond"},{"name":"Yoga restauratif 40 min","detail":"Postures soutenues par bolster/briques — libération des hanches et du bas du dos"},{"name":"Méditation assise 15 min","detail":"Pranayama (cohérence cardiaque 5/5) + balayage corporel — ancrage mental"}]},{"week":"Semaine 5–6","theme":"Inversions & Approfondissement","sessions":[{"name":"Yoga avancé — inversions 50 min","detail":"Prépa chandelle, demi-poirier contre le mur, corbeau, ouverture des épaules au sol"},{"name":"Ashtanga primary series partielle 60 min","detail":"Debout + assis jusqu''à navasana — practice dynamique et rigoureuse"},{"name":"Yin & restoratif 45 min","detail":"Postures yin passives longues pour compenser l''intensité du vinyasa"}]},{"week":"Semaine 7–8","theme":"Intégration & Autonomie","sessions":[{"name":"Pratique autonome 45 min","detail":"Crée ta propre séquence avec les postures apprises — cultive ton intelligence intuitive du mouvement"},{"name":"Atelier posture clé","detail":"Focus sur une posture avancée de ton choix : ouverture de hanche, inversion ou équilibre de bras"},{"name":"Yoga nidra 30 min","detail":"Relaxation profonde guidée — intégration complète du cycle de 8 semaines"},{"name":"Bilan souplesse & force","detail":"Test de flexion avant, équilibre unipodal, chaturanga max — mesure de la progression"}]}],"faq":[{"q":"Faut-il être souple pour faire du yoga ?","a":"Non — la raideur est justement la raison de commencer le yoga, pas un obstacle. Chaque posture est adaptable avec des accessoires (briques, sangle). La souplesse viendra avec la pratique."},{"q":"Quelle différence entre vinyasa, ashtanga et yin yoga ?","a":"Vinyasa est dynamique et créatif (lien souffle-mouvement). Ashtanga suit une séquence fixe, très structurée. Yin est passif et lent (postures tenues 3–5 min). Commence par le vinyasa ou le hatha pour un bon équilibre."},{"q":"À quelle fréquence pratiquer pour voir des résultats ?","a":"Minimum 3 séances/semaine de 30–45 min. Les changements de souplesse apparaissent en 3–4 semaines. Les bénéfices sur le stress et la qualité du sommeil souvent dès la première semaine."},{"q":"Le yoga peut-il remplacer la musculation ?","a":"Le yoga développe la force fonctionnelle, la mobilité et l''endurance musculaire — complémentaire mais différent. Des styles comme l''ashtanga ou le rocket yoga offrent un renforcement sérieux. L''idéal est de combiner les deux."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('yoga', 'en', '{"title":"Yoga","tag":"Wellness","description":"Flexibility, inner strength and mindfulness — from beginner flows to advanced yoga for a balanced body and mind.","stats":["+2,000 practitioners","40+ sequences","20–60 min / session"],"levels":["Beginner","Intermediate","Advanced","All levels"]}'::jsonb, '{"tagline":"Flexibility, inner strength and serenity — on and off the mat.","heroStat":"2,900+ active practitioners","guide":{"technique":{"emoji":"🧘","title":"Technique & Alignment","items":["Body alignment: ears, shoulders, hips and ankles in the same axis in standing poses","Ujjayi breathing — slow breath through the nose, throat slightly contracted, synced with each movement","Engage the abdominal bandha (uddiyana) to protect the lower back in flexions and extensions","Postural progression: never force a pose — use blocks and straps to adapt the range","Hold each pose for 5 to 10 breaths — holding over time is more beneficial than depth"]},"equipment":{"emoji":"🛒","title":"Recommended gear","items":["A non-slip mat 4–6 mm (TPE or natural rubber) — essential for stability and joint comfort","Two yoga blocks (cork or foam) to adapt poses to your current flexibility","A yoga strap for forward bends and hip-opening poses","A cylindrical bolster for restorative yoga and passive recovery poses","Fitted, breathable clothing (no baggy clothes that hide your alignment)"]},"nutrition":{"emoji":"🥗","title":"Nutrition & Hydration","items":["Practice fasted or at least 2h after a meal — a full stomach hinders twists and inversions","Gentle hydration: drink 300–400 ml of water before the session, not during active poses","Green tea or ginger-lemon infusion 30 min before practice to aid digestion","Post-session: a light meal rich in plant protein (lentils, quinoa, tofu) for recovery","Avoid refined sugar and alcohol on intensive practice days — they amplify inflammation"]},"recovery":{"emoji":"💆","title":"Recovery & Well-being","items":["Savasana is mandatory 5–10 min at the end of each session — that''s when the body integrates the work","Yoga nidra (sleep yoga) 20 min replaces 1h of conventional sleep according to studies","Self-massage the feet and calves with a tennis ball after standing sessions","A warm shower post-practice to release deep muscle tension","A practice journal: note how you feel after each session to track your subtle progress"]}},"tips":[{"icon":"🌬️","title":"The breath is king","body":"If you lose control of your breath, you''ve gone past your limit. The breath guides the pose — never the other way around."},{"icon":"📅","title":"Consistency > Duration","body":"20 minutes every day transform the body in 4 weeks. One hour once a week produces little lasting change."},{"icon":"🧠","title":"Yoga = brain training","body":"MRI studies show that 8 weeks of regular practice increase the volume of the prefrontal cortex, reducing anxiety by 40%."},{"icon":"🔄","title":"Alternate yin and yang","body":"Alternate dynamic yoga (vinyasa, ashtanga) and passive yoga (yin, restorative) during the week to balance strengthening and recovery."}],"exercises":[{"name":"Downward dog (Adho Mukha)","muscles":"Hamstrings, calves, shoulders, back","sets":"5 breaths","difficulty":"Beginner","description":"From the plank, push the hips toward the ceiling forming an inverted V. Heels toward the floor, back lengthened. A reference pose that stretches and strengthens at once."},{"name":"Warrior I (Virabhadrasana I)","muscles":"Quads, glutes, hip flexors","sets":"5–8 breaths/side","difficulty":"Beginner","description":"Front foot at 90°, back foot at 45°, front knee over the ankle. Arms raised, shoulders relaxed. Strengthens the legs and opens the chest."},{"name":"Warrior II (Virabhadrasana II)","muscles":"Quads, glutes, abductors, shoulders","sets":"5–8 breaths/side","difficulty":"Beginner","description":"Feet on one line, front knee in line with the foot. Arms horizontal, gaze over the front hand. Builds leg strength and focus."},{"name":"Triangle (Trikonasana)","muscles":"Hamstrings, obliques, hip flexors","sets":"5 breaths/side","difficulty":"Intermediate","description":"Legs wide, torso tilted laterally, lower hand on the shin or floor. A twist that opens the chest. Improves lateral flexibility and balance."},{"name":"Plank (Phalakasana)","muscles":"Abs, shoulders, glutes, full core","sets":"3×30–60 s","difficulty":"Beginner","description":"Body in a straight line, wrists under the shoulders. Engage the abs, glutes and legs. The yoga plank strengthens without compressing the lower back."},{"name":"Crow (Bakasana)","muscles":"Abs, triceps, forearms, balance","sets":"3×5 breaths","difficulty":"Advanced","description":"Squatting, place the knees on the bent arms, tilt the torso forward and lift the feet. Deeply strengthens the core and arms. An iconic balance pose."},{"name":"Child''s pose (Balasana)","muscles":"Lower back, glutes, shoulders (stretch)","sets":"1–3 min","difficulty":"All levels","description":"Sitting on the heels, extend the arms forward or alongside the body. Fully release the back and shoulders. A rest and recovery pose between sequences."},{"name":"Bridge (Setu Bandha)","muscles":"Glutes, hamstrings, spine","sets":"3×10 breaths","difficulty":"Beginner","description":"Lying on your back, knees bent, push the hips toward the ceiling. Press the feet into the floor. Opens the chest, strengthens the glutes and stretches the spine."},{"name":"Seated twist (Ardha Matsyendrasana)","muscles":"Obliques, paraspinal muscles, hip","sets":"5 breaths/side","difficulty":"Intermediate","description":"Sitting on the floor, one foot placed outside the opposite knee, twist the torso. Detoxifies the abdominal organs and improves thoracic mobility."},{"name":"Tree pose (Vrksasana)","muscles":"Ankle stabilizers, glutes","sets":"5 breaths/side","difficulty":"Beginner","description":"Standing on one leg, the other foot placed on the shin or thigh. Hands in prayer or arms raised. Builds proprioception and mental focus."}],"program":[{"week":"Week 1–2","theme":"Foundations — Basic poses","sessions":[{"name":"Beginner flow 30 min","detail":"Sun salutation A × 5, Warriors I & II, downward dog, child''s pose"},{"name":"Yin yoga 40 min","detail":"Butterfly, half-frog, reclined twist — poses held 3–5 min each"},{"name":"Morning yoga 20 min","detail":"Wake-up sequence: cat-cow, downward dog, low lunges, bridge"}]},{"week":"Week 3–4","theme":"Strengthening & Balance","sessions":[{"name":"Vinyasa flow 45 min","detail":"Sun salutation B, Warrior III, triangle, side plank, chaturanga"},{"name":"Core yoga 30 min","detail":"Plank, boat, half-boat, side plank, boat crunches — deep strengthening"},{"name":"Restorative yoga 40 min","detail":"Poses supported by bolster/blocks — release the hips and lower back"},{"name":"Seated meditation 15 min","detail":"Pranayama (5/5 heart coherence) + body scan — mental grounding"}]},{"week":"Week 5–6","theme":"Inversions & Deepening","sessions":[{"name":"Advanced yoga — inversions 50 min","detail":"Shoulderstand prep, half-headstand against the wall, crow, shoulder opening on the floor"},{"name":"Partial Ashtanga primary series 60 min","detail":"Standing + seated through navasana — dynamic, rigorous practice"},{"name":"Yin & restorative 45 min","detail":"Long passive yin poses to balance the intensity of the vinyasa"}]},{"week":"Week 7–8","theme":"Integration & Autonomy","sessions":[{"name":"Self-led practice 45 min","detail":"Create your own sequence with the poses learned — cultivate your intuitive sense of movement"},{"name":"Key-pose workshop","detail":"Focus on an advanced pose of your choice: hip opening, inversion or arm balance"},{"name":"Yoga nidra 30 min","detail":"Deep guided relaxation — full integration of the 8-week cycle"},{"name":"Flexibility & strength check","detail":"Forward-bend test, single-leg balance, max chaturanga — measure progress"}]}],"faq":[{"q":"Do I need to be flexible to do yoga?","a":"No — stiffness is precisely the reason to start yoga, not an obstacle. Every pose is adaptable with props (blocks, strap). Flexibility will come with practice."},{"q":"What''s the difference between vinyasa, ashtanga and yin yoga?","a":"Vinyasa is dynamic and creative (breath-movement link). Ashtanga follows a fixed, very structured sequence. Yin is passive and slow (poses held 3–5 min). Start with vinyasa or hatha for a good balance."},{"q":"How often should I practice to see results?","a":"At least 3 sessions/week of 30–45 min. Flexibility changes appear in 3–4 weeks. Benefits on stress and sleep quality often from the first week."},{"q":"Can yoga replace strength training?","a":"Yoga develops functional strength, mobility and muscular endurance — complementary but different. Styles like ashtanga or rocket yoga offer serious strengthening. The ideal is to combine both."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('yoga', 'de', '{"title":"Yoga","tag":"Wohlbefinden","description":"Flexibilität, innere Stärke und Achtsamkeit — von Anfänger-Flows bis zu fortgeschrittenem Yoga für einen ausgeglichenen Körper und Geist.","stats":["+2.000 Praktizierende","40+ Sequenzen","20–60 Min / Einheit"],"levels":["Anfänger","Fortgeschritten","Erfahren","Alle Niveaus"]}'::jsonb, '{"tagline":"Flexibilität, innere Stärke und Gelassenheit — auf und neben der Matte.","heroStat":"2.900+ aktive Praktizierende","guide":{"technique":{"emoji":"🧘","title":"Technik & Ausrichtung","items":["Körperausrichtung: Ohren, Schultern, Hüften und Knöchel in derselben Achse in stehenden Posen","Ujjayi-Atmung — langsamer Atem durch die Nase, Kehle leicht kontrahiert, mit jeder Bewegung synchronisiert","Aktiviere die Bauch-Bandha (Uddiyana), um den unteren Rücken bei Beugen und Streckungen zu schützen","Posturale Progression: erzwinge nie eine Pose — nutze Blöcke und Gurte, um den Umfang anzupassen","Halte jede Pose 5 bis 10 Atemzüge — das Halten über die Zeit ist sinnvoller als die Tiefe"]},"equipment":{"emoji":"🛒","title":"Empfohlene Ausrüstung","items":["Eine rutschfeste Matte 4–6 mm (TPE oder Naturkautschuk) — essenziell für Stabilität und Gelenkkomfort","Zwei Yoga-Blöcke (Kork oder Schaum), um Posen an deine aktuelle Flexibilität anzupassen","Ein Yoga-Gurt für Vorbeugen und hüftöffnende Posen","Ein zylindrisches Bolster für restoratives Yoga und passive Erholungsposen","Eng anliegende, atmungsaktive Kleidung (keine weite Kleidung, die deine Ausrichtung verbirgt)"]},"nutrition":{"emoji":"🥗","title":"Ernährung & Hydration","items":["Praktiziere nüchtern oder mindestens 2 h nach einer Mahlzeit — ein voller Magen behindert Drehungen und Umkehrhaltungen","Sanfte Hydration: trinke 300–400 ml Wasser vor der Einheit, nicht während aktiver Posen","Grüner Tee oder Ingwer-Zitronen-Aufguss 30 Min vor der Praxis zur Verdauungsförderung","Nach der Einheit: eine leichte Mahlzeit reich an pflanzlichem Protein (Linsen, Quinoa, Tofu) zur Erholung","Vermeide raffinierten Zucker und Alkohol an Tagen intensiver Praxis — sie verstärken Entzündungen"]},"recovery":{"emoji":"💆","title":"Erholung & Wohlbefinden","items":["Savasana ist Pflicht 5–10 Min am Ende jeder Einheit — dann integriert der Körper die Arbeit","Yoga Nidra (Schlaf-Yoga) 20 Min ersetzt laut Studien 1 h konventionellen Schlaf","Selbstmassage von Füßen und Waden mit einem Tennisball nach stehenden Einheiten","Eine warme Dusche nach der Praxis, um tiefe Muskelverspannungen zu lösen","Ein Praxistagebuch: notiere, wie du dich nach jeder Einheit fühlst, um deinen subtilen Fortschritt zu verfolgen"]}},"tips":[{"icon":"🌬️","title":"Der Atem ist König","body":"Wenn du die Kontrolle über deinen Atem verlierst, bist du über deine Grenze hinausgegangen. Der Atem führt die Pose — nie umgekehrt."},{"icon":"📅","title":"Beständigkeit > Dauer","body":"20 Minuten jeden Tag verwandeln den Körper in 4 Wochen. Eine Stunde einmal pro Woche bewirkt wenig dauerhafte Veränderung."},{"icon":"🧠","title":"Yoga = Gehirntraining","body":"MRT-Studien zeigen, dass 8 Wochen regelmäßige Praxis das Volumen des präfrontalen Kortex erhöhen und Angst um 40% reduzieren."},{"icon":"🔄","title":"Wechsle Yin und Yang","body":"Wechsle dynamisches Yoga (Vinyasa, Ashtanga) und passives Yoga (Yin, restorativ) während der Woche, um Stärkung und Erholung auszugleichen."}],"exercises":[{"name":"Herabschauender Hund (Adho Mukha)","muscles":"Beinbeuger, Waden, Schultern, Rücken","sets":"5 Atemzüge","difficulty":"Anfänger","description":"Aus der Plank schiebe die Hüften zur Decke und bilde ein umgekehrtes V. Fersen Richtung Boden, Rücken gelängt. Eine Referenzpose, die zugleich dehnt und stärkt."},{"name":"Krieger I (Virabhadrasana I)","muscles":"Quadrizeps, Gesäß, Hüftbeuger","sets":"5–8 Atemzüge/Seite","difficulty":"Anfänger","description":"Vorderer Fuß bei 90°, hinterer Fuß bei 45°, vorderes Knie über dem Knöchel. Arme erhoben, Schultern entspannt. Stärkt die Beine und öffnet die Brust."},{"name":"Krieger II (Virabhadrasana II)","muscles":"Quadrizeps, Gesäß, Abduktoren, Schultern","sets":"5–8 Atemzüge/Seite","difficulty":"Anfänger","description":"Füße auf einer Linie, vorderes Knie in Linie mit dem Fuß. Arme horizontal, Blick über die vordere Hand. Baut Beinkraft und Fokus auf."},{"name":"Dreieck (Trikonasana)","muscles":"Beinbeuger, schräge Bauchmuskeln, Hüftbeuger","sets":"5 Atemzüge/Seite","difficulty":"Fortgeschritten","description":"Beine weit, Oberkörper seitlich geneigt, untere Hand am Schienbein oder Boden. Eine Drehung, die die Brust öffnet. Verbessert seitliche Flexibilität und Gleichgewicht."},{"name":"Plank (Phalakasana)","muscles":"Bauch, Schultern, Gesäß, ganzer Rumpf","sets":"3×30–60 s","difficulty":"Anfänger","description":"Körper in gerader Linie, Handgelenke unter den Schultern. Spanne Bauch, Gesäß und Beine an. Die Yoga-Plank stärkt, ohne den unteren Rücken zu komprimieren."},{"name":"Krähe (Bakasana)","muscles":"Bauch, Trizeps, Unterarme, Gleichgewicht","sets":"3×5 Atemzüge","difficulty":"Erfahren","description":"In der Hocke setze die Knie auf die gebeugten Arme, neige den Oberkörper nach vorn und hebe die Füße. Stärkt Rumpf und Arme tief. Eine ikonische Balancepose."},{"name":"Stellung des Kindes (Balasana)","muscles":"Unterer Rücken, Gesäß, Schultern (Dehnung)","sets":"1–3 Min","difficulty":"Alle Niveaus","description":"Auf den Fersen sitzend strecke die Arme nach vorn oder neben den Körper. Löse Rücken und Schultern vollständig. Eine Ruhe- und Erholungspose zwischen Sequenzen."},{"name":"Brücke (Setu Bandha)","muscles":"Gesäß, Beinbeuger, Wirbelsäule","sets":"3×10 Atemzüge","difficulty":"Anfänger","description":"Auf dem Rücken liegend, Knie gebeugt, schiebe die Hüften zur Decke. Drücke die Füße in den Boden. Öffnet die Brust, stärkt das Gesäß und dehnt die Wirbelsäule."},{"name":"Sitzende Drehung (Ardha Matsyendrasana)","muscles":"Schräge Bauchmuskeln, Rückenstrecker, Hüfte","sets":"5 Atemzüge/Seite","difficulty":"Fortgeschritten","description":"Auf dem Boden sitzend, ein Fuß außerhalb des gegenüberliegenden Knies, drehe den Oberkörper. Entgiftet die Bauchorgane und verbessert die Brustwirbel-Mobilität."},{"name":"Baum (Vrksasana)","muscles":"Knöchelstabilisatoren, Gesäß","sets":"5 Atemzüge/Seite","difficulty":"Anfänger","description":"Auf einem Bein stehend, der andere Fuß am Schienbein oder Oberschenkel. Hände im Gebet oder Arme erhoben. Baut Propriozeption und mentalen Fokus auf."}],"program":[{"week":"Woche 1–2","theme":"Grundlagen — Basisposen","sessions":[{"name":"Anfänger-Flow 30 Min","detail":"Sonnengruß A × 5, Krieger I & II, herabschauender Hund, Kindspose"},{"name":"Yin Yoga 40 Min","detail":"Schmetterling, halber Frosch, liegende Drehung — Posen 3–5 Min je gehalten"},{"name":"Morgen-Yoga 20 Min","detail":"Aufwachsequenz: Katze-Kuh, herabschauender Hund, tiefe Ausfallschritte, Brücke"}]},{"week":"Woche 3–4","theme":"Stärkung & Gleichgewicht","sessions":[{"name":"Vinyasa-Flow 45 Min","detail":"Sonnengruß B, Krieger III, Dreieck, seitliche Plank, Chaturanga"},{"name":"Core-Yoga 30 Min","detail":"Plank, Boot, halbes Boot, seitliche Plank, Boot-Crunches — tiefe Stärkung"},{"name":"Restoratives Yoga 40 Min","detail":"Posen gestützt durch Bolster/Blöcke — Hüften und unteren Rücken lösen"},{"name":"Sitzmeditation 15 Min","detail":"Pranayama (5/5 Herzkohärenz) + Body Scan — mentale Erdung"}]},{"week":"Woche 5–6","theme":"Umkehrhaltungen & Vertiefung","sessions":[{"name":"Fortgeschrittenes Yoga — Umkehrhaltungen 50 Min","detail":"Schulterstand-Vorbereitung, halber Kopfstand an der Wand, Krähe, Schulteröffnung am Boden"},{"name":"Teilweise Ashtanga-Primärserie 60 Min","detail":"Stehend + sitzend bis Navasana — dynamische, rigorose Praxis"},{"name":"Yin & restorativ 45 Min","detail":"Lange passive Yin-Posen, um die Intensität des Vinyasa auszugleichen"}]},{"week":"Woche 7–8","theme":"Integration & Eigenständigkeit","sessions":[{"name":"Selbstgeführte Praxis 45 Min","detail":"Erstelle deine eigene Sequenz mit den gelernten Posen — kultiviere dein intuitives Bewegungsgefühl"},{"name":"Schlüsselposen-Workshop","detail":"Fokus auf eine fortgeschrittene Pose deiner Wahl: Hüftöffnung, Umkehrhaltung oder Armbalance"},{"name":"Yoga Nidra 30 Min","detail":"Tiefe geführte Entspannung — volle Integration des 8-Wochen-Zyklus"},{"name":"Flexibilitäts- & Kraft-Check","detail":"Vorbeuge-Test, einbeiniges Gleichgewicht, max. Chaturanga — Fortschritt messen"}]}],"faq":[{"q":"Muss ich flexibel sein, um Yoga zu machen?","a":"Nein — Steifheit ist genau der Grund, mit Yoga anzufangen, kein Hindernis. Jede Pose ist mit Hilfsmitteln (Blöcke, Gurt) anpassbar. Die Flexibilität kommt mit der Praxis."},{"q":"Was ist der Unterschied zwischen Vinyasa, Ashtanga und Yin Yoga?","a":"Vinyasa ist dynamisch und kreativ (Atem-Bewegungs-Verbindung). Ashtanga folgt einer festen, sehr strukturierten Sequenz. Yin ist passiv und langsam (Posen 3–5 Min gehalten). Starte mit Vinyasa oder Hatha für eine gute Balance."},{"q":"Wie oft sollte ich üben, um Ergebnisse zu sehen?","a":"Mindestens 3 Einheiten/Woche à 30–45 Min. Flexibilitätsveränderungen treten in 3–4 Wochen auf. Vorteile bei Stress und Schlafqualität oft schon ab der ersten Woche."},{"q":"Kann Yoga Krafttraining ersetzen?","a":"Yoga entwickelt funktionelle Kraft, Mobilität und Muskelausdauer — komplementär, aber anders. Stile wie Ashtanga oder Rocket Yoga bieten ernsthafte Stärkung. Ideal ist es, beides zu kombinieren."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('yoga', 0, array['v7AYKMP6rOE','e_OolrYHidY']::text[], 'pro', '{"fr":{"title":"Yoga débutant — 30 min flow","description":"Séquence yoga complète pour débutants — postures fondamentales, alignement et respiration guidés étape par étape.","duration":"30 min","level":"Débutant"},"en":{"title":"Beginner yoga — 30 min flow","description":"A complete yoga sequence for beginners — fundamental poses, alignment and breathing guided step by step.","duration":"30 min","level":"Beginner"},"de":{"title":"Anfänger-Yoga — 30-Min-Flow","description":"Eine komplette Yoga-Sequenz für Anfänger — fundamentale Posen, Ausrichtung und Atmung Schritt für Schritt geführt.","duration":"30 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('yoga', 1, array['2zCYsv4f4z0','AXcdWvE3GsA']::text[], 'pro', '{"fr":{"title":"Vinyasa flow 45 min","description":"Enchaînement vinyasa intermédiaire — lien souffle-mouvement, ouverture des hanches et renforcement du core.","duration":"45 min","level":"Intermédiaire"},"en":{"title":"Vinyasa flow 45 min","description":"An intermediate vinyasa flow — breath-movement link, hip opening and core strengthening.","duration":"45 min","level":"Intermediate"},"de":{"title":"Vinyasa-Flow 45 Min","description":"Ein Vinyasa-Flow für Fortgeschrittene — Atem-Bewegungs-Verbindung, Hüftöffnung und Rumpfkräftigung.","duration":"45 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('yoga', 2, array['4pKly2JojMw','5bNLz6nlkIo']::text[], 'pro', '{"fr":{"title":"Yoga du matin — Réveil en douceur","description":"Séquence matinale de 20 minutes pour éveiller le corps, activer l''énergie et préparer la journée.","duration":"20 min","level":"Tous niveaux"},"en":{"title":"Morning yoga — Gentle wake-up","description":"A 20-minute morning sequence to wake the body, activate energy and prepare for the day.","duration":"20 min","level":"All levels"},"de":{"title":"Morgen-Yoga — Sanftes Erwachen","description":"Eine 20-minütige Morgensequenz, um den Körper zu wecken, Energie zu aktivieren und sich auf den Tag vorzubereiten.","duration":"20 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('yoga', 3, array['VaoV1PrYft4','0Uoe4v1wsjc']::text[], 'pro', '{"fr":{"title":"Yin Yoga — Ouverture profonde","description":"Yin yoga 40 minutes axé sur les hanches et le bas du dos — postures tenues longtemps pour les fascias et ligaments.","duration":"40 min","level":"Tous niveaux"},"en":{"title":"Yin Yoga — Deep opening","description":"A 40-minute yin yoga focused on the hips and lower back — poses held long for the fascia and ligaments.","duration":"40 min","level":"All levels"},"de":{"title":"Yin Yoga — Tiefe Öffnung","description":"Ein 40-minütiges Yin Yoga mit Fokus auf Hüften und unteren Rücken — lange gehaltene Posen für Faszien und Bänder.","duration":"40 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
