insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('yoga', 5, array['UEP4HQ7_Eo0','x0to9WbMxrg','BCfzvOZ7rI4','vdMdqZ6slpM']::text[], 'pro', '{"fr":{"title":"Yoga du soir — Détente & sommeil","description":"Yoga restauratif 30 minutes pour se décompresser, relâcher les tensions de la journée et favoriser un sommeil profond.","duration":"30 min","level":"Débutant"},"en":{"title":"Evening yoga — Relax & sleep","description":"A 30-minute restorative yoga to decompress, release the tension of the day and promote deep sleep.","duration":"30 min","level":"Beginner"},"de":{"title":"Abend-Yoga — Entspannen & schlafen","description":"Ein 30-minütiges restoratives Yoga, um zu entspannen, die Spannung des Tages zu lösen und tiefen Schlaf zu fördern.","duration":"30 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_disciplines (slug, sort_order, color, icon, min_plan) values ('boxing', 7, 'orange', 'target', 'pro') on conflict (slug) do update set sort_order=excluded.sort_order, color=excluded.color, icon=excluded.icon, min_plan=excluded.min_plan, updated_at=now();
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('boxing', 'fr', '{"title":"Boxe","tag":"Combat","description":"Technique, cardio et puissance — des bases aux combinaisons avancées pour te transformer physiquement et mentalement.","stats":["+1 200 boxeurs","35+ programmes","8 semaines moy."],"levels":["Débutant","Intermédiaire","Avancé","Compétition"]}'::jsonb, '{"tagline":"Puissance, explosivité et maîtrise de soi — forgées sur le ring.","heroStat":"1 800+ boxeurs actifs","guide":{"technique":{"emoji":"🥊","title":"Technique & Garde","items":["Garde orthodoxe (gaucher en avant) ou southpaw (droitier en avant) — pied directeur détermine la garde naturelle","Position de base : pieds à largeur d''épaules + 45°, poids 55 % sur la jambe arrière pour la mobilité","Jab — coup direct du poing avant, bras tendu, épaule qui remonte pour protéger le menton","Cross — coup du poing arrière avec rotation complète des hanches — 70 % de la puissance vient de la rotation du bassin","Le mouvement de tête (slip, roll) est aussi important que les frappes — protège et crée les opportunités"]},"equipment":{"emoji":"🛒","title":"Équipement essentiel","items":["Gants de boxe (10–12 oz pour entraînement général, 16 oz pour sparring) — protège les poignets et les adversaires","Bandes de boxe 4,5 m — obligatoires sous les gants pour le soutien des poignets et des articulations","Protège-dents moulé sur mesure — protection n°1 contre les commotions et fractures dentaires","Sac de frappe (lourd 40–60 kg pour force, léger 20 kg pour vitesse et technique)","Corde à sauter — l''outil de cardio et de coordination le plus efficace de la boxe"]},"nutrition":{"emoji":"🥩","title":"Nutrition du boxeur","items":["Repas pré-entraînement 2h avant : riz + protéine maigre + légumes — energie stable sans lourdeur","Hydratation : minimum 600 ml d''eau par heure d''entraînement — la déshydratation ralentit les réflexes","Protéines : 2–2,2 g/kg/jour pour maintenir la masse musculaire en période de préparation","Gestion du poids : déficit calorique max 500 kcal/jour — les coupures de poids brutales réduisent la puissance de 15 %","Récupération : collagène + vitamine C post-séance pour la santé des poignets, coudes et épaules"]},"recovery":{"emoji":"💆","title":"Récupération du boxeur","items":["Glaçage poignets et articulations 10–15 min après chaque séance intense — prévention tendinite","Étirements actifs des épaules, pectoraux et fléchisseurs de hanche post-séance (10 min)","Rotation agoniste/antagoniste : jour frappe / jour jambes + core pour répartir la charge","Massage des avant-bras et de la nuque — zones les plus contractées lors de la boxe","Sommeil réparateur : les réflexes et la coordination se consolident pendant les phases de sommeil profond"]}},"tips":[{"icon":"⚡","title":"La puissance vient des hanches","body":"Un cross généré uniquement par le bras représente 30 % de la puissance maximale. Ajoute la rotation des hanches et du tronc pour atteindre 100 % de ton potentiel."},{"icon":"🧠","title":"Pense en combinaisons","body":"Un seul coup est facilement évitable. Les combinaisons (1-2, 1-1-2, 1-2-3b) créent des ouvertures. Maîtrise 3 combinaisons avant d''en apprendre de nouvelles."},{"icon":"🦶","title":"Le travail de jambes est la clé","body":"Un boxeur avec un mauvais travail de jambes ne peut pas attaquer ni défendre efficacement. Consacre 30 % de ton temps à la corde et aux déplacements."},{"icon":"🎯","title":"Qualité > Quantité sur le sac","body":"Frapper 100 coups propres vaut mieux que 500 coups bâclés. Chaque frappe sur le sac doit être précise, bien ancrée, avec retrait rapide des mains."}],"exercises":[{"name":"Corde à sauter","muscles":"Cardio, mollets, coordination, rythme","sets":"10×1 min / récup 30 s","difficulty":"Tous niveaux","description":"Saut simple en rythme constant, progresser vers double-under et crossover. L''outil fondamental de tout boxeur pour améliorer la coordination pied-main-oeil et le cardio."},{"name":"Shadow boxing","muscles":"Épaules, cardio, technique, coordination","sets":"5×3 min / 1 min repos","difficulty":"Débutant","description":"Boxe dans le vide en visualisant un adversaire. Travaille les combinaisons, les déplacements, les esquives et la fluidité. Séance technique par excellence."},{"name":"Sac lourd — combinaisons","muscles":"Épaules, pectoraux, triceps, core, cardio","sets":"6×3 min / 1 min repos","difficulty":"Intermédiaire","description":"Enchaîne des combinaisons prédéfinies (1-2, 1-2-3b, 1-2-lb) sur le sac lourd. Focus sur la qualité de frappe, le retrait rapide des mains et la rotation des hanches."},{"name":"Pompes boxeur","muscles":"Pectoraux, triceps, épaules, core","sets":"4×15","difficulty":"Intermédiaire","description":"Pompe classique avec rotation du buste et extension du bras en uppercut en fin de mouvement. Renforce les muscles de frappe tout en travaillant la coordination."},{"name":"Footwork en échelle","muscles":"Mollets, coordination, vitesse de réaction","sets":"3×4 passages","difficulty":"Débutant","description":"Utilise une échelle de coordination au sol pour travailler les pas de boxe (in-out, latéral, pivot). Améliore la vitesse de déplacement et l''équilibre dynamique en garde."},{"name":"Squat sauté avec crochet","muscles":"Quadriceps, fessiers, épaules, explosivité","sets":"4×10","difficulty":"Intermédiaire","description":"Descend en squat, explose vers le haut et envoie un crochet imaginaire en montant. Combine puissance des jambes et frappe — comme pour sortir d''un clinch et contre-attaquer."},{"name":"Gainage avec rotation (Russian twist)","muscles":"Obliques, abdominaux, rotation du tronc","sets":"3×20","difficulty":"Débutant","description":"Assis en V, pieds décollés, tourne le buste de droite à gauche en touchant le sol de chaque côté. La rotation du tronc est la source de puissance de tous les coups latéraux."},{"name":"Medicine ball slam","muscles":"Épaules, dos, abdominaux, explosivité","sets":"4×12","difficulty":"Intermédiaire","description":"Lève le médecine ball à bout de bras puis projette-le violemment au sol. Simule la puissance d''un overhand ou d''un coup de tête. Excellent pour l''explosivité du haut du corps."},{"name":"Défense aux mitaines","muscles":"Réflexes, coordination, cardio","sets":"4×3 min","difficulty":"Avancé","description":"Face au partenaire tenant les mitaines, travaille frappe-esquive alternée. Développe la vision périphérique, la vitesse de réaction et l''adaptation tactique en temps réel."}],"program":[{"week":"Semaine 1–2","theme":"Fondations — Garde et coups de base","sessions":[{"name":"Technique débutant 45 min","detail":"Garde, jab, cross, déplacements latéraux + 10 min corde à sauter basique"},{"name":"Cardio boxe 30 min","detail":"Shadow boxing 3×3 min + sac léger combinaisons simples (1-2) 4×2 min"},{"name":"Conditioning athlétique 40 min","detail":"Corde 5 min + pompes 4×15 + squat 4×15 + gainage 3×45 s + étirements"}]},{"week":"Semaine 3–4","theme":"Combinaisons & Cardio boxing","sessions":[{"name":"Mitaines / sac — combinaisons","detail":"10 combinaisons différentes en rotation sur sac lourd — 6×3 min avec 1 min repos"},{"name":"Sparring léger (si partenaire)","detail":"4×2 min de sparring technique à 50 % — focus déplacements et jab uniquement"},{"name":"HIIT boxe 25 min","detail":"Shadow boxing 30 s / repos 15 s × 10, puis burpees boxeur 20 s / 10 s × 10"},{"name":"Renforcement fonctionnel","detail":"Medicine ball slam 4×12 + Russian twist 3×20 + pompes boxeur 4×15"}]},{"week":"Semaine 5–6","theme":"Puissance & Défense","sessions":[{"name":"Séance puissance sac lourd","detail":"Travail de puissance maximale : 5×3 min avec focus cross et uppercut à intensité maximale"},{"name":"Esquives et contre-attaques","detail":"Slip/roll en réponse aux jabs du partenaire + contre 1-2 immédiat — 6×2 min"},{"name":"Cardio endurance 40 min","detail":"Corde 15 min + shadow boxing 15 min + sac 10 min — intensité modérée continue"}]},{"week":"Semaine 7–8","theme":"Sparring & Consolidation","sessions":[{"name":"Sparring complet 4×3 min","detail":"Application tactique complète — tous les coups et esquives appris en situation réelle"},{"name":"Affûtage technique 45 min","detail":"Retour aux fondamentaux : garde, jab, déplacements — affiner la précision et la fluidité"},{"name":"Bilan performance","detail":"Test corde à sauter max 3 min + test frappe puissance sur sac avec capteur + évaluation technique"},{"name":"Récupération active","detail":"Yoga 30 min + étirements profonds épaules et poignets + auto-massage bras"}]}],"faq":[{"q":"La boxe est-elle dangereuse pour les débutants ?","a":"L''entraînement boxe fitness (sac, shadow, mitaines) est très sûr et sans contact. Le sparring nécessite un équipement complet et un entraîneur compétent. La boxe développe la self-défense et la confiance en soi."},{"q":"Combien de temps pour apprendre les bases ?","a":"En 4 semaines de pratique régulière (3 séances/sem), tu maîtrises la garde, le jab, le cross et les déplacements de base. Les combinaisons et la défense nécessitent 3–6 mois."},{"q":"La boxe fait-elle perdre du poids efficacement ?","a":"Oui — une séance de boxe de 45 min brûle entre 500 et 800 kcal selon l''intensité. C''est l''un des sports les plus efficaces pour la dépense calorique totale grâce à l''implication du corps entier."},{"q":"Faut-il un partenaire pour s''entraîner à la boxe ?","a":"Non — sac de frappe, shadow boxing et corde à sauter permettent un entraînement complet en solo. Le partenaire est un plus (mitaines, sparring) mais pas une nécessité, surtout au début."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('boxing', 'en', '{"title":"Boxing","tag":"Combat","description":"Technique, cardio and power — from the basics to advanced combinations to transform you physically and mentally.","stats":["+1,200 boxers","35+ programs","8 weeks avg."],"levels":["Beginner","Intermediate","Advanced","Competition"]}'::jsonb, '{"tagline":"Power, explosiveness and self-control — forged in the ring.","heroStat":"1,800+ active boxers","guide":{"technique":{"emoji":"🥊","title":"Technique & Guard","items":["Orthodox stance (left foot forward) or southpaw (right foot forward) — your dominant foot determines the natural stance","Base position: feet shoulder-width + 45°, 55% of the weight on the back leg for mobility","Jab — straight punch with the lead hand, arm extended, shoulder raised to protect the chin","Cross — rear-hand punch with full hip rotation — 70% of the power comes from the hip turn","Head movement (slip, roll) is as important as punching — it protects and creates openings"]},"equipment":{"emoji":"🛒","title":"Essential equipment","items":["Boxing gloves (10–12 oz for general training, 16 oz for sparring) — protects the wrists and your partners","Hand wraps 4.5 m — mandatory under the gloves for wrist and joint support","A custom-molded mouthguard — the #1 protection against concussions and dental fractures","A punching bag (heavy 40–60 kg for power, light 20 kg for speed and technique)","A jump rope — the most effective cardio and coordination tool in boxing"]},"nutrition":{"emoji":"🥩","title":"Boxer''s nutrition","items":["Pre-training meal 2h before: rice + lean protein + vegetables — stable energy without heaviness","Hydration: at least 600 ml of water per hour of training — dehydration slows the reflexes","Protein: 2–2.2 g/kg/day to maintain muscle mass during a training block","Weight management: max 500 kcal/day deficit — sharp weight cuts reduce power by 15%","Recovery: collagen + vitamin C post-session for the health of wrists, elbows and shoulders"]},"recovery":{"emoji":"💆","title":"Boxer''s recovery","items":["Ice the wrists and joints 10–15 min after every intense session — tendinitis prevention","Active stretching of the shoulders, pecs and hip flexors post-session (10 min)","Agonist/antagonist rotation: punch day / legs + core day to spread the load","Massage the forearms and the back of the neck — the most contracted areas in boxing","Restorative sleep: reflexes and coordination consolidate during deep-sleep phases"]}},"tips":[{"icon":"⚡","title":"Power comes from the hips","body":"A cross generated by the arm alone is 30% of maximum power. Add hip and trunk rotation to reach 100% of your potential."},{"icon":"🧠","title":"Think in combinations","body":"A single punch is easily avoided. Combinations (1-2, 1-1-2, 1-2-3b) create openings. Master 3 combinations before learning new ones."},{"icon":"🦶","title":"Footwork is the key","body":"A boxer with poor footwork can''t attack or defend effectively. Spend 30% of your time on the rope and on movement."},{"icon":"🎯","title":"Quality > Quantity on the bag","body":"Landing 100 clean punches beats 500 sloppy ones. Every strike on the bag must be precise, well-anchored, with a fast hand return."}],"exercises":[{"name":"Jump rope","muscles":"Cardio, calves, coordination, rhythm","sets":"10×1 min / 30 s rest","difficulty":"All levels","description":"Single jumps at a steady rhythm, progressing to double-unders and crossovers. The fundamental tool of every boxer to improve foot-hand-eye coordination and cardio."},{"name":"Shadow boxing","muscles":"Shoulders, cardio, technique, coordination","sets":"5×3 min / 1 min rest","difficulty":"Beginner","description":"Box in the air visualizing an opponent. Work combinations, footwork, slips and fluidity. The technical session par excellence."},{"name":"Heavy bag — combinations","muscles":"Shoulders, pecs, triceps, core, cardio","sets":"6×3 min / 1 min rest","difficulty":"Intermediate","description":"Chain preset combinations (1-2, 1-2-3b, 1-2-lb) on the heavy bag. Focus on strike quality, fast hand return and hip rotation."},{"name":"Boxer push-ups","muscles":"Pecs, triceps, shoulders, core","sets":"4×15","difficulty":"Intermediate","description":"A classic push-up with a torso rotation and arm extension into an uppercut at the end. Strengthens the striking muscles while training coordination."},{"name":"Ladder footwork","muscles":"Calves, coordination, reaction speed","sets":"3×4 runs","difficulty":"Beginner","description":"Use an agility ladder on the floor to work boxing steps (in-out, lateral, pivot). Improves movement speed and dynamic balance in your guard."},{"name":"Jump squat with hook","muscles":"Quads, glutes, shoulders, explosiveness","sets":"4×10","difficulty":"Intermediate","description":"Drop into a squat, explode upward and throw an imaginary hook on the way up. Combines leg power and striking — like coming out of a clinch and countering."},{"name":"Russian twist","muscles":"Obliques, abs, trunk rotation","sets":"3×20","difficulty":"Beginner","description":"Seated in a V, feet lifted, rotate the torso right to left touching the floor on each side. Trunk rotation is the power source of every lateral punch."},{"name":"Medicine ball slam","muscles":"Shoulders, back, abs, explosiveness","sets":"4×12","difficulty":"Intermediate","description":"Lift the medicine ball overhead then slam it violently to the floor. Mimics the power of an overhand. Excellent for upper-body explosiveness."},{"name":"Pad defense","muscles":"Reflexes, coordination, cardio","sets":"4×3 min","difficulty":"Advanced","description":"Facing a partner holding the pads, work alternating strike-slip. Develops peripheral vision, reaction speed and real-time tactical adaptation."}],"program":[{"week":"Week 1–2","theme":"Foundations — Guard and basic punches","sessions":[{"name":"Beginner technique 45 min","detail":"Guard, jab, cross, lateral movement + 10 min basic jump rope"},{"name":"Boxing cardio 30 min","detail":"Shadow boxing 3×3 min + light bag simple combos (1-2) 4×2 min"},{"name":"Athletic conditioning 40 min","detail":"Rope 5 min + push-ups 4×15 + squat 4×15 + core 3×45 s + stretching"}]},{"week":"Week 3–4","theme":"Combinations & Boxing cardio","sessions":[{"name":"Pads / bag — combinations","detail":"10 different combinations rotating on the heavy bag — 6×3 min with 1 min rest"},{"name":"Light sparring (if partner)","detail":"4×2 min of technical sparring at 50% — focus on footwork and jab only"},{"name":"Boxing HIIT 25 min","detail":"Shadow boxing 30 s / 15 s rest × 10, then boxer burpees 20 s / 10 s × 10"},{"name":"Functional strengthening","detail":"Medicine ball slam 4×12 + Russian twist 3×20 + boxer push-ups 4×15"}]},{"week":"Week 5–6","theme":"Power & Defense","sessions":[{"name":"Heavy-bag power session","detail":"Maximal power work: 5×3 min focusing on cross and uppercut at max intensity"},{"name":"Slips and counters","detail":"Slip/roll in response to the partner''s jabs + immediate 1-2 counter — 6×2 min"},{"name":"Endurance cardio 40 min","detail":"Rope 15 min + shadow boxing 15 min + bag 10 min — moderate continuous intensity"}]},{"week":"Week 7–8","theme":"Sparring & Consolidation","sessions":[{"name":"Full sparring 4×3 min","detail":"Full tactical application — all punches and slips learned in a real situation"},{"name":"Technical sharpening 45 min","detail":"Back to the fundamentals: guard, jab, footwork — refine precision and fluidity"},{"name":"Performance check","detail":"Max 3-min jump-rope test + punching-power test with a sensor + technical assessment"},{"name":"Active recovery","detail":"Yoga 30 min + deep shoulder and wrist stretching + arm self-massage"}]}],"faq":[{"q":"Is boxing dangerous for beginners?","a":"Fitness boxing training (bag, shadow, pads) is very safe and contactless. Sparring requires full gear and a competent coach. Boxing builds self-defense and self-confidence."},{"q":"How long to learn the basics?","a":"In 4 weeks of regular practice (3 sessions/week), you master the guard, jab, cross and basic footwork. Combinations and defense take 3–6 months."},{"q":"Does boxing burn fat effectively?","a":"Yes — a 45-min boxing session burns between 500 and 800 kcal depending on intensity. It''s one of the most effective sports for total caloric expenditure thanks to full-body involvement."},{"q":"Do I need a partner to train boxing?","a":"No — a punching bag, shadow boxing and jump rope allow a complete solo workout. A partner is a plus (pads, sparring) but not a necessity, especially at the start."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('boxing', 'de', '{"title":"Boxen","tag":"Kampf","description":"Technik, Cardio und Kraft — von den Grundlagen bis zu fortgeschrittenen Kombinationen, um dich körperlich und mental zu transformieren.","stats":["+1.200 Boxer","35+ Programme","Ø 8 Wochen"],"levels":["Anfänger","Fortgeschritten","Erfahren","Wettkampf"]}'::jsonb, '{"tagline":"Kraft, Explosivität und Selbstkontrolle — im Ring geschmiedet.","heroStat":"1.800+ aktive Boxer","guide":{"technique":{"emoji":"🥊","title":"Technik & Deckung","items":["Orthodoxe Auslage (linker Fuß vorn) oder Southpaw (rechter Fuß vorn) — dein dominanter Fuß bestimmt die natürliche Auslage","Grundposition: Füße schulterbreit + 45°, 55% des Gewichts auf dem hinteren Bein für Mobilität","Jab — gerader Schlag mit der Führhand, Arm gestreckt, Schulter angehoben zum Schutz des Kinns","Cross — Schlag mit der hinteren Hand mit voller Hüftrotation — 70% der Kraft kommt aus der Hüftdrehung","Kopfbewegung (Slip, Roll) ist so wichtig wie das Schlagen — sie schützt und schafft Öffnungen"]},"equipment":{"emoji":"🛒","title":"Essenzielle Ausrüstung","items":["Boxhandschuhe (10–12 oz für allgemeines Training, 16 oz für Sparring) — schützt Handgelenke und Partner","Handbandagen 4,5 m — Pflicht unter den Handschuhen zur Stütze von Handgelenk und Gelenken","Ein individuell angepasster Mundschutz — der Schutz Nr. 1 gegen Gehirnerschütterungen und Zahnfrakturen","Ein Boxsack (schwer 40–60 kg für Kraft, leicht 20 kg für Schnelligkeit und Technik)","Ein Springseil — das effektivste Cardio- und Koordinationstool im Boxen"]},"nutrition":{"emoji":"🥩","title":"Ernährung des Boxers","items":["Mahlzeit vor dem Training 2 h vorher: Reis + mageres Protein + Gemüse — stabile Energie ohne Schwere","Hydration: mindestens 600 ml Wasser pro Trainingsstunde — Dehydrierung verlangsamt die Reflexe","Protein: 2–2,2 g/kg/Tag, um die Muskelmasse während eines Trainingsblocks zu erhalten","Gewichtsmanagement: max. 500 kcal/Tag Defizit — scharfe Gewichtsreduktionen senken die Kraft um 15%","Erholung: Kollagen + Vitamin C nach der Einheit für die Gesundheit von Handgelenken, Ellbogen und Schultern"]},"recovery":{"emoji":"💆","title":"Erholung des Boxers","items":["Kühle Handgelenke und Gelenke 10–15 Min nach jeder intensiven Einheit — Tendinitis-Prävention","Aktives Dehnen von Schultern, Brust und Hüftbeugern nach der Einheit (10 Min)","Agonist/Antagonist-Rotation: Schlagtag / Bein- + Rumpftag, um die Last zu verteilen","Massiere die Unterarme und den Nacken — die im Boxen am stärksten verspannten Bereiche","Erholsamer Schlaf: Reflexe und Koordination festigen sich in den Tiefschlafphasen"]}},"tips":[{"icon":"⚡","title":"Kraft kommt aus der Hüfte","body":"Ein nur vom Arm erzeugter Cross sind 30% der Maximalkraft. Füge Hüft- und Rumpfrotation hinzu, um 100% deines Potenzials zu erreichen."},{"icon":"🧠","title":"Denke in Kombinationen","body":"Ein einzelner Schlag wird leicht ausgewichen. Kombinationen (1-2, 1-1-2, 1-2-3b) schaffen Öffnungen. Beherrsche 3 Kombinationen, bevor du neue lernst."},{"icon":"🦶","title":"Beinarbeit ist der Schlüssel","body":"Ein Boxer mit schlechter Beinarbeit kann weder effektiv angreifen noch verteidigen. Verbringe 30% deiner Zeit am Seil und mit Bewegung."},{"icon":"🎯","title":"Qualität > Quantität am Sack","body":"100 saubere Treffer zu landen schlägt 500 schludrige. Jeder Schlag am Sack muss präzise, gut verankert sein, mit schneller Handrückführung."}],"exercises":[{"name":"Seilspringen","muscles":"Cardio, Waden, Koordination, Rhythmus","sets":"10×1 Min / 30 s Pause","difficulty":"Alle Niveaus","description":"Einfache Sprünge in gleichmäßigem Rhythmus, fortschreitend zu Double-Unders und Crossovers. Das fundamentale Werkzeug jedes Boxers zur Verbesserung von Fuß-Hand-Auge-Koordination und Cardio."},{"name":"Schattenboxen","muscles":"Schultern, Cardio, Technik, Koordination","sets":"5×3 Min / 1 Min Pause","difficulty":"Anfänger","description":"Boxe in die Luft und visualisiere einen Gegner. Arbeite an Kombinationen, Beinarbeit, Slips und Flüssigkeit. Die technische Einheit schlechthin."},{"name":"Schwersack — Kombinationen","muscles":"Schultern, Brust, Trizeps, Rumpf, Cardio","sets":"6×3 Min / 1 Min Pause","difficulty":"Fortgeschritten","description":"Verkette voreingestellte Kombinationen (1-2, 1-2-3b, 1-2-lb) am Schwersack. Fokus auf Schlagqualität, schnelle Handrückführung und Hüftrotation."},{"name":"Boxer-Liegestütze","muscles":"Brust, Trizeps, Schultern, Rumpf","sets":"4×15","difficulty":"Fortgeschritten","description":"Ein klassischer Liegestütz mit einer Oberkörperrotation und Armstreckung in einen Uppercut am Ende. Stärkt die Schlagmuskeln und trainiert die Koordination."},{"name":"Leiter-Beinarbeit","muscles":"Waden, Koordination, Reaktionsgeschwindigkeit","sets":"3×4 Durchläufe","difficulty":"Anfänger","description":"Nutze eine Koordinationsleiter am Boden für Boxschritte (rein-raus, seitlich, Pivot). Verbessert die Bewegungsgeschwindigkeit und das dynamische Gleichgewicht in deiner Deckung."},{"name":"Jump Squat mit Haken","muscles":"Quadrizeps, Gesäß, Schultern, Explosivität","sets":"4×10","difficulty":"Fortgeschritten","description":"Geh in die Kniebeuge, explodiere nach oben und wirf beim Hochkommen einen imaginären Haken. Kombiniert Beinkraft und Schlagen — wie aus einem Clinch zu kommen und zu kontern."},{"name":"Russian Twist","muscles":"Schräge Bauchmuskeln, Bauch, Rumpfrotation","sets":"3×20","difficulty":"Anfänger","description":"Im V sitzend, Füße angehoben, drehe den Oberkörper rechts nach links und berühre bei jeder Seite den Boden. Die Rumpfrotation ist die Kraftquelle jedes seitlichen Schlags."},{"name":"Medizinball-Slam","muscles":"Schultern, Rücken, Bauch, Explosivität","sets":"4×12","difficulty":"Fortgeschritten","description":"Hebe den Medizinball über den Kopf und schlage ihn dann heftig auf den Boden. Simuliert die Kraft eines Overhands. Exzellent für Oberkörper-Explosivität."},{"name":"Pratzen-Verteidigung","muscles":"Reflexe, Koordination, Cardio","sets":"4×3 Min","difficulty":"Erfahren","description":"Gegenüber einem Partner, der die Pratzen hält, arbeite abwechselnd Schlag-Slip. Entwickelt peripheres Sehen, Reaktionsgeschwindigkeit und taktische Anpassung in Echtzeit."}],"program":[{"week":"Woche 1–2","theme":"Grundlagen — Deckung und Basisschläge","sessions":[{"name":"Anfänger-Technik 45 Min","detail":"Deckung, Jab, Cross, Seitwärtsbewegung + 10 Min Basis-Seilspringen"},{"name":"Box-Cardio 30 Min","detail":"Schattenboxen 3×3 Min + leichter Sack einfache Kombos (1-2) 4×2 Min"},{"name":"Athletisches Konditionieren 40 Min","detail":"Seil 5 Min + Liegestütze 4×15 + Kniebeuge 4×15 + Rumpf 3×45 s + Dehnen"}]},{"week":"Woche 3–4","theme":"Kombinationen & Box-Cardio","sessions":[{"name":"Pratzen / Sack — Kombinationen","detail":"10 verschiedene Kombinationen rotierend am Schwersack — 6×3 Min mit 1 Min Pause"},{"name":"Leichtes Sparring (wenn Partner)","detail":"4×2 Min technisches Sparring bei 50% — Fokus nur auf Beinarbeit und Jab"},{"name":"Box-HIIT 25 Min","detail":"Schattenboxen 30 s / 15 s Pause × 10, dann Boxer-Burpees 20 s / 10 s × 10"},{"name":"Funktionelle Stärkung","detail":"Medizinball-Slam 4×12 + Russian Twist 3×20 + Boxer-Liegestütze 4×15"}]},{"week":"Woche 5–6","theme":"Kraft & Verteidigung","sessions":[{"name":"Schwersack-Kraft-Einheit","detail":"Maximale Kraftarbeit: 5×3 Min Fokus auf Cross und Uppercut bei max. Intensität"},{"name":"Slips und Konter","detail":"Slip/Roll als Antwort auf die Jabs des Partners + sofortiger 1-2-Konter — 6×2 Min"},{"name":"Ausdauer-Cardio 40 Min","detail":"Seil 15 Min + Schattenboxen 15 Min + Sack 10 Min — moderate durchgehende Intensität"}]},{"week":"Woche 7–8","theme":"Sparring & Festigung","sessions":[{"name":"Volles Sparring 4×3 Min","detail":"Volle taktische Anwendung — alle gelernten Schläge und Slips in einer realen Situation"},{"name":"Technisches Schärfen 45 Min","detail":"Zurück zu den Grundlagen: Deckung, Jab, Beinarbeit — Präzision und Flüssigkeit verfeinern"},{"name":"Leistungs-Check","detail":"Max. 3-Min-Seilspring-Test + Schlagkraft-Test mit Sensor + technische Bewertung"},{"name":"Aktive Erholung","detail":"Yoga 30 Min + tiefes Schulter- und Handgelenk-Dehnen + Arm-Selbstmassage"}]}],"faq":[{"q":"Ist Boxen für Anfänger gefährlich?","a":"Box-Fitnesstraining (Sack, Schatten, Pratzen) ist sehr sicher und kontaktlos. Sparring erfordert volle Ausrüstung und einen kompetenten Coach. Boxen baut Selbstverteidigung und Selbstvertrauen auf."},{"q":"Wie lange, um die Grundlagen zu lernen?","a":"In 4 Wochen regelmäßiger Praxis (3 Einheiten/Woche) beherrschst du Deckung, Jab, Cross und Basis-Beinarbeit. Kombinationen und Verteidigung brauchen 3–6 Monate."},{"q":"Verbrennt Boxen effektiv Fett?","a":"Ja — eine 45-Min-Box-Einheit verbrennt je nach Intensität zwischen 500 und 800 kcal. Dank der Ganzkörperbeteiligung ist es eine der effektivsten Sportarten für den gesamten Kalorienverbrauch."},{"q":"Brauche ich einen Partner, um zu boxen?","a":"Nein — ein Boxsack, Schattenboxen und Springseil ermöglichen ein komplettes Solo-Workout. Ein Partner ist ein Plus (Pratzen, Sparring), aber keine Notwendigkeit, besonders am Anfang."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('boxing', 0, array['kKDHdsVN0b8','jhcIjFgz2bI','N0U5RPGpjSg']::text[], 'pro', '{"fr":{"title":"Boxe débutant — Bases techniques","description":"Initiation complète à la boxe — garde, jab, cross, crochet et uppercut expliqués pour les débutants absolus.","duration":"25 min","level":"Débutant"},"en":{"title":"Beginner boxing — Technical basics","description":"A complete intro to boxing — guard, jab, cross, hook and uppercut explained for absolute beginners.","duration":"25 min","level":"Beginner"},"de":{"title":"Anfänger-Boxen — Technische Grundlagen","description":"Eine komplette Einführung ins Boxen — Deckung, Jab, Cross, Haken und Uppercut für absolute Anfänger erklärt.","duration":"25 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('boxing', 1, array['93r6lz1pbcw','NWEThzMnLq8']::text[], 'pro', '{"fr":{"title":"Combinaisons de boxe — Intermédiaire","description":"Apprentissage de 10 combinaisons essentielles avec travail sur sac et mitaines — progression garantie.","duration":"30 min","level":"Intermédiaire"},"en":{"title":"Boxing combinations — Intermediate","description":"Learn 10 essential combinations with bag and pad work — guaranteed progress.","duration":"30 min","level":"Intermediate"},"de":{"title":"Box-Kombinationen — Fortgeschritten","description":"Lerne 10 essenzielle Kombinationen mit Sack- und Pratzenarbeit — garantierter Fortschritt.","duration":"30 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('boxing', 2, array['4hYDno0aaAI','bcupGtFmv7k']::text[], 'pro', '{"fr":{"title":"Séance shadow boxing 20 min","description":"Entraînement shadow boxing complet — mouvement de jambes, combinaisons, esquives et visualisation de l''adversaire.","duration":"20 min","level":"Tous niveaux"},"en":{"title":"20-min shadow boxing session","description":"A complete shadow boxing workout — footwork, combinations, slips and visualizing the opponent.","duration":"20 min","level":"All levels"},"de":{"title":"20-Min-Schattenboxen-Einheit","description":"Ein komplettes Schattenbox-Workout — Beinarbeit, Kombinationen, Slips und Visualisieren des Gegners.","duration":"20 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('boxing', 3, array['l6Kvp6OZhEA','cpRoLtQaCu0']::text[], 'pro', '{"fr":{"title":"Cardio boxe — Brûle-graisses intense","description":"Circuit cardio boxe de 35 minutes — combinaisons, footwork et exercices athlétiques pour une condition physique optimale.","duration":"35 min","level":"Intermédiaire"},"en":{"title":"Boxing cardio — Intense fat burner","description":"A 35-minute boxing cardio circuit — combinations, footwork and athletic drills for optimal fitness.","duration":"35 min","level":"Intermediate"},"de":{"title":"Box-Cardio — Intensiver Fettverbrenner","description":"Ein 35-minütiger Box-Cardio-Circuit — Kombinationen, Beinarbeit und athletische Drills für optimale Fitness.","duration":"35 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('boxing', 4, array['F7dRCzMDgXA','moQUBT4QUWs']::text[], 'pro', '{"fr":{"title":"Travail de tête et esquives","description":"Maîtrise le slip, le roll et le bob & weave — les mouvements défensifs qui séparent les bons boxeurs des grands.","duration":"22 min","level":"Intermédiaire"},"en":{"title":"Head movement and slips","description":"Master the slip, the roll and the bob & weave — the defensive moves that separate good boxers from great ones.","duration":"22 min","level":"Intermediate"},"de":{"title":"Kopfbewegung und Slips","description":"Beherrsche den Slip, den Roll und das Bob & Weave — die Defensivbewegungen, die gute von großartigen Boxern trennen.","duration":"22 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('boxing', 5, array['bb1yVrGe3VU','D8DouKeOkfI']::text[], 'pro', '{"fr":{"title":"Puissance de frappe — Niveau avancé","description":"Développe ta puissance maximale avec des exercices de plyométrie, de rotation et de frappe lourde sur sac.","duration":"40 min","level":"Avancé"},"en":{"title":"Punching power — Advanced level","description":"Develop your maximum power with plyometric, rotational and heavy-bag striking drills.","duration":"40 min","level":"Advanced"},"de":{"title":"Schlagkraft — Erfahren-Niveau","description":"Entwickle deine Maximalkraft mit plyometrischen, rotatorischen und Schwersack-Schlagdrills.","duration":"40 Min","level":"Erfahren"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_disciplines (slug, sort_order, color, icon, min_plan) values ('stretching', 8, 'blue', 'layers', 'pro') on conflict (slug) do update set sort_order=excluded.sort_order, color=excluded.color, icon=excluded.icon, min_plan=excluded.min_plan, updated_at=now();
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('stretching', 'fr', '{"title":"Stretching","tag":"Mobilité","description":"Mobilité, souplesse et récupération optimale — des routines d''étirements guidées pour prévenir les blessures et performer.","stats":["+1 600 membres","30+ routines","10–30 min / séance"],"levels":["Débutant","Intermédiaire","Avancé","Tous niveaux"]}'::jsonb, '{"tagline":"Libère ton corps, récupère mieux et bougez sans douleur.","heroStat":"3 200+ pratiquants actifs","guide":{"technique":{"emoji":"🤸","title":"Technique d''étirement","items":["Étirement statique : tiens 30–60 secondes, respire profondément, relâche 20 % de tension à l''expir","PNF (Proprioceptive Neuromuscular Facilitation) : contraction 6 s → relâchement → approfondissement — gain de 30 % d''amplitude","Ne jamais étirer un muscle froid — attends 5 min d''échauffement léger (marche, rotation) avant tout stretching profond","Seuil de confort : sensation de tension tolérable, jamais de douleur aiguë — la douleur déclenche le réflexe myotatique","Étirement dynamique avant l''effort, étirement statique après — ne pas confondre les deux dans ta routine"]},"equipment":{"emoji":"🛒","title":"Matériel recommandé","items":["Tapis de sol épais (6–8 mm) pour le confort articulaire des genoux et des hanches","Sangle de stretching (ou ceinture) pour les étirements des ischio-jambiers et des fléchisseurs de hanche","Foam roller (rouleau de massage) pour le relâchement myofascial avant les étirements","Balle de lacrosse ou balle de tennis pour le massage des points trigger sur mollets et voûte plantaire","Timer / application pour respecter les durées d''étirement — ne jamais estimer à l''oeil"]},"nutrition":{"emoji":"🍊","title":"Nutrition pour la souplesse","items":["Collagène (10–15 g) + vitamine C 30–60 min avant les séances de stretching intensif pour la synthèse du collagène","Hydratation optimale : les fascias et les tendons sont composés à 70 % d''eau — bois 2L minimum par jour","Magnésium (300–400 mg/j) : réduit les crampes et favorise la relaxation musculaire profonde","Curcumine + poivre noir post-séance : anti-inflammatoire naturel puissant pour les douleurs de courbatures","Évite le café en excès les jours de stretching intensif — la caféine augmente le tonus musculaire basal"]},"recovery":{"emoji":"💆","title":"Intégration & Récupération","items":["Foam rolling 5–10 min avant les étirements libère les restrictions fasciales et amplifie les gains de mobilité","Bain chaud 20 min (38–40 °C) pré-séance — la chaleur augmente l''élasticité du collagène de 15 %","Stretching du soir → meilleur sommeil : les étirements parasympathiques abaissent la fréquence cardiaque","Maintiens les gains : 10 min de stretching quotidien vaut mieux qu''une session intensive hebdomadaire","Progressive overload en souplesse : augmente l''amplitude de 5 % par semaine — la progression est linéaire si régulière"]}},"tips":[{"icon":"🌡️","title":"Chaud = plus souple","body":"La température musculaire améliore l''élasticité. Étire-toi après l''effort ou après un bain chaud pour des gains 2× plus rapides."},{"icon":"📐","title":"La respiration est l''outil","body":"À chaque expiration, les muscles se relâchent naturellement. Expire lentement pour \"aller plus loin\" dans l''étirement sans forcer."},{"icon":"🔄","title":"Mobilité ≠ Souplesse","body":"La souplesse est passive (jusqu''où tu peux aller). La mobilité est active (jusqu''où tu contrôles). Travaille les deux pour une flexibilité fonctionnelle."},{"icon":"⏰","title":"La constance prime","body":"10 minutes chaque jour produisent des résultats en 3 semaines. Sans régularité, les tissus conjonctifs retournent à leur longueur d''origine en 72h."}],"exercises":[{"name":"Flexion avant jambes tendues","muscles":"Ischio-jambiers, bas du dos, mollets","sets":"3×45 s","difficulty":"Débutant","description":"Debout, jambes jointes et tendues, descends lentement les mains vers le sol. Fléchis légèrement les genoux si douleur dans le bas du dos. Tiens la position en respirant profondément."},{"name":"Fente basse psoas (lézard)","muscles":"Psoas, fléchisseurs de hanche, quadriceps","sets":"3×45 s/côté","difficulty":"Débutant","description":"En fente profonde, genou arrière au sol, bassin poussé vers l''avant. Optionnel : lève les bras pour approfondir. Libère le psoas raccourci par la position assise prolongée."},{"name":"Papillon assis","muscles":"Adducteurs, fléchisseurs de hanche, aine","sets":"3×60 s","difficulty":"Débutant","description":"Assis, plantes des pieds collées, genoux vers le sol. Penche doucement le buste en avant en gardant le dos droit. Étirement fondamental pour les coureurs et cyclistes."},{"name":"Pigeon (préparatoire)","muscles":"Fessiers, rotateurs externes de hanche, psoas","sets":"2 min/côté","difficulty":"Intermédiaire","description":"En quadrupédie, avance un genou entre les mains, étends la jambe arrière. Incline progressivement le buste vers l''avant. L''un des étirements de hanche les plus efficaces qui existe."},{"name":"Étirement pectoral à la porte","muscles":"Pectoraux, biceps, coiffe des rotateurs","sets":"3×30 s/côté","difficulty":"Débutant","description":"Bras à 90° contre le montant d''une porte, fais un pas en avant. Ressens l''étirement de toute la face antérieure de l''épaule. Contre-balance le volume en développé couché."},{"name":"Cobra (Bhujangasana)","muscles":"Abdominaux, fléchisseurs de hanche, pectoraux","sets":"3×30 s","difficulty":"Débutant","description":"Allongé face au sol, mains sous les épaules, pousse le buste vers le haut en gardant le bassin au sol. Étire toute la face antérieure du corps et renforce les érecteurs du rachis."},{"name":"Rotation thoracique à genoux","muscles":"Muscles paravertébraux thoraciques, obliques","sets":"3×10/côté","difficulty":"Intermédiaire","description":"En quadrupédie, main derrière la tête, ouvre le coude vers le plafond en pivotant le buste. Améliore la mobilité thoracique essentielle pour la course, la natation et la boxe."},{"name":"Étirement du mollet au mur","muscles":"Gastrocnémiens, soléaire, tendon d''Achille","sets":"3×45 s/côté","difficulty":"Débutant","description":"Mains au mur, jambe arrière tendue, talon ancré au sol. Variante genou fléchi pour cibler le soléaire. Incontournable pour les coureurs et pratiquants de sports de raquette."},{"name":"Lacet (figure 4)","muscles":"Fessiers, pyramidal, rotateurs profonds de hanche","sets":"2 min/côté","difficulty":"Tous niveaux","description":"Assis sur le dos, croise la cheville sur le genou opposé, tire la cuisse vers la poitrine. Excellent pour soulager le syndrome du piriforme et les sciatiques d''origine fessière."}],"program":[{"week":"Semaine 1–2","theme":"Découverte — Étirements essentiels","sessions":[{"name":"Full body stretching 30 min","detail":"Ischio-jambiers, psoas, pectoraux, mollets, fessiers — 40 s par posture"},{"name":"Mobilité matinale 15 min","detail":"Rotations articulaires dynamiques (cou, épaules, hanches, chevilles) + 3 postures clés"},{"name":"Foam rolling récupération","detail":"Quadriceps, IT band, dos thoracique, mollets — 60 s par zone"}]},{"week":"Semaine 3–4","theme":"Ciblé — Zones prioritaires","sessions":[{"name":"Hanches & bas du dos 35 min","detail":"Pigeon, fente basse, papillon, torsion assise — 60–90 s par posture"},{"name":"Chaîne postérieure 30 min","detail":"Flexion avant, mollets, ischio-jambiers debout et allongé, lacet"},{"name":"Épaules & thorax 25 min","detail":"Ouverture pectorale, étirement biceps, rotation thoracique, cobra"},{"name":"Relaxation profonde 20 min","detail":"Yoga restauratif : postures soutenues avec bolster — relâchement total"}]},{"week":"Semaine 5–6","theme":"PNF & Gains d''amplitude","sessions":[{"name":"PNF ischio-jambiers 30 min","detail":"Contraction 6 s — relâchement — approfondissement × 4 cycles par jambe"},{"name":"PNF hanches & adducteurs","detail":"Protocole PNF sur papillon, pigeon et flexion latérale — 3 cycles par zone"},{"name":"Stretching actif-passif 40 min","detail":"Alternance contraction concentrique et étirement passif profond sur les grands groupes"}]},{"week":"Semaine 7–8","theme":"Intégration & Autonomie","sessions":[{"name":"Séquence personnalisée 40 min","detail":"Construis ta routine avec les étirements les plus bénéfiques identifiés sur 6 semaines"},{"name":"Test d''amplitude bilan","detail":"Distance doigts-sol, rotation d''épaule, flexion latérale, test Thomas pour psoas"},{"name":"Stretching sport-spécifique","detail":"Adapte ta routine à ton sport principal — running, musculation, boxe ou yoga"},{"name":"Programme d''entretien 10 min/j","detail":"Mini-routine quotidienne des 5 zones prioritaires pour maintenir les acquis"}]}],"faq":[{"q":"Quand faut-il s''étirer : avant ou après l''entraînement ?","a":"Avant : privilégie les étirements dynamiques (balancés, rotations) pour préparer les articulations. Après : les étirements statiques (30–60 s tenus) pour récupérer et augmenter la souplesse à froid musculaire."},{"q":"Combien de temps avant de voir une amélioration de la souplesse ?","a":"Avec 3–4 séances par semaine de 20–30 min, les premiers gains mesurables apparaissent en 3–4 semaines. Une souplesse significative se construit sur 3–6 mois de pratique régulière."},{"q":"Est-ce que s''étirer fait vraiment mal au début ?","a":"Une sensation de tension intense est normale et nécessaire. La douleur aiguë ou articulaire est un signal d''arrêt immédiat. Travaille à 70–80 % de ton amplitude maximale pour progresser en sécurité."},{"q":"Le stretching peut-il réduire les douleurs chroniques ?","a":"Oui — de nombreuses douleurs lombaires, cervicales et des hanches sont causées par des muscles raccourcis. Un programme régulier de stretching ciblé réduit significativement ces douleurs en 4–8 semaines selon les études."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('stretching', 'en', '{"title":"Stretching","tag":"Mobility","description":"Mobility, flexibility and optimal recovery — guided stretching routines to prevent injuries and perform.","stats":["+1,600 members","30+ routines","10–30 min / session"],"levels":["Beginner","Intermediate","Advanced","All levels"]}'::jsonb, '{"tagline":"Free your body, recover better and move without pain.","heroStat":"3,200+ active practitioners","guide":{"technique":{"emoji":"🤸","title":"Stretching technique","items":["Static stretch: hold 30–60 seconds, breathe deeply, release 20% of the tension on the exhale","PNF (Proprioceptive Neuromuscular Facilitation): contract 6 s → release → deepen — a 30% range gain","Never stretch a cold muscle — wait for 5 min of light warm-up (walking, rotation) before any deep stretching","Comfort threshold: a tolerable feeling of tension, never sharp pain — pain triggers the stretch reflex","Dynamic stretching before the effort, static stretching after — don''t mix the two in your routine"]},"equipment":{"emoji":"🛒","title":"Recommended gear","items":["A thick floor mat (6–8 mm) for the joint comfort of the knees and hips","A stretching strap (or belt) for the hamstring and hip-flexor stretches","A foam roller for myofascial release before stretching","A lacrosse ball or tennis ball to massage trigger points on the calves and arch of the foot","A timer / app to respect stretch durations — never estimate by eye"]},"nutrition":{"emoji":"🍊","title":"Nutrition for flexibility","items":["Collagen (10–15 g) + vitamin C 30–60 min before intensive stretching sessions for collagen synthesis","Optimal hydration: fascia and tendons are 70% water — drink 2L minimum per day","Magnesium (300–400 mg/day): reduces cramps and promotes deep muscle relaxation","Curcumin + black pepper post-session: a powerful natural anti-inflammatory for soreness","Avoid excess coffee on intensive stretching days — caffeine raises baseline muscle tone"]},"recovery":{"emoji":"💆","title":"Integration & Recovery","items":["Foam rolling 5–10 min before stretching releases fascial restrictions and amplifies mobility gains","A hot bath 20 min (38–40 °C) pre-session — heat increases collagen elasticity by 15%","Evening stretching → better sleep: parasympathetic stretches lower the heart rate","Maintain the gains: 10 min of daily stretching beats one intensive weekly session","Progressive overload in flexibility: increase the range by 5% per week — progress is linear if regular"]}},"tips":[{"icon":"🌡️","title":"Warm = more flexible","body":"Muscle temperature improves elasticity. Stretch after exercise or after a hot bath for gains 2× faster."},{"icon":"📐","title":"Breathing is the tool","body":"On each exhale, the muscles relax naturally. Exhale slowly to \"go deeper\" into the stretch without forcing."},{"icon":"🔄","title":"Mobility ≠ Flexibility","body":"Flexibility is passive (how far you can go). Mobility is active (how far you control). Work both for functional flexibility."},{"icon":"⏰","title":"Consistency rules","body":"10 minutes every day produce results in 3 weeks. Without consistency, connective tissue returns to its original length in 72h."}],"exercises":[{"name":"Standing forward fold","muscles":"Hamstrings, lower back, calves","sets":"3×45 s","difficulty":"Beginner","description":"Standing, legs together and straight, slowly lower the hands toward the floor. Bend the knees slightly if you feel low-back pain. Hold the position breathing deeply."},{"name":"Low lunge psoas (lizard)","muscles":"Psoas, hip flexors, quads","sets":"3×45 s/side","difficulty":"Beginner","description":"In a deep lunge, back knee on the floor, pelvis pushed forward. Optional: raise the arms to deepen. Releases the psoas shortened by prolonged sitting."},{"name":"Seated butterfly","muscles":"Adductors, hip flexors, groin","sets":"3×60 s","difficulty":"Beginner","description":"Seated, soles of the feet together, knees toward the floor. Gently lean the torso forward keeping the back straight. A fundamental stretch for runners and cyclists."},{"name":"Pigeon (preparatory)","muscles":"Glutes, external hip rotators, psoas","sets":"2 min/side","difficulty":"Intermediate","description":"On all fours, bring one knee between the hands, extend the back leg. Gradually lean the torso forward. One of the most effective hip stretches there is."},{"name":"Doorway pec stretch","muscles":"Pecs, biceps, rotator cuff","sets":"3×30 s/side","difficulty":"Beginner","description":"Arm at 90° against the door frame, take a step forward. Feel the stretch across the whole front of the shoulder. Counterbalances bench-press volume."},{"name":"Cobra (Bhujangasana)","muscles":"Abs, hip flexors, pecs","sets":"3×30 s","difficulty":"Beginner","description":"Lying face down, hands under the shoulders, push the torso up keeping the pelvis on the floor. Stretches the whole front of the body and strengthens the spinal erectors."},{"name":"Kneeling thoracic rotation","muscles":"Thoracic paraspinals, obliques","sets":"3×10/side","difficulty":"Intermediate","description":"On all fours, hand behind the head, open the elbow toward the ceiling while rotating the torso. Improves thoracic mobility essential for running, swimming and boxing."},{"name":"Calf stretch at the wall","muscles":"Gastrocnemius, soleus, Achilles tendon","sets":"3×45 s/side","difficulty":"Beginner","description":"Hands on the wall, back leg straight, heel anchored to the floor. Bent-knee variation to target the soleus. A must for runners and racquet-sport players."},{"name":"Figure 4","muscles":"Glutes, piriformis, deep hip rotators","sets":"2 min/side","difficulty":"All levels","description":"Lying on your back, cross the ankle over the opposite knee, pull the thigh toward the chest. Excellent for relieving piriformis syndrome and glute-related sciatica."}],"program":[{"week":"Week 1–2","theme":"Discovery — Essential stretches","sessions":[{"name":"Full body stretching 30 min","detail":"Hamstrings, psoas, pecs, calves, glutes — 40 s per pose"},{"name":"Morning mobility 15 min","detail":"Dynamic joint rotations (neck, shoulders, hips, ankles) + 3 key poses"},{"name":"Foam rolling recovery","detail":"Quads, IT band, thoracic back, calves — 60 s per area"}]},{"week":"Week 3–4","theme":"Targeted — Priority areas","sessions":[{"name":"Hips & lower back 35 min","detail":"Pigeon, low lunge, butterfly, seated twist — 60–90 s per pose"},{"name":"Posterior chain 30 min","detail":"Forward fold, calves, standing and lying hamstrings, figure 4"},{"name":"Shoulders & chest 25 min","detail":"Pec opening, biceps stretch, thoracic rotation, cobra"},{"name":"Deep relaxation 20 min","detail":"Restorative yoga: poses supported with a bolster — total release"}]},{"week":"Week 5–6","theme":"PNF & Range gains","sessions":[{"name":"PNF hamstrings 30 min","detail":"Contract 6 s — release — deepen × 4 cycles per leg"},{"name":"PNF hips & adductors","detail":"PNF protocol on butterfly, pigeon and lateral flexion — 3 cycles per area"},{"name":"Active-passive stretching 40 min","detail":"Alternate concentric contraction and deep passive stretch on the large groups"}]},{"week":"Week 7–8","theme":"Integration & Autonomy","sessions":[{"name":"Personalized sequence 40 min","detail":"Build your routine with the most beneficial stretches identified over 6 weeks"},{"name":"Range-of-motion check","detail":"Fingers-to-floor distance, shoulder rotation, lateral flexion, Thomas test for the psoas"},{"name":"Sport-specific stretching","detail":"Adapt your routine to your main sport — running, strength, boxing or yoga"},{"name":"Maintenance program 10 min/day","detail":"A daily mini-routine of the 5 priority areas to keep your gains"}]}],"faq":[{"q":"When should I stretch: before or after training?","a":"Before: favor dynamic stretches (swings, rotations) to prepare the joints. After: static stretches (held 30–60 s) to recover and increase flexibility on cool muscles."},{"q":"How long before I see an improvement in flexibility?","a":"With 3–4 sessions per week of 20–30 min, the first measurable gains appear in 3–4 weeks. Significant flexibility builds over 3–6 months of regular practice."},{"q":"Does stretching really hurt at first?","a":"A feeling of intense tension is normal and necessary. Sharp or joint pain is an immediate stop signal. Work at 70–80% of your maximum range to progress safely."},{"q":"Can stretching reduce chronic pain?","a":"Yes — many lower-back, neck and hip pains are caused by shortened muscles. A regular program of targeted stretching significantly reduces these pains in 4–8 weeks according to studies."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('stretching', 'de', '{"title":"Stretching","tag":"Mobilität","description":"Mobilität, Beweglichkeit und optimale Erholung — geführte Dehnroutinen, um Verletzungen vorzubeugen und Leistung zu bringen.","stats":["+1.600 Mitglieder","30+ Routinen","10–30 Min / Einheit"],"levels":["Anfänger","Fortgeschritten","Erfahren","Alle Niveaus"]}'::jsonb, '{"tagline":"Befreie deinen Körper, erhole dich besser und bewege dich ohne Schmerz.","heroStat":"3.200+ aktive Praktizierende","guide":{"technique":{"emoji":"🤸","title":"Dehntechnik","items":["Statisches Dehnen: 30–60 Sekunden halten, tief atmen, beim Ausatmen 20% der Spannung lösen","PNF (Propriozeptive Neuromuskuläre Fazilitation): 6 s kontrahieren → lösen → vertiefen — 30% Umfanggewinn","Dehne nie einen kalten Muskel — warte 5 Min leichtes Aufwärmen (Gehen, Rotation) vor jedem tiefen Dehnen","Komfortschwelle: ein tolerierbares Spannungsgefühl, nie stechender Schmerz — Schmerz löst den Dehnreflex aus","Dynamisches Dehnen vor der Anstrengung, statisches Dehnen danach — mische beides nicht in deiner Routine"]},"equipment":{"emoji":"🛒","title":"Empfohlene Ausrüstung","items":["Eine dicke Bodenmatte (6–8 mm) für den Gelenkkomfort von Knien und Hüften","Ein Dehngurt (oder Gürtel) für die Dehnung von Beinbeugern und Hüftbeugern","Eine Faszienrolle für die myofasziale Lösung vor dem Dehnen","Ein Lacrosse- oder Tennisball zum Massieren von Trigger Points an Waden und Fußgewölbe","Ein Timer / eine App, um die Dehndauer einzuhalten — schätze nie nach Augenmaß"]},"nutrition":{"emoji":"🍊","title":"Ernährung für Flexibilität","items":["Kollagen (10–15 g) + Vitamin C 30–60 Min vor intensiven Dehneinheiten für die Kollagensynthese","Optimale Hydration: Faszien und Sehnen bestehen zu 70% aus Wasser — trinke mindestens 2 L pro Tag","Magnesium (300–400 mg/Tag): reduziert Krämpfe und fördert tiefe Muskelentspannung","Curcumin + schwarzer Pfeffer nach der Einheit: ein starker natürlicher Entzündungshemmer gegen Muskelkater","Vermeide übermäßigen Kaffee an Tagen intensiven Dehnens — Koffein erhöht den Grundmuskeltonus"]},"recovery":{"emoji":"💆","title":"Integration & Erholung","items":["Foam Rolling 5–10 Min vor dem Dehnen löst fasziale Einschränkungen und verstärkt die Mobilitätsgewinne","Ein heißes Bad 20 Min (38–40 °C) vor der Einheit — Wärme erhöht die Kollagen-Elastizität um 15%","Abendliches Dehnen → besserer Schlaf: parasympathische Dehnungen senken die Herzfrequenz","Erhalte die Gewinne: 10 Min tägliches Dehnen schlägt eine intensive wöchentliche Einheit","Progressive Überlastung in der Flexibilität: erhöhe den Umfang um 5% pro Woche — der Fortschritt ist linear, wenn regelmäßig"]}},"tips":[{"icon":"🌡️","title":"Warm = flexibler","body":"Die Muskeltemperatur verbessert die Elastizität. Dehne nach dem Sport oder nach einem heißen Bad für 2× schnellere Gewinne."},{"icon":"📐","title":"Die Atmung ist das Werkzeug","body":"Bei jedem Ausatmen entspannen sich die Muskeln natürlich. Atme langsam aus, um „tiefer“ in die Dehnung zu gehen, ohne zu erzwingen."},{"icon":"🔄","title":"Mobilität ≠ Flexibilität","body":"Flexibilität ist passiv (wie weit du gehen kannst). Mobilität ist aktiv (wie weit du kontrollierst). Arbeite an beidem für funktionelle Flexibilität."},{"icon":"⏰","title":"Beständigkeit regiert","body":"10 Minuten jeden Tag bringen in 3 Wochen Ergebnisse. Ohne Beständigkeit kehrt das Bindegewebe in 72 h zu seiner ursprünglichen Länge zurück."}],"exercises":[{"name":"Stehende Vorbeuge","muscles":"Beinbeuger, unterer Rücken, Waden","sets":"3×45 s","difficulty":"Anfänger","description":"Stehend, Beine zusammen und gestreckt, senke langsam die Hände zum Boden. Beuge die Knie leicht, wenn du Schmerzen im unteren Rücken spürst. Halte die Position und atme tief."},{"name":"Tiefer Ausfallschritt Psoas (Eidechse)","muscles":"Psoas, Hüftbeuger, Quadrizeps","sets":"3×45 s/Seite","difficulty":"Anfänger","description":"In einem tiefen Ausfallschritt, hinteres Knie am Boden, Becken nach vorn geschoben. Optional: hebe die Arme zur Vertiefung. Löst den durch langes Sitzen verkürzten Psoas."},{"name":"Sitzender Schmetterling","muscles":"Adduktoren, Hüftbeuger, Leiste","sets":"3×60 s","difficulty":"Anfänger","description":"Sitzend, Fußsohlen zusammen, Knie Richtung Boden. Neige den Oberkörper sanft nach vorn und halte den Rücken gerade. Eine fundamentale Dehnung für Läufer und Radfahrer."},{"name":"Taube (vorbereitend)","muscles":"Gesäß, äußere Hüftrotatoren, Psoas","sets":"2 Min/Seite","difficulty":"Fortgeschritten","description":"Im Vierfüßlerstand bringe ein Knie zwischen die Hände, strecke das hintere Bein. Neige den Oberkörper allmählich nach vorn. Eine der effektivsten Hüftdehnungen überhaupt."},{"name":"Türrahmen-Brustdehnung","muscles":"Brust, Bizeps, Rotatorenmanschette","sets":"3×30 s/Seite","difficulty":"Anfänger","description":"Arm bei 90° am Türrahmen, mach einen Schritt nach vorn. Spüre die Dehnung über die gesamte Schultervorderseite. Gleicht das Bankdrück-Volumen aus."},{"name":"Kobra (Bhujangasana)","muscles":"Bauch, Hüftbeuger, Brust","sets":"3×30 s","difficulty":"Anfänger","description":"Bäuchlings liegend, Hände unter den Schultern, drücke den Oberkörper hoch und halte das Becken am Boden. Dehnt die gesamte Körpervorderseite und stärkt die Rückenstrecker."},{"name":"Knieende Brustwirbelrotation","muscles":"Brustwirbel-Rückenstrecker, schräge Bauchmuskeln","sets":"3×10/Seite","difficulty":"Fortgeschritten","description":"Im Vierfüßlerstand, Hand hinter dem Kopf, öffne den Ellbogen zur Decke und rotiere den Oberkörper. Verbessert die für Laufen, Schwimmen und Boxen essenzielle Brustwirbel-Mobilität."},{"name":"Wadendehnung an der Wand","muscles":"Gastrocnemius, Soleus, Achillessehne","sets":"3×45 s/Seite","difficulty":"Anfänger","description":"Hände an der Wand, hinteres Bein gestreckt, Ferse am Boden verankert. Variante mit gebeugtem Knie, um den Soleus zu treffen. Ein Muss für Läufer und Schlägersportler."},{"name":"Figur 4","muscles":"Gesäß, Piriformis, tiefe Hüftrotatoren","sets":"2 Min/Seite","difficulty":"Alle Niveaus","description":"Auf dem Rücken liegend, kreuze den Knöchel über das gegenüberliegende Knie, zieh den Oberschenkel zur Brust. Exzellent zur Linderung des Piriformis-Syndroms und der gesäßbedingten Ischias."}],"program":[{"week":"Woche 1–2","theme":"Entdeckung — Essenzielle Dehnungen","sessions":[{"name":"Ganzkörper-Stretching 30 Min","detail":"Beinbeuger, Psoas, Brust, Waden, Gesäß — 40 s pro Pose"},{"name":"Morgen-Mobilität 15 Min","detail":"Dynamische Gelenkrotationen (Nacken, Schultern, Hüften, Knöchel) + 3 Schlüsselposen"},{"name":"Foam-Rolling-Erholung","detail":"Quadrizeps, IT-Band, Brustwirbel-Rücken, Waden — 60 s pro Bereich"}]},{"week":"Woche 3–4","theme":"Gezielt — Prioritäre Bereiche","sessions":[{"name":"Hüften & unterer Rücken 35 Min","detail":"Taube, tiefer Ausfallschritt, Schmetterling, sitzende Drehung — 60–90 s pro Pose"},{"name":"Hintere Kette 30 Min","detail":"Vorbeuge, Waden, Beinbeuger stehend und liegend, Figur 4"},{"name":"Schultern & Brust 25 Min","detail":"Brustöffnung, Bizepsdehnung, Brustwirbelrotation, Kobra"},{"name":"Tiefe Entspannung 20 Min","detail":"Restoratives Yoga: mit Bolster gestützte Posen — totale Lösung"}]},{"week":"Woche 5–6","theme":"PNF & Umfanggewinne","sessions":[{"name":"PNF Beinbeuger 30 Min","detail":"6 s kontrahieren — lösen — vertiefen × 4 Zyklen pro Bein"},{"name":"PNF Hüften & Adduktoren","detail":"PNF-Protokoll auf Schmetterling, Taube und Seitneigung — 3 Zyklen pro Bereich"},{"name":"Aktiv-passives Dehnen 40 Min","detail":"Wechsle konzentrische Kontraktion und tiefe passive Dehnung an den großen Gruppen"}]},{"week":"Woche 7–8","theme":"Integration & Eigenständigkeit","sessions":[{"name":"Personalisierte Sequenz 40 Min","detail":"Baue deine Routine mit den nützlichsten über 6 Wochen identifizierten Dehnungen"},{"name":"Bewegungsumfang-Check","detail":"Finger-zu-Boden-Abstand, Schulterrotation, Seitneigung, Thomas-Test für den Psoas"},{"name":"Sportspezifisches Dehnen","detail":"Passe deine Routine an deine Hauptsportart an — Laufen, Kraft, Boxen oder Yoga"},{"name":"Erhaltungsprogramm 10 Min/Tag","detail":"Eine tägliche Mini-Routine der 5 prioritären Bereiche, um deine Gewinne zu halten"}]}],"faq":[{"q":"Wann sollte ich dehnen: vor oder nach dem Training?","a":"Davor: bevorzuge dynamische Dehnungen (Schwünge, Rotationen), um die Gelenke vorzubereiten. Danach: statische Dehnungen (30–60 s gehalten), um dich zu erholen und die Flexibilität an warmen Muskeln zu erhöhen."},{"q":"Wie lange bis ich eine Verbesserung der Flexibilität sehe?","a":"Mit 3–4 Einheiten pro Woche à 20–30 Min treten die ersten messbaren Gewinne in 3–4 Wochen auf. Bedeutende Flexibilität baut sich über 3–6 Monate regelmäßiger Praxis auf."},{"q":"Tut Dehnen am Anfang wirklich weh?","a":"Ein intensives Spannungsgefühl ist normal und nötig. Stechender oder Gelenkschmerz ist ein sofortiges Stoppsignal. Arbeite bei 70–80% deines maximalen Umfangs, um sicher voranzukommen."},{"q":"Kann Dehnen chronische Schmerzen reduzieren?","a":"Ja — viele Schmerzen im unteren Rücken, Nacken und in der Hüfte werden durch verkürzte Muskeln verursacht. Ein regelmäßiges Programm gezielten Dehnens reduziert diese Schmerzen laut Studien in 4–8 Wochen deutlich."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('stretching', 0, array['g_tea8ZNk5A','X4yWT6yqCJ8']::text[], 'pro', '{"fr":{"title":"Stretching full body 30 min","description":"Programme d''étirement complet du corps en 30 minutes — idéal après l''entraînement ou le soir pour récupérer.","duration":"30 min","level":"Tous niveaux"},"en":{"title":"Full body stretching 30 min","description":"A complete full-body stretching program in 30 minutes — ideal after training or in the evening to recover.","duration":"30 min","level":"All levels"},"de":{"title":"Ganzkörper-Stretching 30 Min","description":"Ein komplettes Ganzkörper-Stretching-Programm in 30 Minuten — ideal nach dem Training oder abends zur Erholung.","duration":"30 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('stretching', 1, array['BYsfUroaCcw','4JQ_oLV8c6Q']::text[], 'pro', '{"fr":{"title":"Étirements ischio-jambiers & dos","description":"Routine ciblée 25 minutes pour soulager les ischio-jambiers tendus et les douleurs lombaires — résultats dès la première séance.","duration":"25 min","level":"Débutant"},"en":{"title":"Hamstring & back stretches","description":"A targeted 25-minute routine to relieve tight hamstrings and lower-back pain — results from the first session.","duration":"25 min","level":"Beginner"},"de":{"title":"Beinbeuger- & Rückendehnungen","description":"Eine gezielte 25-Min-Routine, um verspannte Beinbeuger und Schmerzen im unteren Rücken zu lindern — Ergebnisse ab der ersten Einheit.","duration":"25 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('stretching', 2, array['L_xrDAtykMI','Ou2XvUtRCto']::text[], 'pro', '{"fr":{"title":"Mobilité des hanches — Routine complète","description":"Programme mobilité des hanches en 35 minutes — ouverture, rotation interne/externe et libération du psoas.","duration":"35 min","level":"Intermédiaire"},"en":{"title":"Hip mobility — Complete routine","description":"A 35-minute hip-mobility program — opening, internal/external rotation and psoas release.","duration":"35 min","level":"Intermediate"},"de":{"title":"Hüftmobilität — Komplette Routine","description":"Ein 35-Min-Hüftmobilitäts-Programm — Öffnung, Innen-/Außenrotation und Psoas-Lösung.","duration":"35 Min","level":"Fortgeschritten"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('stretching', 3, array['T5OEbqLZS5c','SsgGV0llXjQ']::text[], 'pro', '{"fr":{"title":"Stretching épaules & cou","description":"Libère les tensions cervicales et les épaules bloquées en 20 minutes — parfait pour les personnes travaillant assis.","duration":"20 min","level":"Débutant"},"en":{"title":"Shoulder & neck stretches","description":"Release neck tension and stiff shoulders in 20 minutes — perfect for people who work seated.","duration":"20 min","level":"Beginner"},"de":{"title":"Schulter- & Nackendehnungen","description":"Löse Nackenverspannung und steife Schultern in 20 Minuten — perfekt für Menschen, die im Sitzen arbeiten.","duration":"20 Min","level":"Anfänger"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('stretching', 4, array['maBhWtvsUeE']::text[], 'pro', '{"fr":{"title":"PNF Stretching — Techniques avancées","description":"Méthode PNF expliquée et appliquée sur 6 groupes musculaires majeurs — gains de mobilité rapides et durables.","duration":"40 min","level":"Avancé"},"en":{"title":"PNF Stretching — Advanced techniques","description":"The PNF method explained and applied to 6 major muscle groups — fast, lasting mobility gains.","duration":"40 min","level":"Advanced"},"de":{"title":"PNF-Stretching — Fortgeschrittene Techniken","description":"Die PNF-Methode erklärt und auf 6 große Muskelgruppen angewendet — schnelle, dauerhafte Mobilitätsgewinne.","duration":"40 Min","level":"Erfahren"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_videos (discipline_slug, idx, youtube_ids, min_plan, i18n) values ('stretching', 5, array['UItWltVZZmE']::text[], 'pro', '{"fr":{"title":"Foam rolling + Stretching récupération","description":"Protocole complet de récupération : automassage au rouleau suivi d''étirements ciblés pour accélérer la récupération musculaire.","duration":"35 min","level":"Tous niveaux"},"en":{"title":"Foam rolling + Recovery stretching","description":"A complete recovery protocol: foam-roller self-massage followed by targeted stretches to speed up muscle recovery.","duration":"35 min","level":"All levels"},"de":{"title":"Foam Rolling + Erholungs-Stretching","description":"Ein komplettes Erholungsprotokoll: Faszienrollen-Selbstmassage gefolgt von gezielten Dehnungen zur Beschleunigung der Muskelregeneration.","duration":"35 Min","level":"Alle Niveaus"}}'::jsonb) on conflict (discipline_slug, idx) do update set youtube_ids=excluded.youtube_ids, min_plan=excluded.min_plan, i18n=excluded.i18n;
insert into public.content_disciplines (slug, sort_order, color, icon, min_plan) values ('nutrition', 9, 'lime', 'zap', 'pro') on conflict (slug) do update set sort_order=excluded.sort_order, color=excluded.color, icon=excluded.icon, min_plan=excluded.min_plan, updated_at=now();
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('nutrition', 'fr', '{"title":"Nutrition","tag":"Alimentation","description":"Plans alimentaires personnalisés, calcul des macros et stratégies nutritionnelles pour atteindre tes objectifs sportifs.","stats":["+3 000 membres","50+ plans","Suivi quotidien"],"levels":["Débutant","Intermédiaire","Avancé","Athlète"]}'::jsonb, '{"tagline":"Mange avec intelligence — la performance commence dans l''assiette.","heroStat":"4 100+ membres actifs","guide":{"technique":{"emoji":"🥗","title":"Principes nutritionnels","items":["Déficit calorique pour perdre du poids : 300–500 kcal/jour sous le TDEE — jamais sous 1 200 kcal (femmes) ou 1 500 kcal (hommes)","Surplus calorique pour la prise de masse : 200–300 kcal/jour au-dessus du TDEE pour une prise lean","Macronutriments sportifs : 30–35 % protéines / 40–50 % glucides / 20–25 % lipides pour la performance","Index glycémique (IG) : privilégie les glucides à IG bas (quinoa, patate douce, légumineuses) pour une énergie stable","Chrononutrition : glucides en priorité le matin et autour des entraînements, lipides le soir"]},"equipment":{"emoji":"⚖️","title":"Outils essentiels","items":["Balance alimentaire de précision (au gramme) — indispensable pour comprendre les portions réelles","Application de suivi nutritionnel (MyFitnessPal, Cronometer) pour tracker les macros et micronutriments","Boîtes de préparation repas (meal prep) hermétiques pour la planification hebdomadaire","Mixeur haute puissance pour les smoothies protéinés et les sauces maison nutritives","Thermomètre de cuisson pour maîtriser la température et préserver les nutriments des aliments"]},"nutrition":{"emoji":"🍽️","title":"Planification & Répartition","items":["Timing protéines : 20–40 g de protéines toutes les 3–4 h pour maximiser la synthèse protéique musculaire","Fenêtre anabolique : repas riche en protéines et glucides dans les 60–90 min post-entraînement","Repas pré-entraînement : glucides complexes + protéines légères 2–3h avant (riz + poulet + légumes)","5 portions de légumes/fruits par jour minimum — vitamines, minéraux et fibres pour la santé globale","Hydratation : 35 ml/kg de poids corporel par jour + 500 ml supplémentaires par heure d''exercice"]},"recovery":{"emoji":"🔄","title":"Nutrition de récupération","items":["Les 30 premières minutes post-effort sont la fenêtre de réponse maximale : glucides + protéines 4:1","Caséine (protéine à digestion lente) au coucher pour alimenter la synthèse protéique nocturne","Oméga-3 (2–4 g/jour EPA+DHA) : réduisent l''inflammation musculaire et accélèrent la récupération","Tart cherry ou jus de betterave post-effort intense : anti-inflammatoires naturels validés scientifiquement","Alcool post-effort : réduit la synthèse protéique de 37 % — à éviter dans les 6h qui suivent une séance intensive"]}},"tips":[{"icon":"🍳","title":"Meal prep = réussite","body":"Prépare tes repas du dimanche pour la semaine. Les études montrent que les personnes qui planifient leur alimentation atteignent leurs objectifs 2,5× plus souvent que celles qui improvisent."},{"icon":"🥦","title":"La règle de l''assiette","body":"Chaque repas principal : 1/2 assiette légumes, 1/4 protéines, 1/4 glucides complexes. Simple, efficace, sans calculer les calories à chaque fois."},{"icon":"💧","title":"La soif = déjà déshydraté","body":"Quand tu ressens la soif, tu as déjà perdu 1–2 % de ton poids en eau. Bois régulièrement tout au long de la journée — pas en grandes quantités sporadiques."},{"icon":"📊","title":"Les calories de base d''abord","body":"Maîtrise d''abord la quantité (calories totales), puis optimise la qualité (macros), enfin le timing (chrononutrition). Ne saute pas les étapes."}],"exercises":[{"name":"Planification hebdomadaire des repas","muscles":"Habitude, organisation nutritionnelle","sets":"1× /semaine — 20 min","difficulty":"Débutant","description":"Chaque dimanche, planifie tes 5 repas principaux pour la semaine. Calcule les macros cibles, liste les ingrédients, prépare les protéines et céréales à l''avance. Fondement de la réussite nutritionnelle."},{"name":"Calcul de son TDEE","muscles":"Connaissance métabolique","sets":"1× au départ puis chaque mois","difficulty":"Débutant","description":"Calcule ton Total Daily Energy Expenditure (TDEE) avec la formule Mifflin-St Jeor × facteur d''activité. Ajuste de ±300 kcal selon l''objectif (perte ou prise). Recalcule à chaque -5 kg."},{"name":"Tracking macros 7 jours","muscles":"Conscience alimentaire","sets":"7 jours consécutifs","difficulty":"Débutant","description":"Note chaque aliment dans une app (Cronometer recommandé) pendant 7 jours consécutifs sans changer tes habitudes. Révèle les écarts réels entre ce que tu penses manger et ce que tu manges réellement."},{"name":"Batch cooking protéines","muscles":"Préparation culinaire sportive","sets":"1× /semaine — 45 min","difficulty":"Débutant","description":"Cuis 600–800 g de protéines maigres (poulet, œufs durs, thon, lentilles) en une session. Répartis en portions de 150–200 g. Garantit tes apports protéiques sans effort en semaine."},{"name":"Audit de l''assiette","muscles":"Équilibre nutritionnel","sets":"À chaque repas","difficulty":"Tous niveaux","description":"Avant chaque repas, vérifie visuellement : 50 % légumes, 25 % protéines, 25 % glucides complexes dans l''assiette. Méthode simple qui remplace le comptage de calories pour la plupart des objectifs."},{"name":"Hydratation structurée","muscles":"Métabolisme, performance physique","sets":"8 verres répartis sur la journée","difficulty":"Débutant","description":"Planifie tes apports hydriques : verre au réveil, avant chaque repas, pendant et après l''exercice. Utilise une bouteille graduée de 1,5L comme référence. La déshydratation de 2 % réduit la performance de 20 %."},{"name":"Fenêtre anabolique post-effort","muscles":"Récupération, synthèse protéique","sets":"Après chaque entraînement","difficulty":"Intermédiaire","description":"Dans les 30–60 min suivant chaque séance, consomme 30–40 g de protéines + 50–80 g de glucides (riz, banane, pain complet). Maximise la récupération et l''adaptation musculaire."},{"name":"Chrononutrition — Test 4 semaines","muscles":"Synchronisation circadienne","sets":"4 semaines","difficulty":"Intermédiaire","description":"Semaine 1 : repas normaux (référence). Semaines 2–4 : glucides concentrés sur petit-déj et déjeuner, protéines/lipides le soir. Compare les niveaux d''énergie, la récupération et la composition corporelle."},{"name":"Supplément créatine — Protocole","muscles":"Force, récupération, performance","sets":"3–5 g/jour en continu","difficulty":"Intermédiaire","description":"Prends 3–5 g de créatine monohydrate par jour à n''importe quelle heure (la saturation prend 4 semaines). Pas de phase de charge nécessaire. Le supplément le plus validé scientifiquement pour la performance sportive."}],"program":[{"week":"Semaine 1–2","theme":"Diagnostic — Connais ton point de départ","sessions":[{"name":"Calcul TDEE & macros cibles","detail":"Formule Mifflin-St Jeor + facteur activité → déficit ou surplus de 300 kcal selon objectif"},{"name":"Tracking alimentaire 7 j","detail":"Note tout sans changer tes habitudes — révèle les vrais déficits (protéines en général)"},{"name":"Audit du frigo et placard","detail":"Identifie les aliments ultra-transformés à remplacer progressivement par des alternatives saines"}]},{"week":"Semaine 3–4","theme":"Structure — Mettre en place les bases","sessions":[{"name":"Premier meal prep complet","detail":"Prépare 5 déjeuners + 5 dîners le dimanche — riz, légumes rôtis, protéines variées"},{"name":"Optimisation petit-déjeuner","detail":"Transition vers un petit-déjeuner protéiné 25–30 g : œufs + flocons + fruits + noix"},{"name":"Hydratation structurée","detail":"Bouteille 1,5L à finir avant 18h + 500 ml autour de chaque entraînement"},{"name":"Bilan macros semaine 4","detail":"Vérifie l''atteinte des objectifs protein/carbs/fats sur 7 jours avec l''app — ajuste si besoin"}]},{"week":"Semaine 5–6","theme":"Optimisation — Timing et qualité","sessions":[{"name":"Chrononutrition appliquée","detail":"Glucides le matin et péri-entraînement, lipides au dîner — teste sur 2 semaines"},{"name":"Fenêtre anabolique systématique","detail":"Shaker whey + banane ou riz + thon dans les 30 min post-effort à chaque séance"},{"name":"Intégration suppléments","detail":"Créatine 5 g/j + oméga-3 2 g/j + vitamine D3 2 000 UI/j — protocole de base éprouvé"}]},{"week":"Semaine 7–8","theme":"Autonomie & Pérennité","sessions":[{"name":"Flexibilité nutritionnelle","detail":"Applique la règle 80/20 — 80 % nutrition rigoureuse, 20 % repas libres sans culpabilité"},{"name":"Recettes hautes protéines maison","detail":"Maîtrise 5 recettes rapides (< 15 min) qui atteignent 40 g de protéines/portion"},{"name":"Bilan composition corporelle","detail":"Tour de taille, poids, photos comparatives J1/J56 — évalue l''impact sur la composition"},{"name":"Plan de maintenance personnalisé","detail":"Adapte les macros cibles à ta nouvelle composition — recalcul TDEE post-progression"}]}],"faq":[{"q":"Faut-il compter les calories pour progresser ?","a":"Pas nécessairement au quotidien, mais le faire au moins une fois pendant 2–4 semaines est très révélateur. Ça calibre l''intuition alimentaire de façon permanente. Ensuite, la méthode de l''assiette (50/25/25) suffit pour la majorité des objectifs."},{"q":"Les compléments alimentaires sont-ils indispensables ?","a":"Non — l''alimentation doit couvrir 90 % des besoins. La whey est pratique (pas magique), la créatine améliore mesurément la performance, les oméga-3 et la vitamine D sont pertinents si les apports alimentaires sont insuffisants. Tout le reste est marketing."},{"q":"Peut-on perdre du gras et prendre du muscle en même temps ?","a":"Oui, en débutant ou après une longue pause (recomposition corporelle). Nécessite un apport protéique élevé (2–2,2 g/kg), un entraînement en résistance et un déficit calorique léger (−200 kcal max). Les résultats sont plus lents mais durables."},{"q":"Combien de repas par jour faut-il manger ?","a":"La fréquence des repas a peu d''impact sur le métabolisme. Ce qui compte : atteindre ses cibles caloriques et protéiques totales sur la journée. 3 repas ou 5 repas : choisis celui qui s''intègre le mieux à ton mode de vie et t''aide à respecter tes objectifs."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('nutrition', 'en', '{"title":"Nutrition","tag":"Diet","description":"Personalized meal plans, macro tracking and nutrition strategies to reach your athletic goals.","stats":["+3,000 members","50+ plans","Daily tracking"],"levels":["Beginner","Intermediate","Advanced","Athlete"]}'::jsonb, '{"tagline":"Eat smart — performance starts on the plate.","heroStat":"4,100+ active members","guide":{"technique":{"emoji":"🥗","title":"Nutrition principles","items":["Caloric deficit to lose weight: 300–500 kcal/day below TDEE — never below 1,200 kcal (women) or 1,500 kcal (men)","Caloric surplus for muscle gain: 200–300 kcal/day above TDEE for a lean gain","Athletic macronutrients: 30–35% protein / 40–50% carbs / 20–25% fat for performance","Glycemic index (GI): favor low-GI carbs (quinoa, sweet potato, legumes) for stable energy","Chrononutrition: carbs primarily in the morning and around workouts, fats in the evening"]},"equipment":{"emoji":"⚖️","title":"Essential tools","items":["A precision food scale (to the gram) — essential to understand real portions","A nutrition-tracking app (MyFitnessPal, Cronometer) to track macros and micronutrients","Airtight meal-prep containers for weekly planning","A high-power blender for protein smoothies and nutritious homemade sauces","A cooking thermometer to control the temperature and preserve the nutrients in foods"]},"nutrition":{"emoji":"🍽️","title":"Planning & Distribution","items":["Protein timing: 20–40 g of protein every 3–4 h to maximize muscle protein synthesis","Anabolic window: a meal rich in protein and carbs within 60–90 min post-workout","Pre-workout meal: complex carbs + light protein 2–3h before (rice + chicken + vegetables)","5 servings of vegetables/fruit per day minimum — vitamins, minerals and fiber for overall health","Hydration: 35 ml/kg of body weight per day + an extra 500 ml per hour of exercise"]},"recovery":{"emoji":"🔄","title":"Recovery nutrition","items":["The first 30 minutes post-effort are the window of maximum response: carbs + protein 4:1","Casein (slow-digesting protein) at bedtime to fuel overnight protein synthesis","Omega-3 (2–4 g/day EPA+DHA): reduce muscle inflammation and speed up recovery","Tart cherry or beet juice after an intense effort: scientifically validated natural anti-inflammatories","Alcohol post-effort: reduces protein synthesis by 37% — avoid in the 6h after an intensive session"]}},"tips":[{"icon":"🍳","title":"Meal prep = success","body":"Prep your meals on Sunday for the week. Studies show that people who plan their nutrition reach their goals 2.5× more often than those who improvise."},{"icon":"🥦","title":"The plate rule","body":"Each main meal: 1/2 plate vegetables, 1/4 protein, 1/4 complex carbs. Simple, effective, no calorie counting every time."},{"icon":"💧","title":"Thirst = already dehydrated","body":"When you feel thirsty, you''ve already lost 1–2% of your body weight in water. Drink regularly throughout the day — not in sporadic large amounts."},{"icon":"📊","title":"Base calories first","body":"Master the quantity (total calories) first, then optimize the quality (macros), finally the timing (chrononutrition). Don''t skip steps."}],"exercises":[{"name":"Weekly meal planning","muscles":"Habit, nutritional organization","sets":"1× /week — 20 min","difficulty":"Beginner","description":"Every Sunday, plan your 5 main meals for the week. Calculate the target macros, list the ingredients, prep the proteins and grains ahead. The foundation of nutritional success."},{"name":"Calculating your TDEE","muscles":"Metabolic knowledge","sets":"1× at the start then each month","difficulty":"Beginner","description":"Calculate your Total Daily Energy Expenditure (TDEE) with the Mifflin-St Jeor formula × activity factor. Adjust by ±300 kcal depending on the goal (loss or gain). Recalculate every -5 kg."},{"name":"7-day macro tracking","muscles":"Food awareness","sets":"7 consecutive days","difficulty":"Beginner","description":"Log every food in an app (Cronometer recommended) for 7 consecutive days without changing your habits. Reveals the real gap between what you think you eat and what you actually eat."},{"name":"Batch cooking protein","muscles":"Athletic meal prep","sets":"1× /week — 45 min","difficulty":"Beginner","description":"Cook 600–800 g of lean protein (chicken, hard-boiled eggs, tuna, lentils) in one session. Split into 150–200 g portions. Guarantees your protein intake effortlessly during the week."},{"name":"Plate audit","muscles":"Nutritional balance","sets":"At every meal","difficulty":"All levels","description":"Before each meal, check visually: 50% vegetables, 25% protein, 25% complex carbs on the plate. A simple method that replaces calorie counting for most goals."},{"name":"Structured hydration","muscles":"Metabolism, physical performance","sets":"8 glasses spread over the day","difficulty":"Beginner","description":"Plan your fluid intake: a glass on waking, before each meal, during and after exercise. Use a graduated 1.5L bottle as a reference. 2% dehydration cuts performance by 20%."},{"name":"Post-effort anabolic window","muscles":"Recovery, protein synthesis","sets":"After every workout","difficulty":"Intermediate","description":"Within 30–60 min after each session, consume 30–40 g of protein + 50–80 g of carbs (rice, banana, wholegrain bread). Maximizes recovery and muscle adaptation."},{"name":"Chrononutrition — 4-week test","muscles":"Circadian timing","sets":"4 weeks","difficulty":"Intermediate","description":"Week 1: normal meals (baseline). Weeks 2–4: carbs concentrated at breakfast and lunch, protein/fat in the evening. Compare energy levels, recovery and body composition."},{"name":"Creatine supplement — Protocol","muscles":"Strength, recovery, performance","sets":"3–5 g/day ongoing","difficulty":"Intermediate","description":"Take 3–5 g of creatine monohydrate per day at any time (saturation takes 4 weeks). No loading phase needed. The most scientifically validated supplement for athletic performance."}],"program":[{"week":"Week 1–2","theme":"Diagnosis — Know your starting point","sessions":[{"name":"TDEE & target macros","detail":"Mifflin-St Jeor formula + activity factor → 300 kcal deficit or surplus depending on goal"},{"name":"Food tracking 7 days","detail":"Log everything without changing your habits — reveals the real gaps (protein in general)"},{"name":"Fridge and pantry audit","detail":"Identify the ultra-processed foods to gradually replace with healthy alternatives"}]},{"week":"Week 3–4","theme":"Structure — Putting the basics in place","sessions":[{"name":"First complete meal prep","detail":"Prep 5 lunches + 5 dinners on Sunday — rice, roasted vegetables, varied proteins"},{"name":"Breakfast optimization","detail":"Transition to a protein breakfast of 25–30 g: eggs + oats + fruit + nuts"},{"name":"Structured hydration","detail":"A 1.5L bottle to finish before 6 PM + 500 ml around each workout"},{"name":"Week-4 macro check","detail":"Check that you''re hitting the protein/carbs/fat targets over 7 days with the app — adjust if needed"}]},{"week":"Week 5–6","theme":"Optimization — Timing and quality","sessions":[{"name":"Applied chrononutrition","detail":"Carbs in the morning and around workouts, fats at dinner — test over 2 weeks"},{"name":"Systematic anabolic window","detail":"Whey shake + banana or rice + tuna within 30 min post-effort at every session"},{"name":"Supplement integration","detail":"Creatine 5 g/day + omega-3 2 g/day + vitamin D3 2,000 IU/day — a proven base protocol"}]},{"week":"Week 7–8","theme":"Autonomy & Sustainability","sessions":[{"name":"Nutritional flexibility","detail":"Apply the 80/20 rule — 80% rigorous nutrition, 20% free meals without guilt"},{"name":"High-protein home recipes","detail":"Master 5 quick recipes (< 15 min) that reach 40 g of protein/serving"},{"name":"Body-composition check","detail":"Waist circumference, weight, comparison photos D1/D56 — assess the impact on composition"},{"name":"Personalized maintenance plan","detail":"Adapt the target macros to your new composition — recalculate TDEE after progress"}]}],"faq":[{"q":"Do I need to count calories to progress?","a":"Not necessarily every day, but doing it at least once for 2–4 weeks is very revealing. It calibrates your food intuition permanently. After that, the plate method (50/25/25) is enough for most goals."},{"q":"Are supplements essential?","a":"No — your diet should cover 90% of your needs. Whey is convenient (not magic), creatine measurably improves performance, omega-3 and vitamin D are relevant if your dietary intake is insufficient. Everything else is marketing."},{"q":"Can you lose fat and build muscle at the same time?","a":"Yes, when you''re a beginner or after a long break (body recomposition). It requires high protein intake (2–2.2 g/kg), resistance training and a slight caloric deficit (−200 kcal max). Results are slower but durable."},{"q":"How many meals per day should I eat?","a":"Meal frequency has little impact on metabolism. What matters: hitting your total daily caloric and protein targets. 3 meals or 5 meals: choose the one that fits your lifestyle best and helps you meet your goals."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
insert into public.content_discipline_i18n (discipline_slug, locale, meta, sections) values ('nutrition', 'de', '{"title":"Ernährung","tag":"Ernährung","description":"Personalisierte Ernährungspläne, Makro-Tracking und Ernährungsstrategien, um deine sportlichen Ziele zu erreichen.","stats":["+3.000 Mitglieder","50+ Pläne","Tägliches Tracking"],"levels":["Anfänger","Fortgeschritten","Erfahren","Athlet"]}'::jsonb, '{"tagline":"Iss klug — Leistung beginnt auf dem Teller.","heroStat":"4.100+ aktive Mitglieder","guide":{"technique":{"emoji":"🥗","title":"Ernährungsprinzipien","items":["Kaloriendefizit zum Abnehmen: 300–500 kcal/Tag unter dem TDEE — nie unter 1.200 kcal (Frauen) oder 1.500 kcal (Männer)","Kalorienüberschuss für Muskelaufbau: 200–300 kcal/Tag über dem TDEE für einen schlanken Aufbau","Sportliche Makronährstoffe: 30–35% Protein / 40–50% Kohlenhydrate / 20–25% Fett für die Leistung","Glykämischer Index (GI): bevorzuge Kohlenhydrate mit niedrigem GI (Quinoa, Süßkartoffel, Hülsenfrüchte) für stabile Energie","Chrononutrition: Kohlenhydrate vor allem morgens und rund ums Training, Fette abends"]},"equipment":{"emoji":"⚖️","title":"Essenzielle Werkzeuge","items":["Eine präzise Küchenwaage (auf das Gramm) — essenziell, um echte Portionen zu verstehen","Eine Ernährungs-Tracking-App (MyFitnessPal, Cronometer), um Makros und Mikronährstoffe zu verfolgen","Luftdichte Meal-Prep-Behälter für die wöchentliche Planung","Ein leistungsstarker Mixer für Protein-Smoothies und nahrhafte hausgemachte Saucen","Ein Küchenthermometer, um die Temperatur zu kontrollieren und die Nährstoffe in Lebensmitteln zu erhalten"]},"nutrition":{"emoji":"🍽️","title":"Planung & Verteilung","items":["Protein-Timing: 20–40 g Protein alle 3–4 h, um die Muskelproteinsynthese zu maximieren","Anaboles Fenster: eine Mahlzeit reich an Protein und Kohlenhydraten innerhalb von 60–90 Min nach dem Training","Mahlzeit vor dem Training: komplexe Kohlenhydrate + leichtes Protein 2–3 h vorher (Reis + Hühnchen + Gemüse)","5 Portionen Gemüse/Obst pro Tag minimum — Vitamine, Mineralien und Ballaststoffe für die allgemeine Gesundheit","Hydration: 35 ml/kg Körpergewicht pro Tag + zusätzliche 500 ml pro Trainingsstunde"]},"recovery":{"emoji":"🔄","title":"Erholungsernährung","items":["Die ersten 30 Minuten nach der Anstrengung sind das Fenster maximaler Reaktion: Kohlenhydrate + Protein 4:1","Casein (langsam verdauliches Protein) vor dem Schlafen, um die nächtliche Proteinsynthese zu speisen","Omega-3 (2–4 g/Tag EPA+DHA): reduzieren Muskelentzündungen und beschleunigen die Erholung","Sauerkirsch- oder Rote-Bete-Saft nach intensiver Anstrengung: wissenschaftlich validierte natürliche Entzündungshemmer","Alkohol nach der Anstrengung: reduziert die Proteinsynthese um 37% — vermeide ihn in den 6 h nach einer intensiven Einheit"]}},"tips":[{"icon":"🍳","title":"Meal Prep = Erfolg","body":"Bereite deine Mahlzeiten am Sonntag für die Woche vor. Studien zeigen, dass Menschen, die ihre Ernährung planen, ihre Ziele 2,5× häufiger erreichen als die, die improvisieren."},{"icon":"🥦","title":"Die Teller-Regel","body":"Jede Hauptmahlzeit: 1/2 Teller Gemüse, 1/4 Protein, 1/4 komplexe Kohlenhydrate. Einfach, effektiv, kein Kalorienzählen jedes Mal."},{"icon":"💧","title":"Durst = schon dehydriert","body":"Wenn du Durst spürst, hast du bereits 1–2% deines Körpergewichts an Wasser verloren. Trink regelmäßig über den Tag — nicht sporadisch in großen Mengen."},{"icon":"📊","title":"Zuerst die Basiskalorien","body":"Beherrsche zuerst die Menge (Gesamtkalorien), dann optimiere die Qualität (Makros), schließlich das Timing (Chrononutrition). Überspringe keine Schritte."}],"exercises":[{"name":"Wöchentliche Mahlzeitenplanung","muscles":"Gewohnheit, Ernährungsorganisation","sets":"1× /Woche — 20 Min","difficulty":"Anfänger","description":"Plane jeden Sonntag deine 5 Hauptmahlzeiten für die Woche. Berechne die Ziel-Makros, liste die Zutaten, bereite Proteine und Getreide im Voraus zu. Die Grundlage des Ernährungserfolgs."},{"name":"Berechne deinen TDEE","muscles":"Metabolisches Wissen","sets":"1× am Start, dann jeden Monat","difficulty":"Anfänger","description":"Berechne deinen Gesamttagesenergieverbrauch (TDEE) mit der Mifflin-St-Jeor-Formel × Aktivitätsfaktor. Passe um ±300 kcal je nach Ziel an (Abnehmen oder Aufbau). Berechne alle -5 kg neu."},{"name":"7-Tage-Makro-Tracking","muscles":"Ernährungsbewusstsein","sets":"7 aufeinanderfolgende Tage","difficulty":"Anfänger","description":"Protokolliere jedes Lebensmittel in einer App (Cronometer empfohlen) 7 Tage hintereinander, ohne deine Gewohnheiten zu ändern. Deckt die reale Lücke zwischen dem auf, was du zu essen glaubst, und was du tatsächlich isst."},{"name":"Batch Cooking Protein","muscles":"Sportliche Mahlzeitenvorbereitung","sets":"1× /Woche — 45 Min","difficulty":"Anfänger","description":"Koche 600–800 g mageres Protein (Hühnchen, hartgekochte Eier, Thunfisch, Linsen) in einer Session. Teile in 150–200-g-Portionen. Garantiert deine Proteinzufuhr mühelos während der Woche."},{"name":"Teller-Audit","muscles":"Ernährungsgleichgewicht","sets":"Bei jeder Mahlzeit","difficulty":"Alle Niveaus","description":"Prüfe vor jeder Mahlzeit visuell: 50% Gemüse, 25% Protein, 25% komplexe Kohlenhydrate auf dem Teller. Eine einfache Methode, die für die meisten Ziele das Kalorienzählen ersetzt."},{"name":"Strukturierte Hydration","muscles":"Stoffwechsel, körperliche Leistung","sets":"8 Gläser über den Tag verteilt","difficulty":"Anfänger","description":"Plane deine Flüssigkeitszufuhr: ein Glas beim Aufwachen, vor jeder Mahlzeit, während und nach dem Sport. Nutze eine 1,5-L-Flasche mit Skala als Referenz. 2% Dehydrierung senkt die Leistung um 20%."},{"name":"Anaboles Fenster nach der Anstrengung","muscles":"Erholung, Proteinsynthese","sets":"Nach jedem Workout","difficulty":"Fortgeschritten","description":"Nimm innerhalb von 30–60 Min nach jeder Einheit 30–40 g Protein + 50–80 g Kohlenhydrate (Reis, Banane, Vollkornbrot) zu dir. Maximiert Erholung und Muskelanpassung."},{"name":"Chrononutrition — 4-Wochen-Test","muscles":"Zirkadianes Timing","sets":"4 Wochen","difficulty":"Fortgeschritten","description":"Woche 1: normale Mahlzeiten (Ausgangswert). Wochen 2–4: Kohlenhydrate auf Frühstück und Mittag konzentriert, Protein/Fett abends. Vergleiche Energie, Erholung und Körperzusammensetzung."},{"name":"Kreatin-Supplement — Protokoll","muscles":"Kraft, Erholung, Leistung","sets":"3–5 g/Tag laufend","difficulty":"Fortgeschritten","description":"Nimm 3–5 g Kreatin-Monohydrat pro Tag zu beliebiger Zeit (Sättigung dauert 4 Wochen). Keine Ladephase nötig. Das wissenschaftlich am besten validierte Supplement für die sportliche Leistung."}],"program":[{"week":"Woche 1–2","theme":"Diagnose — Kenne deinen Ausgangspunkt","sessions":[{"name":"TDEE & Ziel-Makros","detail":"Mifflin-St-Jeor-Formel + Aktivitätsfaktor → 300 kcal Defizit oder Überschuss je nach Ziel"},{"name":"Ernährungs-Tracking 7 Tage","detail":"Protokolliere alles, ohne deine Gewohnheiten zu ändern — deckt die echten Lücken auf (Protein generell)"},{"name":"Kühlschrank- und Vorrats-Audit","detail":"Identifiziere die ultraverarbeiteten Lebensmittel, die schrittweise durch gesunde Alternativen ersetzt werden"}]},{"week":"Woche 3–4","theme":"Struktur — Die Basis aufbauen","sessions":[{"name":"Erste komplette Meal Prep","detail":"Bereite 5 Mittag- + 5 Abendessen am Sonntag vor — Reis, geröstetes Gemüse, abwechslungsreiche Proteine"},{"name":"Frühstücks-Optimierung","detail":"Übergang zu einem Protein-Frühstück von 25–30 g: Eier + Haferflocken + Obst + Nüsse"},{"name":"Strukturierte Hydration","detail":"Eine 1,5-L-Flasche bis 18 Uhr leeren + 500 ml rund um jedes Workout"},{"name":"Makro-Check Woche 4","detail":"Prüfe, ob du die Protein-/Kohlenhydrat-/Fett-Ziele über 7 Tage mit der App triffst — bei Bedarf anpassen"}]},{"week":"Woche 5–6","theme":"Optimierung — Timing und Qualität","sessions":[{"name":"Angewandte Chrononutrition","detail":"Kohlenhydrate morgens und rund ums Training, Fette am Abend — über 2 Wochen testen"},{"name":"Systematisches anaboles Fenster","detail":"Whey-Shake + Banane oder Reis + Thunfisch innerhalb von 30 Min nach der Anstrengung bei jeder Einheit"},{"name":"Supplement-Integration","detail":"Kreatin 5 g/Tag + Omega-3 2 g/Tag + Vitamin D3 2.000 IE/Tag — ein bewährtes Basisprotokoll"}]},{"week":"Woche 7–8","theme":"Eigenständigkeit & Nachhaltigkeit","sessions":[{"name":"Ernährungsflexibilität","detail":"Wende die 80/20-Regel an — 80% rigorose Ernährung, 20% freie Mahlzeiten ohne Schuldgefühl"},{"name":"Proteinreiche Rezepte für zu Hause","detail":"Beherrsche 5 schnelle Rezepte (< 15 Min), die 40 g Protein/Portion erreichen"},{"name":"Körperzusammensetzungs-Check","detail":"Taillenumfang, Gewicht, Vergleichsfotos Tag 1/Tag 56 — Wirkung auf die Komposition bewerten"},{"name":"Personalisierter Erhaltungsplan","detail":"Passe die Ziel-Makros an deine neue Komposition an — TDEE nach Fortschritt neu berechnen"}]}],"faq":[{"q":"Muss ich Kalorien zählen, um voranzukommen?","a":"Nicht unbedingt jeden Tag, aber es mindestens einmal für 2–4 Wochen zu tun ist sehr aufschlussreich. Es kalibriert deine Ernährungsintuition dauerhaft. Danach reicht die Teller-Methode (50/25/25) für die meisten Ziele."},{"q":"Sind Supplemente unverzichtbar?","a":"Nein — deine Ernährung sollte 90% deines Bedarfs decken. Whey ist praktisch (nicht magisch), Kreatin verbessert die Leistung messbar, Omega-3 und Vitamin D sind relevant, wenn deine Nahrungszufuhr unzureichend ist. Alles andere ist Marketing."},{"q":"Kann man gleichzeitig Fett verlieren und Muskeln aufbauen?","a":"Ja, als Anfänger oder nach einer langen Pause (Körper-Rekomposition). Es erfordert hohe Proteinzufuhr (2–2,2 g/kg), Krafttraining und ein leichtes Kaloriendefizit (−200 kcal max). Die Ergebnisse sind langsamer, aber dauerhaft."},{"q":"Wie viele Mahlzeiten pro Tag sollte ich essen?","a":"Die Mahlzeitenhäufigkeit hat wenig Einfluss auf den Stoffwechsel. Was zählt: deine täglichen Gesamt-Kalorien- und Proteinziele zu treffen. 3 Mahlzeiten oder 5 Mahlzeiten: wähle die, die am besten zu deinem Lebensstil passt und dir hilft, deine Ziele zu erreichen."}]}'::jsonb) on conflict (discipline_slug, locale) do update set meta=excluded.meta, sections=excluded.sections;
